+//! SIMD-Optimized Q8_0 Dequantization
+//!
+//! Uses ARM NEON via Zig's @Vector intrinsics to achieve ~10-20x speedup
+//! over scalar dequantization.
+//!
+//! Q8_0 Block Format (34 bytes):
+//!   [delta: f16 (2 bytes)] + [quants: 32 x i8 (32 bytes)]
+//!
+//! Output: 32 x BF16 (64 bytes)
+//! Formula: bf16_value = delta * int8_value
+
+const std = @import("std");
+
+/// BF16 type (stored as u16)
+pub const BF16 = u16;
+
+// Q8_0 constants
+const Q8_BLOCK_SIZE: usize = 32; // Values per block
+const Q8_BLOCK_BYTES: usize = 34; // 2 (f16 delta) + 32 (i8 quants)
+
+// SIMD width: 16 floats = 512 bits, but we use 128-bit chunks for NEON
+const SIMD_WIDTH: usize = 16;
+
+/// Convert F16 bits to F32
+inline fn f16ToF32(bits: u16) f32 {
+    const sign: u32 = @as(u32, bits >> 15) << 31;
+    const exp: u32 = (bits >> 10) & 0x1F;
+    const mant: u32 = bits & 0x3FF;
+
+    if (exp == 0) {
+        if (mant == 0) return @bitCast(sign);
+        // Denormal
+        var m = mant;
+        var e: i32 = -14;
+        while ((m & 0x400) == 0) {
+            m <<= 1;
+            e -= 1;
+        }
+        m &= 0x3FF;
+        const exp32: u32 = @intCast(e + 127);
+        return @bitCast(sign | (exp32 << 23) | (m << 13));
+    } else if (exp == 31) {
+        if (mant == 0) return @bitCast(sign | 0x7F800000);
+        return @bitCast(sign | 0x7FC00000 | (mant << 13));
+    }
+
+    const exp32: u32 = exp + 127 - 15;
+    return @bitCast(sign | (exp32 << 23) | (mant << 13));
+}
+
+/// Convert F32 to BF16 (truncation - fast)
+inline fn f32ToBf16(value: f32) BF16 {
+    const bits: u32 = @bitCast(value);
+    return @truncate(bits >> 16);
+}
+
+/// SIMD dequantize a single Q8_0 block (32 values)
+/// Uses 16-wide vectors, processing in two chunks
+inline fn dequantizeBlock(
+    src: [*]const u8,
+    dst: [*]BF16,
+) void {
+    // 1. Load delta (f16) - first 2 bytes
+    const delta_bits = std.mem.readInt(u16, src[0..2], .little);
+    const delta_f32 = f16ToF32(delta_bits);
+
+    // Broadcast delta to vector
+    const delta_vec: @Vector(SIMD_WIDTH, f32) = @splat(delta_f32);
+
+    // 2. Process first 16 values (bytes 2-17)
+    processChunk16(src + 2, dst, delta_vec);
+
+    // 3. Process second 16 values (bytes 18-33)
+    processChunk16(src + 18, dst + 16, delta_vec);
+}
+
+/// Process 16 int8 values with SIMD
+inline fn processChunk16(
+    src_ptr: [*]const u8,
+    dst_ptr: [*]BF16,
+    delta_vec: @Vector(SIMD_WIDTH, f32),
+) void {
+    // Copy to aligned buffer (src may not be 16-byte aligned)
+    var buf: [16]u8 align(16) = undefined;
+    @memcpy(&buf, src_ptr[0..16]);
+
+    // Load as i8 vector
+    const i8_vec: @Vector(16, i8) = @bitCast(buf);
+
+    // Convert i8 -> i32 -> f32 (sign extension happens automatically)
+    const i32_vec: @Vector(16, i32) = i8_vec;
+    const f32_vec: @Vector(16, f32) = @floatFromInt(i32_vec);
+
+    // Multiply by delta
+    const result_f32 = f32_vec * delta_vec;
+
+    // Convert f32 -> bf16 (truncate upper 16 bits)
+    const result_u32: @Vector(16, u32) = @bitCast(result_f32);
+    const shift: @Vector(16, u5) = @splat(16);
+    const bf16_vec: @Vector(16, u16) = @truncate(result_u32 >> shift);
+
+    // Store result
+    dst_ptr[0..16].* = bf16_vec;
+}
+
+/// Dequantize multiple Q8_0 blocks using SIMD
+/// This is the main entry point for bulk dequantization
+pub fn dequantizeQ8_0_SIMD(
+    src: []const u8,
+    dst: []BF16,
+    n_elements: usize,
+) void {
+    const n_blocks = (n_elements + Q8_BLOCK_SIZE - 1) / Q8_BLOCK_SIZE;
+
+    // Process blocks
+    var block_idx: usize = 0;
+    while (block_idx < n_blocks) : (block_idx += 1) {
+        const src_offset = block_idx * Q8_BLOCK_BYTES;
+        const dst_offset = block_idx * Q8_BLOCK_SIZE;
+
+        // Bounds check for last partial block
+        const remaining = n_elements - dst_offset;
+        if (remaining < Q8_BLOCK_SIZE) {
+            // Fall back to scalar for partial block
+            dequantizeBlockScalar(
+                src[src_offset..],
+                dst[dst_offset..][0..remaining],
+            );
+            break;
+        }
+
+        dequantizeBlock(
+            @ptrCast(src.ptr + src_offset),
+            @ptrCast(dst.ptr + dst_offset),
+        );
+    }
+}
+
+/// Scalar fallback for partial blocks
+fn dequantizeBlockScalar(src: []const u8, dst: []BF16) void {
+    const delta_bits = std.mem.readInt(u16, src[0..2], .little);
+    const delta = f16ToF32(delta_bits);
+
+    for (dst, 0..) |*d, i| {
+        if (i + 2 >= src.len) break;
+        const q: i8 = @bitCast(src[i + 2]);
+        const val = @as(f32, @floatFromInt(q)) * delta;
+        d.* = f32ToBf16(val);
+    }
+}
+
+/// Dequantize with multi-threading for maximum throughput
+/// Splits work across available CPU cores
+pub fn dequantizeQ8_0_Parallel(
+    allocator: std.mem.Allocator,
+    src: []const u8,
+    dst: []BF16,
+    n_elements: usize,
+) !void {
+    const n_blocks = (n_elements + Q8_BLOCK_SIZE - 1) / Q8_BLOCK_SIZE;
+
+    // Use 4 threads (typical M2/M3 efficiency core count)
+    const n_threads: usize = 4;
+
+    if (n_blocks < n_threads * 4) {
+        // Too few blocks, just use single-threaded SIMD
+        dequantizeQ8_0_SIMD(src, dst, n_elements);
+        return;
+    }
+
+    const blocks_per_thread = n_blocks / n_threads;
+
+    var threads: [4]?std.Thread = .{ null, null, null, null };
+
+    // Spawn worker threads
+    for (0..n_threads) |t| {
+        const start_block = t * blocks_per_thread;
+        const end_block = if (t == n_threads - 1) n_blocks else (t + 1) * blocks_per_thread;
+
+        const src_start = start_block * Q8_BLOCK_BYTES;
+        const dst_start = start_block * Q8_BLOCK_SIZE;
+        const chunk_elements = (end_block - start_block) * Q8_BLOCK_SIZE;
+
+        threads[t] = try std.Thread.spawn(.{}, workerFn, .{
+            src[src_start..],
+            dst[dst_start..],
+            chunk_elements,
+        });
+    }
+
+    // Wait for all threads
+    for (&threads) |*t| {
+        if (t.*) |thread| {
+            thread.join();
+        }
+    }
+
+    _ = allocator;
+}
+
+fn workerFn(src: []const u8, dst: []BF16, n_elements: usize) void {
+    dequantizeQ8_0_SIMD(src, dst, n_elements);
+}
+
+// =============================================================================
+// Benchmark Helper
+// =============================================================================
+
+/// Benchmark the SIMD dequantizer
+pub fn benchmarkDequantize(allocator: std.mem.Allocator) !void {
+    const n_elements: usize = 26_214_400; // ~26M (one Q weight matrix)
+    const n_blocks = n_elements / Q8_BLOCK_SIZE;
+    const src_size = n_blocks * Q8_BLOCK_BYTES;
+
+    std.debug.print("\n=== SIMD Dequantization Benchmark ===\n", .{});
+    std.debug.print("Elements: {} ({} M)\n", .{ n_elements, n_elements / 1_000_000 });
+    std.debug.print("Source size: {} MB (Q8_0)\n", .{src_size / (1024 * 1024)});
+    std.debug.print("Dest size: {} MB (BF16)\n", .{n_elements * 2 / (1024 * 1024)});
+
+    // Allocate buffers
+    const src = try allocator.alloc(u8, src_size);
+    defer allocator.free(src);
+    const dst = try allocator.alloc(BF16, n_elements);
+    defer allocator.free(dst);
+
+    // Fill with test data
+    for (0..n_blocks) |i| {
+        const offset = i * Q8_BLOCK_BYTES;
+        // Set delta to 0.01 (f16)
+        std.mem.writeInt(u16, src[offset..][0..2], 0x211E, .little); // ~0.01 in f16
+        // Fill quants with pattern
+        for (0..32) |j| {
+            src[offset + 2 + j] = @truncate(j);
+        }
+    }
+
+    // Warm up
+    dequantizeQ8_0_SIMD(src, dst, n_elements);
+
+    // Benchmark
+    const iterations: usize = 10;
+    var total_ns: u64 = 0;
+
+    for (0..iterations) |_| {
+        const start = std.time.nanoTimestamp();
+        dequantizeQ8_0_SIMD(src, dst, n_elements);
+        const elapsed: u64 = @intCast(std.time.nanoTimestamp() - start);
+        total_ns += elapsed;
+    }
+
+    const avg_ns = total_ns / iterations;
+    const bytes_processed = n_elements * 2; // Output bytes
+    const throughput_mbps = @as(f64, @floatFromInt(bytes_processed)) / @as(f64, @floatFromInt(avg_ns)) * 1000.0;
+
+    std.debug.print("\nResults (avg of {} iterations):\n", .{iterations});
+    std.debug.print("  Time: {} ms\n", .{avg_ns / 1_000_000});
+    std.debug.print("  Throughput: {d:.1} MB/s\n", .{throughput_mbps});
+    std.debug.print("  Speedup target: {d:.1}x vs 276 MB/s scalar\n", .{throughput_mbps / 276.0});
+}
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "simd dequantize basic" {
+    // Create a single block
+    var src: [34]u8 = undefined;
+    // Delta = 1.0 (f16: 0x3C00)
+    std.mem.writeInt(u16, src[0..2], 0x3C00, .little);
+    // Quants: 0, 1, 2, ..., 31
+    for (0..32) |i| {
+        src[2 + i] = @truncate(i);
+    }
+
+    var dst: [32]BF16 = undefined;
+    dequantizeQ8_0_SIMD(&src, &dst, 32);
+
+    // Verify: each output should be approximately equal to the input index
+    for (dst, 0..) |val, i| {
+        const f: f32 = @bitCast(@as(u32, val) << 16);
+        try std.testing.expectApproxEqRel(@as(f32, @floatFromInt(i)), f, 0.1);
+    }
+}
+
+test "simd dequantize negative" {
+    var src: [34]u8 = undefined;
+    // Delta = 0.5 (f16: 0x3800)
+    std.mem.writeInt(u16, src[0..2], 0x3800, .little);
+    // Quants: -128 to -97 (first 32 negative values)
+    for (0..32) |i| {
+        const val: i8 = @intCast(@as(i32, @intCast(i)) - 128);
+        src[2 + i] = @bitCast(val);
+    }
+
+    var dst: [32]BF16 = undefined;
+    dequantizeQ8_0_SIMD(&src, &dst, 32);
+
+    // First value should be -128 * 0.5 = -64
+    const first: f32 = @bitCast(@as(u32, dst[0]) << 16);
+    try std.testing.expectApproxEqRel(@as(f32, -64.0), first, 0.1);
+}

