+//! GGUF Streaming Loader
+//!
+//! Parses GGUF files and provides random-access to tensor data for streaming inference.
+//! Memory-maps the file for zero-copy access to compressed weights.
+//!
+//! GGUF Format (v3):
+//! ┌─────────────────────────────────────────────────────────────────┐
+//! │ Header (32 bytes)                                               │
+//! │   Magic "GGUF" (4), Version (4), Tensor Count (8), KV Count (8) │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │ Key-Value Metadata                                              │
+//! │   Architecture, layer count, hidden size, etc.                  │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │ Tensor Info Table                                               │
+//! │   Name, Dimensions, Type, Offset for each tensor                │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │ Alignment Padding                                               │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │ Tensor Data                                                     │
+//! │   Raw tensor bytes (quantized weights)                          │
+//! └─────────────────────────────────────────────────────────────────┘
+
+const std = @import("std");
+const simd = @import("dequantize_simd.zig");
+
+// =============================================================================
+// BF16 Utilities (inline to avoid import path issues)
+// =============================================================================
+
+/// BFloat16 type (stored as u16 for Zig compatibility)
+pub const BF16 = u16;
+
+/// Convert FP32 to BF16 (truncation)
+pub inline fn f32ToBf16(value: f32) BF16 {
+    const bits: u32 = @bitCast(value);
+    return @truncate(bits >> 16);
+}
+
+/// Convert BF16 to FP32
+pub inline fn bf16ToF32(value: BF16) f32 {
+    const bits: u32 = @as(u32, value) << 16;
+    return @bitCast(bits);
+}
+
+/// Batch convert FP32 to BF16
+pub fn batchF32ToBf16(src: []const f32, dest: []BF16) void {
+    for (src, 0..) |v, i| {
+        dest[i] = f32ToBf16(v);
+    }
+}
+
+// Expose for external use
+pub const bf16_utils = struct {
+    pub const f32ToBf16 = @import("gguf_loader.zig").f32ToBf16;
+    pub const bf16ToF32 = @import("gguf_loader.zig").bf16ToF32;
+    pub const batchF32ToBf16 = @import("gguf_loader.zig").batchF32ToBf16;
+};
+
+const log = std.log.scoped(.gguf_loader);
+
+// =============================================================================
+// GGUF Constants and Types
+// =============================================================================
+
+/// GGUF magic bytes "GGUF"
+const GGUF_MAGIC: u32 = 0x46554747; // "GGUF" little-endian
+
+/// Supported GGUF versions
+const GGUF_VERSION_MIN: u32 = 2;
+const GGUF_VERSION_MAX: u32 = 3;
+
+/// GGUF value types for metadata
+pub const GGUFValueType = enum(u32) {
+    uint8 = 0,
+    int8 = 1,
+    uint16 = 2,
+    int16 = 3,
+    uint32 = 4,
+    int32 = 5,
+    float32 = 6,
+    bool_ = 7,
+    string = 8,
+    array = 9,
+    uint64 = 10,
+    int64 = 11,
+    float64 = 12,
+};
+
+/// GGML tensor types (quantization formats)
+pub const GGMLType = enum(u32) {
+    f32 = 0,
+    f16 = 1,
+    q4_0 = 2,
+    q4_1 = 3,
+    // 4, 5 are deprecated
+    q5_0 = 6,
+    q5_1 = 7,
+    q8_0 = 8,
+    q8_1 = 9,
+    q2_k = 10,
+    q3_k = 11,
+    q4_k = 12,
+    q5_k = 13,
+    q6_k = 14,
+    q8_k = 15,
+    iq2_xxs = 16,
+    iq2_xs = 17,
+    iq3_xxs = 18,
+    iq1_s = 19,
+    iq4_nl = 20,
+    iq3_s = 21,
+    iq2_s = 22,
+    iq4_xs = 23,
+    i8 = 24,
+    i16 = 25,
+    i32 = 26,
+    i64 = 27,
+    f64 = 28,
+    bf16 = 30,
+    _,
+
+    /// Get block size for quantization type
+    pub fn blockSize(self: GGMLType) u32 {
+        return switch (self) {
+            .q4_0, .q4_1, .q5_0, .q5_1, .q8_0, .q8_1 => 32,
+            .q2_k, .q3_k, .q4_k, .q5_k, .q6_k, .q8_k => 256,
+            else => 1,
+        };
+    }
+
+    /// Get bytes per block for this type
+    pub fn bytesPerBlock(self: GGMLType) u32 {
+        return switch (self) {
+            .f32 => 4,
+            .f16, .bf16 => 2,
+            .q4_0 => 18, // 2 (f16 scale) + 16 (32 * 4 bits)
+            .q4_1 => 20, // 2 (f16 scale) + 2 (f16 min) + 16
+            .q5_0 => 22, // 2 + 4 + 16
+            .q5_1 => 24, // 2 + 2 + 4 + 16
+            .q8_0 => 34, // 2 (f16 scale) + 32 (32 * 8 bits)
+            .q8_1 => 36, // 2 + 2 + 32
+            .q2_k => 84,
+            .q3_k => 110,
+            .q4_k => 144,
+            .q5_k => 176,
+            .q6_k => 210,
+            .q8_k => 292,
+            .i8 => 1,
+            .i16 => 2,
+            .i32 => 4,
+            .i64 => 8,
+            .f64 => 8,
+            else => 1,
+        };
+    }
+};
+
+/// Information about a single tensor in the GGUF file
+pub const GGUFTensorInfo = struct {
+    name: []const u8,
+    n_dims: u32,
+    dimensions: [4]u64,
+    type_: GGMLType,
+    offset: u64, // Offset from start of tensor data section
+
+    /// Calculate total number of elements
+    pub fn numElements(self: GGUFTensorInfo) u64 {
+        var n: u64 = 1;
+        for (0..self.n_dims) |i| {
+            n *= self.dimensions[i];
+        }
+        return n;
+    }
+
+    /// Calculate size in bytes of this tensor
+    pub fn sizeBytes(self: GGUFTensorInfo) u64 {
+        const n_elements = self.numElements();
+        const block_size = self.type_.blockSize();
+        const bytes_per_block = self.type_.bytesPerBlock();
+
+        // Number of blocks (rounded up)
+        const n_blocks = (n_elements + block_size - 1) / block_size;
+        return n_blocks * bytes_per_block;
+    }
+};
+
+/// Model metadata extracted from GGUF
+pub const GGUFMetadata = struct {
+    architecture: []const u8 = "unknown",
+    name: []const u8 = "unknown",
+    n_layers: u32 = 0,
+    n_heads: u32 = 0,
+    n_kv_heads: u32 = 0,
+    hidden_size: u32 = 0,
+    intermediate_size: u32 = 0,
+    vocab_size: u32 = 0,
+    context_length: u32 = 0,
+    rope_freq_base: f32 = 10000.0,
+    head_dim: u32 = 0,
+};
+
+// =============================================================================
+// GGUF Loader
+// =============================================================================
+
+pub const GGUFLoader = struct {
+    allocator: std.mem.Allocator,
+
+    // File access
+    file: std.fs.File,
+    mmap_ptr: [*]align(16384) const u8, // macOS page size (16KB for Apple Silicon)
+    mmap_len: usize,
+
+    // Parsed data
+    version: u32,
+    tensor_count: u64,
+    metadata_kv_count: u64,
+    tensor_data_offset: u64, // Where tensor data starts in file
+
+    // Tensor lookup
+    tensors: std.StringHashMap(GGUFTensorInfo),
+
+    // Model metadata
+    metadata: GGUFMetadata,
+
+    const Self = @This();
+
+    /// Initialize loader by parsing GGUF file header and tensor table
+    pub fn init(allocator: std.mem.Allocator, path: []const u8) !Self {
+        log.info("Opening GGUF file: {s}", .{path});
+
+        // Open file
+        const file = try std.fs.cwd().openFile(path, .{});
+        errdefer file.close();
+
+        // Get file size
+        const stat = try file.stat();
+        const file_size = stat.size;
+        log.info("File size: {} bytes ({} MB)", .{ file_size, file_size / (1024 * 1024) });
+
+        // Memory map the file
+        const mmap_ptr = try std.posix.mmap(
+            null,
+            file_size,
+            std.posix.PROT.READ,
+            .{ .TYPE = .PRIVATE },
+            file.handle,
+            0,
+        );
+
+        var self = Self{
+            .allocator = allocator,
+            .file = file,
+            .mmap_ptr = mmap_ptr.ptr,
+            .mmap_len = file_size,
+            .version = 0,
+            .tensor_count = 0,
+            .metadata_kv_count = 0,
+            .tensor_data_offset = 0,
+            .tensors = std.StringHashMap(GGUFTensorInfo).init(allocator),
+            .metadata = .{},
+        };
+
+        // Parse header
+        try self.parseHeader();
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Free tensor name strings
+        var it = self.tensors.iterator();
+        while (it.next()) |entry| {
+            self.allocator.free(entry.key_ptr.*);
+        }
+        self.tensors.deinit();
+
+        // Unmap file
+        std.posix.munmap(self.mmap_ptr[0..self.mmap_len]);
+
+        // Close file
+        self.file.close();
+    }
+
+    // =========================================================================
+    // Memory Pinning (Tiered Memory Architecture)
+    // =========================================================================
+
+    /// Lock the first N bytes of the mmap'd file in physical RAM
+    /// This prevents the OS from paging out "hot" layers to disk
+    /// Returns the actual number of bytes locked (may be less if system limits)
+    pub fn lockResidentMemory(self: *Self, bytes: usize) !usize {
+        const lock_size = @min(bytes, self.mmap_len);
+
+        log.info("Attempting to lock {} MB in RAM...", .{lock_size / (1024 * 1024)});
+
+        // Use mlock to pin pages in physical memory
+        // On macOS, this requires either:
+        // 1. Running as root
+        // 2. Having sufficient RLIMIT_MEMLOCK
+        // 3. Being within the default ~2GB limit for unprivileged processes
+
+        // Try mlock via extern C function
+        const mlock_result = mlock_extern(self.mmap_ptr, lock_size);
+
+        if (mlock_result == 0) {
+            log.info("Successfully locked {} MB in RAM", .{lock_size / (1024 * 1024)});
+            return lock_size;
+        } else {
+            log.warn("mlock failed. Falling back to touch-based warming.", .{});
+
+            // Fallback: Touch pages to bring them into RAM
+            // The OS unified buffer cache will keep them hot if we have enough RAM
+            return try self.warmResidentMemory(lock_size);
+        }
+    }
+
+    // External mlock declaration for macOS
+    extern "c" fn mlock(addr: ?*const anyopaque, len: usize) c_int;
+
+    fn mlock_extern(ptr: [*]const u8, len: usize) c_int {
+        return mlock(@ptrCast(ptr), len);
+    }
+
+    /// Touch pages to bring them into RAM (fallback when mlock fails)
+    /// This relies on the OS keeping recently-accessed pages in the buffer cache
+    pub fn warmResidentMemory(self: *Self, bytes: usize) !usize {
+        const warm_size = @min(bytes, self.mmap_len);
+        const page_size: usize = 16384; // macOS ARM64 page size
+
+        log.info("Warming {} MB by touching pages...", .{warm_size / (1024 * 1024)});
+
+        var sum: u64 = 0; // Prevent optimizer from removing the loop
+        var offset: usize = 0;
+
+        while (offset < warm_size) : (offset += page_size) {
+            // Read one byte per page to fault it into RAM
+            sum +%= self.mmap_ptr[offset];
+        }
+
+        // Use sum to prevent optimization
+        if (sum == 0xDEADBEEF) {
+            log.debug("Unlikely sum: {}", .{sum});
+        }
+
+        log.info("Warmed {} MB ({} pages touched)", .{ warm_size / (1024 * 1024), warm_size / page_size });
+        return warm_size;
+    }
+
+    /// Calculate the byte offset where a given layer's data starts
+    /// Used to determine how much memory to lock for N resident layers
+    pub fn getLayerDataOffset(self: *Self, layer_idx: u32) ?usize {
+        // Find the first tensor for this layer
+        var name_buf: [64]u8 = undefined;
+        const tensor_name = std.fmt.bufPrint(&name_buf, "blk.{d}.attn_norm.weight", .{layer_idx}) catch return null;
+
+        const info = self.tensors.get(tensor_name) orelse return null;
+        return self.tensor_data_offset + info.offset;
+    }
+
+    /// Get the byte range for the first N layers (for memory locking)
+    pub fn getResidentLayerBytes(self: *Self, n_layers: u32) usize {
+        // Find the last tensor of layer (n_layers - 1) to determine end offset
+        // The layers are mostly contiguous in the GGUF file
+
+        // Estimate: Each layer is ~540MB in Q8_0 format
+        // 40 layers = ~21.6 GB
+        const estimated_bytes_per_layer: usize = 540 * 1024 * 1024;
+        const estimated_total = @as(usize, n_layers) * estimated_bytes_per_layer;
+
+        // Don't exceed file size
+        return @min(estimated_total + self.tensor_data_offset, self.mmap_len);
+    }
+
+    /// Parse GGUF header and build tensor index
+    fn parseHeader(self: *Self) !void {
+        var cursor: usize = 0;
+
+        // Read magic
+        const magic = self.readU32(&cursor);
+        if (magic != GGUF_MAGIC) {
+            log.err("Invalid GGUF magic: 0x{X:0>8}, expected 0x{X:0>8}", .{ magic, GGUF_MAGIC });
+            return error.InvalidGGUFMagic;
+        }
+
+        // Read version
+        self.version = self.readU32(&cursor);
+        if (self.version < GGUF_VERSION_MIN or self.version > GGUF_VERSION_MAX) {
+            log.err("Unsupported GGUF version: {}, supported: {}-{}", .{ self.version, GGUF_VERSION_MIN, GGUF_VERSION_MAX });
+            return error.UnsupportedGGUFVersion;
+        }
+        log.info("GGUF version: {}", .{self.version});
+
+        // Read tensor count and KV count
+        self.tensor_count = self.readU64(&cursor);
+        self.metadata_kv_count = self.readU64(&cursor);
+        log.info("Tensor count: {}, Metadata KV count: {}", .{ self.tensor_count, self.metadata_kv_count });
+
+        // Parse metadata key-value pairs
+        try self.parseMetadata(&cursor);
+
+        // Parse tensor info table
+        try self.parseTensorInfos(&cursor);
+
+        // Calculate tensor data offset (aligned to 32 bytes)
+        const alignment: usize = 32;
+        self.tensor_data_offset = (cursor + alignment - 1) & ~(alignment - 1);
+        log.info("Tensor data offset: {} (0x{X})", .{ self.tensor_data_offset, self.tensor_data_offset });
+    }
+
+    /// Parse metadata key-value pairs
+    fn parseMetadata(self: *Self, cursor: *usize) !void {
+        for (0..self.metadata_kv_count) |_| {
+            const key = self.readString(cursor);
+            const value_type: GGUFValueType = @enumFromInt(self.readU32(cursor));
+
+            // Parse based on type and store interesting metadata
+            switch (value_type) {
+                .uint32 => {
+                    const val = self.readU32(cursor);
+                    self.storeMetadataU32(key, val);
+                },
+                .int32 => {
+                    const val = self.readI32(cursor);
+                    self.storeMetadataU32(key, @intCast(@as(i64, val)));
+                },
+                .uint64 => {
+                    const val = self.readU64(cursor);
+                    self.storeMetadataU32(key, @truncate(val));
+                },
+                .int64 => {
+                    const val = self.readI64(cursor);
+                    self.storeMetadataU32(key, @intCast(@as(i128, val)));
+                },
+                .float32 => {
+                    const val = self.readF32(cursor);
+                    self.storeMetadataF32(key, val);
+                },
+                .float64 => {
+                    const val = self.readF64(cursor);
+                    self.storeMetadataF32(key, @floatCast(val));
+                },
+                .string => {
+                    const val = self.readString(cursor);
+                    self.storeMetadataString(key, val);
+                },
+                .bool_ => {
+                    _ = self.readU8(cursor);
+                },
+                .uint8 => {
+                    _ = self.readU8(cursor);
+                },
+                .int8 => {
+                    _ = self.readU8(cursor);
+                },
+                .uint16 => {
+                    _ = self.readU16(cursor);
+                },
+                .int16 => {
+                    _ = self.readU16(cursor);
+                },
+                .array => {
+                    // Skip array contents
+                    const arr_type: GGUFValueType = @enumFromInt(self.readU32(cursor));
+                    const arr_len = self.readU64(cursor);
+                    self.skipArrayElements(cursor, arr_type, arr_len);
+                },
+            }
+        }
+
+        // Calculate head_dim if we have the info
+        if (self.metadata.hidden_size > 0 and self.metadata.n_heads > 0) {
+            self.metadata.head_dim = self.metadata.hidden_size / self.metadata.n_heads;
+        }
+
+        log.info("Model: {s} ({s})", .{ self.metadata.name, self.metadata.architecture });
+        log.info("Layers: {}, Heads: {}, KV Heads: {}", .{
+            self.metadata.n_layers,
+            self.metadata.n_heads,
+            self.metadata.n_kv_heads,
+        });
+        log.info("Hidden: {}, FFN: {}, Vocab: {}", .{
+            self.metadata.hidden_size,
+            self.metadata.intermediate_size,
+            self.metadata.vocab_size,
+        });
+    }
+
+    /// Store integer metadata value
+    fn storeMetadataU32(self: *Self, key: []const u8, val: u32) void {
+        if (std.mem.endsWith(u8, key, ".block_count") or std.mem.endsWith(u8, key, ".layer_count")) {
+            self.metadata.n_layers = val;
+        } else if (std.mem.endsWith(u8, key, ".attention.head_count")) {
+            self.metadata.n_heads = val;
+        } else if (std.mem.endsWith(u8, key, ".attention.head_count_kv")) {
+            self.metadata.n_kv_heads = val;
+        } else if (std.mem.endsWith(u8, key, ".embedding_length")) {
+            self.metadata.hidden_size = val;
+        } else if (std.mem.endsWith(u8, key, ".feed_forward_length")) {
+            self.metadata.intermediate_size = val;
+        } else if (std.mem.endsWith(u8, key, ".context_length")) {
+            self.metadata.context_length = val;
+        } else if (std.mem.eql(u8, key, "tokenizer.ggml.vocab_size")) {
+            self.metadata.vocab_size = val;
+        }
+    }
+
+    /// Store float metadata value
+    fn storeMetadataF32(self: *Self, key: []const u8, val: f32) void {
+        if (std.mem.endsWith(u8, key, ".rope.freq_base")) {
+            self.metadata.rope_freq_base = val;
+        }
+    }
+
+    /// Store string metadata value
+    fn storeMetadataString(self: *Self, key: []const u8, val: []const u8) void {
+        if (std.mem.eql(u8, key, "general.architecture")) {
+            self.metadata.architecture = val;
+        } else if (std.mem.eql(u8, key, "general.name")) {
+            self.metadata.name = val;
+        }
+    }
+
+    /// Skip array elements when parsing metadata
+    fn skipArrayElements(self: *Self, cursor: *usize, elem_type: GGUFValueType, count: u64) void {
+        for (0..count) |_| {
+            switch (elem_type) {
+                .uint8, .int8, .bool_ => _ = self.readU8(cursor),
+                .uint16, .int16 => _ = self.readU16(cursor),
+                .uint32, .int32, .float32 => cursor.* += 4,
+                .uint64, .int64, .float64 => cursor.* += 8,
+                .string => _ = self.readString(cursor),
+                .array => {
+                    const nested_type: GGUFValueType = @enumFromInt(self.readU32(cursor));
+                    const nested_len = self.readU64(cursor);
+                    self.skipArrayElements(cursor, nested_type, nested_len);
+                },
+            }
+        }
+    }
+
+    /// Parse tensor info table
+    fn parseTensorInfos(self: *Self, cursor: *usize) !void {
+        for (0..self.tensor_count) |_| {
+            // Read tensor name
+            const name_raw = self.readString(cursor);
+            const name = try self.allocator.dupe(u8, name_raw);
+
+            // Read dimensions
+            const n_dims = self.readU32(cursor);
+            var dimensions: [4]u64 = .{ 1, 1, 1, 1 };
+            for (0..n_dims) |i| {
+                dimensions[i] = self.readU64(cursor);
+            }
+
+            // Read type
+            const type_: GGMLType = @enumFromInt(self.readU32(cursor));
+
+            // Read offset
+            const offset = self.readU64(cursor);
+
+            const info = GGUFTensorInfo{
+                .name = name,
+                .n_dims = n_dims,
+                .dimensions = dimensions,
+                .type_ = type_,
+                .offset = offset,
+            };
+
+            try self.tensors.put(name, info);
+        }
+
+        log.info("Parsed {} tensor infos", .{self.tensors.count()});
+    }
+
+    // =========================================================================
+    // Tensor Access
+    // =========================================================================
+
+    /// Get tensor info by name
+    pub fn getTensor(self: *Self, name: []const u8) ?GGUFTensorInfo {
+        return self.tensors.get(name);
+    }
+
+    /// Get raw pointer to tensor data (still quantized)
+    pub fn getTensorData(self: *Self, info: GGUFTensorInfo) []const u8 {
+        const start = self.tensor_data_offset + info.offset;
+        const size = info.sizeBytes();
+        return self.mmap_ptr[start..][0..size];
+    }
+
+    /// Get tensor data by name
+    pub fn getTensorDataByName(self: *Self, name: []const u8) ?[]const u8 {
+        const info = self.getTensor(name) orelse return null;
+        return self.getTensorData(info);
+    }
+
+    // =========================================================================
+    // Raw Q8 Access (for GPU Dequantization)
+    // =========================================================================
+
+    /// Get raw Q8_0 bytes for a tensor (zero-copy from mmap)
+    /// Returns the raw bytes that can be copied to GPU for dequantization
+    pub fn getRawQ8Slice(self: *Self, name: []const u8) ?[]const u8 {
+        const info = self.getTensor(name) orelse return null;
+        if (info.type_ != .q8_0) return null;
+        return self.getTensorData(info);
+    }
+
+    /// Copy raw Q8_0 bytes for a layer's tensor into a destination buffer
+    /// This is used to stage raw data for GPU dequantization
+    pub fn copyRawQ8ToBuffer(self: *Self, name: []const u8, dest: []u8) !usize {
+        const info = self.getTensor(name) orelse return error.TensorNotFound;
+        if (info.type_ != .q8_0) return error.WrongTensorType;
+
+        const src = self.getTensorData(info);
+        if (dest.len < src.len) return error.DestBufferTooSmall;
+
+        @memcpy(dest[0..src.len], src);
+        return src.len;
+    }
+
+    /// Get Q8_0 block count for a tensor (for GPU dispatch sizing)
+    pub fn getQ8BlockCount(self: *Self, name: []const u8) ?usize {
+        const info = self.getTensor(name) orelse return null;
+        if (info.type_ != .q8_0) return null;
+        return info.numElements() / 32; // 32 values per Q8_0 block
+    }
+
+    /// Calculate total Q8_0 bytes needed for a layer
+    /// Used to size the raw staging buffer
+    pub fn getLayerQ8SizeBytes(self: *Self, layer_idx: u32) usize {
+        var total: usize = 0;
+        var name_buf: [64]u8 = undefined;
+
+        // Sum up all Q8_0 tensors in this layer
+        const q8_tensors = [_][]const u8{
+            "blk.{d}.attn_q.weight",
+            "blk.{d}.attn_k.weight",
+            "blk.{d}.attn_v.weight",
+            "blk.{d}.attn_output.weight",
+            "blk.{d}.ffn_gate.weight",
+            "blk.{d}.ffn_up.weight",
+            "blk.{d}.ffn_down.weight",
+        };
+
+        for (q8_tensors) |template| {
+            const name = std.fmt.bufPrint(&name_buf, template, .{layer_idx}) catch continue;
+            if (self.getTensor(name)) |info| {
+                if (info.type_ == .q8_0) {
+                    total += info.sizeBytes();
+                }
+            }
+        }
+
+        return total;
+    }
+
+    /// Dequantize Q8_0 tensor to BF16 using SIMD
+    /// Q8_0 format: [f16 scale][32 x int8] per block
+    pub fn dequantizeQ8_0(self: *Self, info: GGUFTensorInfo, dest: []BF16) !void {
+        if (info.type_ != .q8_0) {
+            log.err("Expected Q8_0 tensor, got {}", .{info.type_});
+            return error.WrongTensorType;
+        }
+
+        const src = self.getTensorData(info);
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) {
+            return error.DestBufferTooSmall;
+        }
+
+        // Use SIMD-optimized dequantization
+        simd.dequantizeQ8_0_SIMD(src, dest, n_elements);
+    }
+
+    /// Dequantize any supported tensor type to BF16
+    pub fn dequantizeToBF16(self: *Self, name: []const u8, dest: []BF16) !void {
+        const info = self.getTensor(name) orelse return error.TensorNotFound;
+
+        switch (info.type_) {
+            .q8_0 => try self.dequantizeQ8_0(info, dest),
+            .f16 => try self.dequantizeF16(info, dest),
+            .bf16 => try self.copyBF16(info, dest),
+            .f32 => try self.dequantizeF32(info, dest),
+            else => {
+                log.err("Unsupported tensor type for dequantization: {}", .{info.type_});
+                return error.UnsupportedTensorType;
+            },
+        }
+    }
+
+    /// Copy F16 tensor to BF16 (with conversion)
+    fn dequantizeF16(self: *Self, info: GGUFTensorInfo, dest: []BF16) !void {
+        const src = self.getTensorData(info);
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) return error.DestBufferTooSmall;
+
+        const src_f16: []const u16 = @as([*]const u16, @ptrCast(@alignCast(src.ptr)))[0..n_elements];
+
+        for (src_f16, 0..) |f16_bits, i| {
+            const f32_val = f16ToF32(f16_bits);
+            dest[i] = f32ToBf16(f32_val);
+        }
+    }
+
+    /// Copy BF16 tensor directly
+    fn copyBF16(self: *Self, info: GGUFTensorInfo, dest: []BF16) !void {
+        const src = self.getTensorData(info);
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) return error.DestBufferTooSmall;
+
+        const src_bf16: []const BF16 = @as([*]const BF16, @ptrCast(@alignCast(src.ptr)))[0..n_elements];
+        @memcpy(dest[0..n_elements], src_bf16);
+    }
+
+    /// Convert F32 tensor to BF16
+    fn dequantizeF32(self: *Self, info: GGUFTensorInfo, dest: []BF16) !void {
+        const src = self.getTensorData(info);
+        const n_elements = info.numElements();
+
+        if (dest.len < n_elements) return error.DestBufferTooSmall;
+
+        const src_f32: []const f32 = @as([*]const f32, @ptrCast(@alignCast(src.ptr)))[0..n_elements];
+        batchF32ToBf16(src_f32, dest[0..n_elements]);
+    }
+
+    // =========================================================================
+    // Layer Access Helpers
+    // =========================================================================
+
+    /// Get all tensor names for a specific layer
+    pub fn getLayerTensorNames(self: *Self, layer_idx: u32, result: *std.ArrayList([]const u8)) !void {
+        var buf: [64]u8 = undefined;
+        const prefix = std.fmt.bufPrint(&buf, "blk.{}.", .{layer_idx}) catch unreachable;
+
+        var it = self.tensors.keyIterator();
+        while (it.next()) |key| {
+            if (std.mem.startsWith(u8, key.*, prefix)) {
+                try result.append(key.*);
+            }
+        }
+    }
+
+    /// Calculate total size of all tensors in a layer (in BF16)
+    pub fn getLayerSizeBF16(self: *Self, layer_idx: u32) u64 {
+        var total: u64 = 0;
+        var buf: [64]u8 = undefined;
+        const prefix = std.fmt.bufPrint(&buf, "blk.{}.", .{layer_idx}) catch unreachable;
+
+        var it = self.tensors.iterator();
+        while (it.next()) |entry| {
+            if (std.mem.startsWith(u8, entry.key_ptr.*, prefix)) {
+                total += entry.value_ptr.numElements() * @sizeOf(BF16);
+            }
+        }
+        return total;
+    }
+
+    // =========================================================================
+    // Read Helpers
+    // =========================================================================
+
+    fn readU8(self: *Self, cursor: *usize) u8 {
+        const val = self.mmap_ptr[cursor.*];
+        cursor.* += 1;
+        return val;
+    }
+
+    fn readU16(self: *Self, cursor: *usize) u16 {
+        const val = std.mem.readInt(u16, self.mmap_ptr[cursor.*..][0..2], .little);
+        cursor.* += 2;
+        return val;
+    }
+
+    fn readU32(self: *Self, cursor: *usize) u32 {
+        const val = std.mem.readInt(u32, self.mmap_ptr[cursor.*..][0..4], .little);
+        cursor.* += 4;
+        return val;
+    }
+
+    fn readI32(self: *Self, cursor: *usize) i32 {
+        const val = std.mem.readInt(i32, self.mmap_ptr[cursor.*..][0..4], .little);
+        cursor.* += 4;
+        return val;
+    }
+
+    fn readU64(self: *Self, cursor: *usize) u64 {
+        const val = std.mem.readInt(u64, self.mmap_ptr[cursor.*..][0..8], .little);
+        cursor.* += 8;
+        return val;
+    }
+
+    fn readI64(self: *Self, cursor: *usize) i64 {
+        const val = std.mem.readInt(i64, self.mmap_ptr[cursor.*..][0..8], .little);
+        cursor.* += 8;
+        return val;
+    }
+
+    fn readF32(self: *Self, cursor: *usize) f32 {
+        const bits = self.readU32(cursor);
+        return @bitCast(bits);
+    }
+
+    fn readF64(self: *Self, cursor: *usize) f64 {
+        const bits = self.readU64(cursor);
+        return @bitCast(bits);
+    }
+
+    fn readString(self: *Self, cursor: *usize) []const u8 {
+        const len = self.readU64(cursor);
+        const str = self.mmap_ptr[cursor.*..][0..len];
+        cursor.* += len;
+        return str;
+    }
+};
+
+// =============================================================================
+// F16 Conversion Helper
+// =============================================================================
+
+/// Convert IEEE 754 half-precision float (f16) to f32
+fn f16ToF32(bits: u16) f32 {
+    const sign: u32 = @as(u32, bits >> 15) << 31;
+    const exp: u32 = (bits >> 10) & 0x1F;
+    const mant: u32 = bits & 0x3FF;
+
+    if (exp == 0) {
+        // Zero or denormal
+        if (mant == 0) {
+            return @bitCast(sign);
+        }
+        // Denormal - convert to normalized f32
+        var m = mant;
+        var e: i32 = -14;
+        while ((m & 0x400) == 0) {
+            m <<= 1;
+            e -= 1;
+        }
+        m &= 0x3FF;
+        const exp32: u32 = @intCast(e + 127);
+        return @bitCast(sign | (exp32 << 23) | (m << 13));
+    } else if (exp == 31) {
+        // Inf or NaN
+        if (mant == 0) {
+            return @bitCast(sign | 0x7F800000); // Inf
+        }
+        return @bitCast(sign | 0x7FC00000 | (mant << 13)); // NaN
+    }
+
+    // Normal number
+    const exp32: u32 = exp + 127 - 15;
+    return @bitCast(sign | (exp32 << 23) | (mant << 13));
+}
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "ggml type block sizes" {
