+
+test "f16 to f32 conversion" {
+    // Zero
+    try std.testing.expectEqual(@as(f32, 0.0), f16ToF32(0x0000));
+
+    // One (f16: 0x3C00)
+    try std.testing.expectApproxEqRel(@as(f32, 1.0), f16ToF32(0x3C00), 0.001);
+
+    // Negative one (f16: 0xBC00)
+    try std.testing.expectApproxEqRel(@as(f32, -1.0), f16ToF32(0xBC00), 0.001);
+
+    // Two (f16: 0x4000)
+    try std.testing.expectApproxEqRel(@as(f32, 2.0), f16ToF32(0x4000), 0.001);
+}

