+//! Zell Inference Engine - Main Entry Point
+//!
+//! Heterogeneous pipelining inference for Qwen2.5-Coder-32B on 32GB Mac.
+//! Architecture:
+//!   - CPU Thread: Reads Q8 from disk/RAM → memcpy to staging buffer
+//!   - GPU Thread: Dequantizes Q8 → BF16, then runs transformer layers
+//!
+//! This achieves ~27x speedup over CPU dequant via zero-copy Metal buffers.
+
+const std = @import("std");
+const gguf = @import("gguf_loader.zig");
+const streaming = @import("streaming_qwen.zig");
+const metal = @import("metal_inference.zig");
+const model = @import("qwen_model.zig");
+
+const log = std.log.scoped(.zell_inference);
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n", .{});
+    std.debug.print("=" ** 70 ++ "\n", .{});
+    std.debug.print("  Zell Inference Engine - Qwen2.5-Coder-32B\n", .{});
+    std.debug.print("  Heterogeneous Pipelining: GPU Dequant + GPU Compute\n", .{});
+    std.debug.print("=" ** 70 ++ "\n\n", .{});
+
+    // Model path
+    const model_path = "/Users/steven_chong/Downloads/repos/zell/models/Qwen2.5-Coder-32B-Instruct-Q8_0.gguf";
+
+    // =========================================================================
+    // Phase 1: Initialize GGUF Loader
+    // =========================================================================
+    std.debug.print("[1/4] Loading GGUF metadata...\n", .{});
+    var loader = try gguf.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    std.debug.print("       Model: {s}\n", .{loader.metadata.name});
+    std.debug.print("       Layers: {}\n", .{loader.metadata.n_layers});
+    std.debug.print("       Hidden: {}\n", .{loader.metadata.hidden_size});
+    std.debug.print("       File: {} GB\n\n", .{loader.mmap_len / (1024 * 1024 * 1024)});
+
+    // =========================================================================
+    // Phase 2: Initialize Metal Engine
+    // =========================================================================
+    std.debug.print("[2/4] Initializing Metal GPU...\n", .{});
+
+    var config = model.QwenConfig{};
+    // Override with GGUF metadata
+    if (loader.metadata.n_layers > 0) config.n_layers = loader.metadata.n_layers;
+    if (loader.metadata.hidden_size > 0) config.hidden_size = loader.metadata.hidden_size;
