+    const RESIDENT_LAYERS: u32 = 20;
+    std.debug.print("       Warming {} resident layers into RAM...\n", .{RESIDENT_LAYERS});
+    try stream_engine.warmResidentLayers(RESIDENT_LAYERS);
+    std.debug.print("       Tiered: {} hot (RAM) + {} cold (SSD)\n\n", .{
+        stream_engine.resident_layers,
+        config.n_layers - stream_engine.resident_layers,
+    });
+
