+    std.debug.print("  GPU Compute (placeholder): {} ms/layer\n\n", .{
+        gpu_compute_time_ns / layers / 1_000_000,
+    });
+
+    stream_engine.printStats();
+
+    std.debug.print("\n", .{});
+    std.debug.print("=" ** 70 ++ "\n", .{});
+    std.debug.print("  PERFORMANCE: {d:.4} tok/s ({} ms/token)\n", .{ tok_per_sec, total_ms });
+    std.debug.print("=" ** 70 ++ "\n", .{});
+
+    // Compare to theoretical limits
+    std.debug.print("\nTheoretical Analysis:\n", .{});
+    std.debug.print("  Resident layers (RAM):   {} × ~50ms  = {} ms\n", .{
+        stream_engine.resident_layers,
+        stream_engine.resident_layers * 50,
+    });
+    std.debug.print("  Streaming layers (SSD):  {} × ~1700ms = {} ms\n", .{
+        layers - stream_engine.resident_layers,
+        (layers - stream_engine.resident_layers) * 1700,
+    });
+    std.debug.print("  Theoretical minimum: ~{} ms/token\n", .{
+        stream_engine.resident_layers * 50 + (layers - stream_engine.resident_layers) * 1700,
+    });
+}

