+//! GPU Dequantization Kernels
+//!
+//! Moves the Q8_0 → BF16 conversion from CPU to GPU.
+//! This eliminates the CPU compute bottleneck (~1.6s/layer → ~0.02s/layer).
+//!
+//! Architecture:
+//!   CPU: memcpy raw Q8 bytes from mmap → shared buffer (fast)
+//!   GPU: dequantize Q8 → BF16 in parallel (100+ GB/s bandwidth)
+
+#include <metal_stdlib>
+using namespace metal;
+
+// BF16 stored as ushort
+typedef ushort bfloat16_t;
+
+// =============================================================================
+// Q8_0 Block Structure (34 bytes)
+// =============================================================================
+// Layout: [delta: f16 (2 bytes)] + [quants: 32 x i8 (32 bytes)]
+
+struct Q8_0_Block {
+    half d;        // Scale factor (f16)
+    char qs[32];   // 32 quantized values (int8)
+};
+
+// =============================================================================
+// Float → BF16 Conversion
+// =============================================================================
+
+inline bfloat16_t float_to_bf16(float x) {
+    return (bfloat16_t)(as_type<uint>(x) >> 16);
+}
+
+// =============================================================================
+// Dequantize Q8_0 → BF16
+// =============================================================================
+// Each thread processes one Q8_0 block (32 values)
+// This ensures coalesced memory access patterns.
+//
+// Input:  src_bytes - Raw Q8_0 data (34 bytes per block)
+// Output: dst - BF16 values (2 bytes per value, 64 bytes per block)
+// Params: num_blocks - Total number of Q8_0 blocks to process
+
+kernel void dequantize_q8_0_bf16(
+    device const uchar* src_bytes [[buffer(0)]],  // Raw Q8_0 bytes
+    device bfloat16_t* dst        [[buffer(1)]],  // Output BF16 values
+    constant uint& num_blocks     [[buffer(2)]],  // Total blocks
+    uint gid                      [[thread_position_in_grid]]
+) {
+    // Bounds check
+    if (gid >= num_blocks) return;
+
+    // 1. Calculate offsets
+    // Q8_0 block size = 34 bytes (2 for delta + 32 for quants)
+    const uint Q8_BLOCK_SIZE = 34;
+    const uint VALUES_PER_BLOCK = 32;
+
+    uint src_offset = gid * Q8_BLOCK_SIZE;
+    uint dst_offset = gid * VALUES_PER_BLOCK;
+
+    // 2. Load delta (f16) from first 2 bytes
+    // Use pointer casting to read as half
+    device const half* delta_ptr = (device const half*)(src_bytes + src_offset);
+    float delta = (float)(*delta_ptr);
+
+    // 3. Get pointer to quantized values (offset +2 bytes)
+    device const char* quants = (device const char*)(src_bytes + src_offset + 2);
+
+    // 4. Dequantize 32 values
+    // Formula: bf16_value = delta * int8_value
+    // Metal compiler will auto-vectorize this loop
+    for (int i = 0; i < 32; i++) {
+        float val = delta * (float)quants[i];
+        dst[dst_offset + i] = float_to_bf16(val);
+    }
+}
+
+// =============================================================================
+// Optimized Version: Process 4 blocks per thread (128 values)
+// =============================================================================
+// Uses thread coarsening to reduce kernel launch overhead
+// Each thread processes 4 consecutive blocks
+
+kernel void dequantize_q8_0_bf16_x4(
+    device const uchar* src_bytes [[buffer(0)]],
+    device bfloat16_t* dst        [[buffer(1)]],
+    constant uint& num_blocks     [[buffer(2)]],
+    uint gid                      [[thread_position_in_grid]]
+) {
+    const uint Q8_BLOCK_SIZE = 34;
+    const uint VALUES_PER_BLOCK = 32;
+    const uint BLOCKS_PER_THREAD = 4;
+
+    uint base_block = gid * BLOCKS_PER_THREAD;
+
+    // Process 4 blocks
+    for (uint b = 0; b < BLOCKS_PER_THREAD; b++) {
+        uint block_idx = base_block + b;
+        if (block_idx >= num_blocks) return;
+
+        uint src_offset = block_idx * Q8_BLOCK_SIZE;
+        uint dst_offset = block_idx * VALUES_PER_BLOCK;
+
+        // Load delta
+        device const half* delta_ptr = (device const half*)(src_bytes + src_offset);
+        float delta = (float)(*delta_ptr);
+
+        // Get quants pointer
+        device const char* quants = (device const char*)(src_bytes + src_offset + 2);
+
+        // Dequantize 32 values
+        for (int i = 0; i < 32; i++) {
+            float val = delta * (float)quants[i];
+            dst[dst_offset + i] = float_to_bf16(val);
+        }
+    }
+}
+
+// =============================================================================
+// SIMD-Optimized Version: Use simdgroup operations
+// =============================================================================
+// Each simdgroup (32 threads) cooperatively processes blocks
+// Threads within simdgroup share delta via shuffle
+
+kernel void dequantize_q8_0_bf16_simd(
+    device const uchar* src_bytes [[buffer(0)]],
+    device bfloat16_t* dst        [[buffer(1)]],
+    constant uint& num_blocks     [[buffer(2)]],
+    uint gid                      [[thread_position_in_grid]],
+    uint simd_lane                [[thread_index_in_simdgroup]]
+) {
+    const uint Q8_BLOCK_SIZE = 34;
+    const uint VALUES_PER_BLOCK = 32;
+
+    // Each thread in the simdgroup handles one value from the same block
+    // Block index = gid / 32 (since 32 threads per block)
+    uint block_idx = gid / VALUES_PER_BLOCK;
+    uint value_idx = simd_lane;  // 0-31
+
+    if (block_idx >= num_blocks) return;
+
+    uint src_offset = block_idx * Q8_BLOCK_SIZE;
+    uint dst_offset = block_idx * VALUES_PER_BLOCK;
+
+    // Lane 0 loads delta, then broadcasts to all lanes
+    float delta = 0.0f;
+    if (simd_lane == 0) {
+        device const half* delta_ptr = (device const half*)(src_bytes + src_offset);
+        delta = (float)(*delta_ptr);
+    }
+    delta = simd_broadcast_first(delta);
+
+    // Each lane loads its own quantized value
+    device const char* quants = (device const char*)(src_bytes + src_offset + 2);
+    float val = delta * (float)quants[value_idx];
+
+    // Write output
+    dst[dst_offset + value_idx] = float_to_bf16(val);
+}
+
+// =============================================================================
+// Batch Dequantize: Process entire tensor with offset mapping
+// =============================================================================
+// For dequantizing multiple tensors packed in one buffer
+// Uses an offset table to know where each tensor starts/ends
+
+struct TensorOffsets {
+    uint src_offset;  // Byte offset in Q8 buffer
+    uint dst_offset;  // Element offset in BF16 buffer
+    uint num_blocks;  // Number of Q8 blocks in this tensor
+};
+
+kernel void dequantize_q8_0_bf16_batch(
+    device const uchar* src_bytes         [[buffer(0)]],
+    device bfloat16_t* dst                [[buffer(1)]],
+    constant TensorOffsets* offsets       [[buffer(2)]],
+    constant uint& num_tensors            [[buffer(3)]],
+    uint2 gid                             [[thread_position_in_grid]]
+) {
+    // gid.x = block index within tensor
+    // gid.y = tensor index
+
+    if (gid.y >= num_tensors) return;
+
+    TensorOffsets tinfo = offsets[gid.y];
+    if (gid.x >= tinfo.num_blocks) return;
+
+    const uint Q8_BLOCK_SIZE = 34;
+    const uint VALUES_PER_BLOCK = 32;
+
+    uint src_offset = tinfo.src_offset + gid.x * Q8_BLOCK_SIZE;
+    uint dst_offset = tinfo.dst_offset + gid.x * VALUES_PER_BLOCK;
+
+    // Load delta
+    device const half* delta_ptr = (device const half*)(src_bytes + src_offset);
+    float delta = (float)(*delta_ptr);
+
+    // Get quants
+    device const char* quants = (device const char*)(src_bytes + src_offset + 2);
+
+    // Dequantize
+    for (int i = 0; i < 32; i++) {
+        float val = delta * (float)quants[i];
+        dst[dst_offset + i] = float_to_bf16(val);
+    }
+}

