+//! Objective-C / Metal Framework Bindings
+//!
+//! Low-level bindings to Apple's Metal framework via Objective-C runtime.
+//! Only compiled on macOS with Apple Silicon.
+
+const std = @import("std");
+const builtin = @import("builtin");
+
+// =============================================================================
+// Type Aliases for Metal Objects (Opaque Pointers)
+// =============================================================================
+
+pub const MTLDevice = *anyopaque;
+pub const MTLCommandQueue = *anyopaque;
+pub const MTLCommandBuffer = *anyopaque;
+pub const MTLComputeCommandEncoder = *anyopaque;
+pub const MTLBuffer = *anyopaque;
+pub const MTLLibrary = *anyopaque;
+pub const MTLFunction = *anyopaque;
+pub const MTLComputePipelineState = *anyopaque;
+pub const NSString = *anyopaque;
+pub const NSError = *anyopaque;
+
+// =============================================================================
+// Metal Resource Options
+// =============================================================================
+
+/// MTLResourceStorageModeShared - CPU and GPU share memory (Zero-Copy on Apple Silicon)
+pub const MTLResourceStorageModeShared: u64 = 0 << 4;
+/// MTLResourceStorageModeManaged - Explicit sync between CPU/GPU
+pub const MTLResourceStorageModeManaged: u64 = 1 << 4;
+/// MTLResourceStorageModePrivate - GPU only
+pub const MTLResourceStorageModePrivate: u64 = 2 << 4;
+
+/// MTLResourceCPUCacheModeDefaultCache
+pub const MTLResourceCPUCacheModeDefaultCache: u64 = 0;
+/// MTLResourceCPUCacheModeWriteCombined
+pub const MTLResourceCPUCacheModeWriteCombined: u64 = 1;
+
+// =============================================================================
+// External C/ObjC Functions (macOS only)
+// =============================================================================
+
+const c = if (builtin.os.tag == .macos) struct {
+    // Metal framework
+    extern "Metal" fn MTLCreateSystemDefaultDevice() ?MTLDevice;
+
+    // Objective-C runtime
+    extern "objc" fn objc_msgSend() void;
+    extern "objc" fn sel_registerName(name: [*:0]const u8) *anyopaque;
+    extern "objc" fn objc_getClass(name: [*:0]const u8) ?*anyopaque;
+
+    // Foundation - NSString
+    extern "Foundation" fn CFStringCreateWithCString(
+        alloc: ?*anyopaque,
+        cStr: [*:0]const u8,
+        encoding: u32,
+    ) ?NSString;
+
+    extern "Foundation" fn CFStringCreateWithBytes(
+        alloc: ?*anyopaque,
+        bytes: [*]const u8,
+        numBytes: i64,
+        encoding: u32,
+        isExternalRepresentation: u8,
+    ) ?NSString;
+} else struct {};
+
+// =============================================================================
+// Core Functions
+// =============================================================================
+
+/// Create the default Metal device (Apple Silicon GPU)
+pub fn createSystemDefaultDevice() ?MTLDevice {
+    if (comptime builtin.os.tag != .macos) return null;
+    return c.MTLCreateSystemDefaultDevice();
+}
+
+/// Get selector by name
+pub fn sel(name: [*:0]const u8) *anyopaque {
+    if (comptime builtin.os.tag != .macos) {
+        @compileError("Metal only available on macOS");
+    }
+    return c.sel_registerName(name);
+}
+
+/// Generic Objective-C message send (no args, returns value)
+pub fn msgSend(comptime ReturnType: type) *const fn (*anyopaque, *anyopaque) callconv(.c) ReturnType {
+    if (comptime builtin.os.tag != .macos) {
+        @compileError("Metal only available on macOS");
+    }
+    return @ptrCast(&c.objc_msgSend);
+}
+
+/// Message send with one argument
+pub fn msgSend1(
+    comptime ReturnType: type,
+    comptime Arg1: type,
+) *const fn (*anyopaque, *anyopaque, Arg1) callconv(.c) ReturnType {
+    if (comptime builtin.os.tag != .macos) {
+        @compileError("Metal only available on macOS");
+    }
+    return @ptrCast(&c.objc_msgSend);
+}
+
+/// Message send with two arguments
+pub fn msgSend2(
+    comptime ReturnType: type,
+    comptime Arg1: type,
+    comptime Arg2: type,
+) *const fn (*anyopaque, *anyopaque, Arg1, Arg2) callconv(.c) ReturnType {
+    if (comptime builtin.os.tag != .macos) {
+        @compileError("Metal only available on macOS");
+    }
+    return @ptrCast(&c.objc_msgSend);
+}
+
+/// Message send with three arguments
+pub fn msgSend3(
+    comptime ReturnType: type,
+    comptime Arg1: type,
+    comptime Arg2: type,
+    comptime Arg3: type,
+) *const fn (*anyopaque, *anyopaque, Arg1, Arg2, Arg3) callconv(.c) ReturnType {
+    if (comptime builtin.os.tag != .macos) {
+        @compileError("Metal only available on macOS");
+    }
+    return @ptrCast(&c.objc_msgSend);
+}
+
+/// Message send with four arguments
+pub fn msgSend4(
+    comptime ReturnType: type,
+    comptime Arg1: type,
+    comptime Arg2: type,
+    comptime Arg3: type,
+    comptime Arg4: type,
+) *const fn (*anyopaque, *anyopaque, Arg1, Arg2, Arg3, Arg4) callconv(.c) ReturnType {
+    if (comptime builtin.os.tag != .macos) {
+        @compileError("Metal only available on macOS");
+    }
+    return @ptrCast(&c.objc_msgSend);
+}
+
+/// Release an Objective-C object
+pub fn release(obj: *anyopaque) void {
+    if (comptime builtin.os.tag != .macos) return;
+    const releaseMsg = msgSend(void);
+    releaseMsg(obj, sel("release"));
+}
+
+/// Retain an Objective-C object
+pub fn retain(obj: *anyopaque) *anyopaque {
+    if (comptime builtin.os.tag != .macos) return obj;
+    const retainMsg = msgSend(*anyopaque);
+    return retainMsg(obj, sel("retain"));
+}
+
+// =============================================================================
+// NSString Utilities
+// =============================================================================
+
+/// Create NSString from Zig string slice (for short strings, up to 4KB)
+pub fn createNSString(str: []const u8) ?NSString {
+    if (comptime builtin.os.tag != .macos) return null;
+
+    // Need null-terminated string
+    var buf: [4096]u8 = undefined;
+    if (str.len >= buf.len) return null;
+
+    @memcpy(buf[0..str.len], str);
+    buf[str.len] = 0;
+
+    // kCFStringEncodingUTF8 = 0x08000100
+    return c.CFStringCreateWithCString(null, @ptrCast(&buf), 0x08000100);
+}
+
+/// Create NSString from large string slice (no size limit, uses CFStringCreateWithBytes)
+pub fn createNSStringLong(str: []const u8) ?NSString {
+    if (comptime builtin.os.tag != .macos) return null;
+
+    // kCFStringEncodingUTF8 = 0x08000100
+    // Use CFStringCreateWithBytes which doesn't require null termination
+    return c.CFStringCreateWithBytes(
+        null,
+        str.ptr,
+        @intCast(str.len),
+        0x08000100, // kCFStringEncodingUTF8
+        0, // isExternalRepresentation = false
+    );
+}
+
+// =============================================================================
+// MTLDevice Methods
+// =============================================================================
+
+/// [device newCommandQueue]
+pub fn deviceNewCommandQueue(device: MTLDevice) ?MTLCommandQueue {
+    if (comptime builtin.os.tag != .macos) return null;
+    const newCommandQueue = msgSend(?MTLCommandQueue);
+    return newCommandQueue(device, sel("newCommandQueue"));
+}
+
+/// [device name]
+pub fn deviceGetName(device: MTLDevice) []const u8 {
+    if (comptime builtin.os.tag != .macos) return "Unknown";
+    // name returns NSString, need to get UTF8String from it
+    const getName = msgSend(?NSString);
+    const ns_name = getName(device, sel("name")) orelse return "Unknown";
+    // Get C string from NSString
+    const getUTF8 = msgSend(?[*:0]const u8);
+    const cstr = getUTF8(ns_name, sel("UTF8String")) orelse return "Unknown";
+    return std.mem.span(cstr);
+}
+
+/// [device newBufferWithLength:options:]
+pub fn deviceNewBuffer(device: MTLDevice, length: u64, options: u64) ?MTLBuffer {
+    if (comptime builtin.os.tag != .macos) return null;
+    const newBuffer = msgSend2(?MTLBuffer, u64, u64);
+    return newBuffer(device, sel("newBufferWithLength:options:"), length, options);
+}
+
+/// [device newBufferWithBytes:length:options:]
+pub fn deviceNewBufferWithBytes(device: MTLDevice, ptr: *const anyopaque, length: u64, options: u64) ?MTLBuffer {
+    if (comptime builtin.os.tag != .macos) return null;
+    const newBuffer = msgSend3(?MTLBuffer, *const anyopaque, u64, u64);
+    return newBuffer(device, sel("newBufferWithBytes:length:options:"), ptr, length, options);
+}
+
+/// [device newBufferWithBytesNoCopy:length:options:deallocator:]
+/// Critical for Zero-Copy: wraps existing memory (e.g., mmap'd Lance data)
+pub fn deviceNewBufferNoCopy(device: MTLDevice, ptr: *anyopaque, length: u64, options: u64) ?MTLBuffer {
+    if (comptime builtin.os.tag != .macos) return null;
+    const newBuffer = msgSend4(?MTLBuffer, *anyopaque, u64, u64, ?*anyopaque);
+    return newBuffer(device, sel("newBufferWithBytesNoCopy:length:options:deallocator:"), ptr, length, options, null);
+}
