+//! Qwen2.5 Metal Kernels for Streaming Inference
+//!
+//! These kernels implement the Qwen2.5-specific operations that differ from GPT-2:
+//! - RMSNorm (instead of LayerNorm)
+//! - RoPE (Rotary Positional Embeddings)
+//! - SwiGLU activation (instead of GELU)
+//! - GQA (Grouped Query Attention) with KV cache
+//!
+//! Designed for streaming inference with heterogeneous pipelining.
+
+#include <metal_stdlib>
+using namespace metal;
+
+// =============================================================================
+// BF16 Helper Types and Functions
+// =============================================================================
+
+// Use ushort for BF16 storage (compatible with all Metal versions)
+typedef ushort bfloat16_t;
+
+// Convert bf16 -> float
+inline float bf16_to_float(bfloat16_t x) {
+    uint32_t val = (uint32_t)x << 16;
+    return as_type<float>(val);
+}
+
+// Convert float -> bf16 (truncation for speed)
+inline bfloat16_t float_to_bf16(float x) {
+    return (bfloat16_t)(as_type<uint32_t>(x) >> 16);
+}
+
+// =============================================================================
+// 1. RMSNorm (Root Mean Square Normalization)
+// =============================================================================
+// Formula: y = x * (1 / sqrt(mean(x^2) + eps)) * weight
+//
+// Unlike LayerNorm, RMSNorm doesn't subtract the mean - it only normalizes
+// by the root mean square. This is simpler and faster.
+
+kernel void rmsnorm_bf16(
+    device const bfloat16_t* input  [[buffer(0)]],  // [batch, seq, hidden]
+    device const bfloat16_t* weight [[buffer(1)]],  // [hidden] (gamma)
+    device bfloat16_t* output       [[buffer(2)]],  // [batch, seq, hidden]
+    constant float& eps             [[buffer(3)]],  // 1e-6 typically
+    constant uint& hidden_size      [[buffer(4)]],  // 5120 for Qwen2.5-32B
+    uint2 gid                       [[thread_position_in_grid]]
+) {
+    // gid.x = element index within row (0..hidden_size-1)
+    // gid.y = row index (batch * seq)
+
+    const uint row = gid.y;
+    const uint offset = row * hidden_size;
+
+    // Only thread 0 per row computes the norm (we'll use a better approach below)
+    // For simplicity, each thread processes the full row
+    if (gid.x != 0) return;
+
+    // 1. Calculate Sum of Squares
+    float sum_sq = 0.0f;
+    for (uint i = 0; i < hidden_size; i++) {
+        float x = bf16_to_float(input[offset + i]);
+        sum_sq += x * x;
+    }
+
+    // 2. Calculate Inverse RMS
+    float mean_sq = sum_sq / (float)hidden_size;
+    float inv_rms = rsqrt(mean_sq + eps);
+
+    // 3. Normalize and Scale
+    for (uint i = 0; i < hidden_size; i++) {
+        float x = bf16_to_float(input[offset + i]);
+        float w = bf16_to_float(weight[i]);
+        output[offset + i] = float_to_bf16(x * inv_rms * w);
+    }
+}
+
+// Optimized RMSNorm using threadgroup reduction
+kernel void rmsnorm_bf16_fast(
+    device const bfloat16_t* input  [[buffer(0)]],
+    device const bfloat16_t* weight [[buffer(1)]],
+    device bfloat16_t* output       [[buffer(2)]],
+    constant float& eps             [[buffer(3)]],
+    constant uint& hidden_size      [[buffer(4)]],
+    uint2 gid                       [[thread_position_in_grid]],
+    uint2 tid                       [[thread_position_in_threadgroup]],
+    uint2 tg_size                   [[threads_per_threadgroup]]
+) {
+    const uint row = gid.y;
+    const uint col = gid.x;
+    const uint offset = row * hidden_size;
+
+    // Shared memory for partial sums
+    threadgroup float partial_sums[256];
+
+    // Each thread accumulates partial sum of squares
+    float local_sum = 0.0f;
+    for (uint i = col; i < hidden_size; i += tg_size.x) {
+        float x = bf16_to_float(input[offset + i]);
+        local_sum += x * x;
+    }
+    partial_sums[tid.x] = local_sum;
+
+    threadgroup_barrier(mem_flags::mem_threadgroup);
+
+    // Parallel reduction
+    for (uint s = tg_size.x / 2; s > 0; s >>= 1) {
+        if (tid.x < s) {
+            partial_sums[tid.x] += partial_sums[tid.x + s];
+        }
+        threadgroup_barrier(mem_flags::mem_threadgroup);
+    }
+
+    // Thread 0 has the total sum
+    float inv_rms = rsqrt(partial_sums[0] / (float)hidden_size + eps);
+
+    threadgroup_barrier(mem_flags::mem_threadgroup);
+
+    // All threads apply normalization
+    for (uint i = col; i < hidden_size; i += tg_size.x) {
+        float x = bf16_to_float(input[offset + i]);
+        float w = bf16_to_float(weight[i]);
+        output[offset + i] = float_to_bf16(x * inv_rms * w);
+    }
+}
+
+// =============================================================================
+// 2. RoPE (Rotary Positional Embedding)
+// =============================================================================
+// Rotates adjacent pairs of elements in Q/K vectors based on position.
+// This gives the model position information without explicit position embeddings.
+//
+// Formula:
+//   x'[2i]   = x[2i]   * cos(theta) - x[2i+1] * sin(theta)
+//   x'[2i+1] = x[2i]   * sin(theta) + x[2i+1] * cos(theta)
+//
+// where theta = position / (base ^ (2i / dim))
+// Qwen2.5 uses freq_base = 1,000,000 for extended context
+
+kernel void rope_bf16(
+    device bfloat16_t* data       [[buffer(0)]],  // Q or K [batch, seq, n_heads, head_dim]
+    constant uint& head_dim       [[buffer(1)]],  // 128 for Qwen2.5
+    constant uint& position       [[buffer(2)]],  // Current token position
+    constant float& freq_base     [[buffer(3)]],  // 1000000.0 for Qwen2.5
+    uint2 gid                     [[thread_position_in_grid]]
+) {
+    // gid.x = pair index (0..head_dim/2 - 1)
+    // gid.y = head index (flattened: batch * seq * n_heads)
+
+    const uint pair_idx = gid.x;
+    const uint head_idx = gid.y;
+
+    if (pair_idx >= head_dim / 2) return;
+
+    const uint offset = head_idx * head_dim;
+
+    // Calculate theta for this dimension pair
+    // theta = pos / (base ^ (2*i / dim))
+    // = pos * base^(-2*i/dim)
+    float theta_exp = (float)(2 * pair_idx) / (float)head_dim;
+    float theta = (float)position * pow(freq_base, -theta_exp);
+
+    float cos_theta = cos(theta);
+    float sin_theta = sin(theta);
+
+    // Load the pair (adjacent elements)
+    uint idx0 = offset + 2 * pair_idx;
+    uint idx1 = offset + 2 * pair_idx + 1;
+
+    float x0 = bf16_to_float(data[idx0]);
+    float x1 = bf16_to_float(data[idx1]);
+
+    // Apply rotation
+    float out0 = x0 * cos_theta - x1 * sin_theta;
+    float out1 = x0 * sin_theta + x1 * cos_theta;
+
+    data[idx0] = float_to_bf16(out0);
+    data[idx1] = float_to_bf16(out1);
+}
+
+// RoPE for batched Q and K simultaneously
+kernel void rope_qk_bf16(
+    device bfloat16_t* q          [[buffer(0)]],  // [batch, n_heads, head_dim]
+    device bfloat16_t* k          [[buffer(1)]],  // [batch, n_kv_heads, head_dim]
+    constant uint& head_dim       [[buffer(2)]],  // 128
+    constant uint& n_q_heads      [[buffer(3)]],  // 40
+    constant uint& n_kv_heads     [[buffer(4)]],  // 8
+    constant uint& position       [[buffer(5)]],
+    constant float& freq_base     [[buffer(6)]],
+    uint2 gid                     [[thread_position_in_grid]]
+) {
+    const uint pair_idx = gid.x;
+    const uint head_idx = gid.y;
+
+    if (pair_idx >= head_dim / 2) return;
+
+    // Calculate theta
+    float theta_exp = (float)(2 * pair_idx) / (float)head_dim;
+    float theta = (float)position * pow(freq_base, -theta_exp);
+    float cos_theta = cos(theta);
+    float sin_theta = sin(theta);
+
+    // Apply to Q heads
+    if (head_idx < n_q_heads) {
+        uint q_offset = head_idx * head_dim;
+        uint idx0 = q_offset + 2 * pair_idx;
+        uint idx1 = q_offset + 2 * pair_idx + 1;
+
+        float x0 = bf16_to_float(q[idx0]);
+        float x1 = bf16_to_float(q[idx1]);
+
+        q[idx0] = float_to_bf16(x0 * cos_theta - x1 * sin_theta);
+        q[idx1] = float_to_bf16(x0 * sin_theta + x1 * cos_theta);
+    }
+
+    // Apply to K heads (fewer due to GQA)
+    if (head_idx < n_kv_heads) {
+        uint k_offset = head_idx * head_dim;
+        uint idx0 = k_offset + 2 * pair_idx;
+        uint idx1 = k_offset + 2 * pair_idx + 1;
+
+        float x0 = bf16_to_float(k[idx0]);
+        float x1 = bf16_to_float(k[idx1]);
+
+        k[idx0] = float_to_bf16(x0 * cos_theta - x1 * sin_theta);
+        k[idx1] = float_to_bf16(x0 * sin_theta + x1 * cos_theta);
+    }
+}
+
+// =============================================================================
+// 3. SwiGLU Activation
+// =============================================================================
+// SwiGLU is used in the FFN instead of GELU.
+// Formula: output = SiLU(gate) * up
+// where SiLU(x) = x * sigmoid(x) = x / (1 + exp(-x))
+
+kernel void swiglu_bf16(
+    device const bfloat16_t* gate_in [[buffer(0)]],  // [batch, seq, ffn_dim]
+    device const bfloat16_t* up_in   [[buffer(1)]],  // [batch, seq, ffn_dim]
+    device bfloat16_t* output        [[buffer(2)]],  // [batch, seq, ffn_dim]
+    uint gid                         [[thread_position_in_grid]]
+) {
+    float g = bf16_to_float(gate_in[gid]);
+    float u = bf16_to_float(up_in[gid]);
+
+    // SiLU = x * sigmoid(x) = x / (1 + exp(-x))
+    float silu = g / (1.0f + exp(-g));
+
+    output[gid] = float_to_bf16(silu * u);
+}
+
+// Fused matmul + SwiGLU for FFN (when gate and up come from same weight matrix)
+kernel void ffn_swiglu_fused_bf16(
+    device const bfloat16_t* input      [[buffer(0)]],  // [hidden]
+    device const bfloat16_t* gate_weight[[buffer(1)]],  // [hidden, ffn_dim]
+    device const bfloat16_t* up_weight  [[buffer(2)]],  // [hidden, ffn_dim]
+    device bfloat16_t* output           [[buffer(3)]],  // [ffn_dim]
+    constant uint& hidden_size          [[buffer(4)]],  // 5120
+    constant uint& ffn_dim              [[buffer(5)]],  // 27648
+    uint gid                            [[thread_position_in_grid]]
+) {
+    if (gid >= ffn_dim) return;
+
+    // Compute gate activation
+    float gate_sum = 0.0f;
+    float up_sum = 0.0f;
+
+    for (uint i = 0; i < hidden_size; i++) {
+        float x = bf16_to_float(input[i]);
+        gate_sum += x * bf16_to_float(gate_weight[i * ffn_dim + gid]);
+        up_sum += x * bf16_to_float(up_weight[i * ffn_dim + gid]);
+    }
+
+    // Apply SwiGLU
+    float silu = gate_sum / (1.0f + exp(-gate_sum));
+    output[gid] = float_to_bf16(silu * up_sum);
+}
+
+// =============================================================================
+// 4. KV Cache Operations
+// =============================================================================
+
+// Update KV cache with new K, V for current position
+kernel void cache_kv_bf16(
+    device const bfloat16_t* new_k    [[buffer(0)]],  // [n_kv_heads, head_dim]
+    device const bfloat16_t* new_v    [[buffer(1)]],  // [n_kv_heads, head_dim]
+    device bfloat16_t* cache_k        [[buffer(2)]],  // [n_kv_heads, max_ctx, head_dim]
+    device bfloat16_t* cache_v        [[buffer(3)]],  // [n_kv_heads, max_ctx, head_dim]
+    constant uint& position           [[buffer(4)]],
+    constant uint& head_dim           [[buffer(5)]],
+    constant uint& n_kv_heads         [[buffer(6)]],
+    constant uint& max_ctx            [[buffer(7)]],
+    uint2 gid                         [[thread_position_in_grid]]
+) {
+    // gid.x = element within head (0..head_dim-1)
+    // gid.y = head index (0..n_kv_heads-1)
+
+    if (gid.x >= head_dim || gid.y >= n_kv_heads) return;
+
+    uint head_idx = gid.y;
+    uint elem_idx = gid.x;
+
+    // Source: new_k/v layout is [n_kv_heads, head_dim]
+    uint src_offset = head_idx * head_dim + elem_idx;
+
+    // Destination: cache layout is [n_kv_heads, max_ctx, head_dim]
+    uint dest_offset = head_idx * (max_ctx * head_dim) + position * head_dim + elem_idx;
+
+    cache_k[dest_offset] = new_k[src_offset];
+    cache_v[dest_offset] = new_v[src_offset];
+}
+
+// =============================================================================
+// 5. Grouped Query Attention (GQA)
+// =============================================================================
+// Qwen2.5-32B uses 40 query heads but only 8 KV heads.
+// Each KV head serves 5 query heads.
+
+kernel void gqa_attention_bf16(
+    device const bfloat16_t* q        [[buffer(0)]],   // [n_q_heads, head_dim]
+    device const bfloat16_t* cache_k  [[buffer(1)]],   // [n_kv_heads, seq_len, head_dim]
+    device const bfloat16_t* cache_v  [[buffer(2)]],   // [n_kv_heads, seq_len, head_dim]
+    device bfloat16_t* output         [[buffer(3)]],   // [n_q_heads, head_dim]
+    constant uint& n_q_heads          [[buffer(4)]],   // 40
+    constant uint& n_kv_heads         [[buffer(5)]],   // 8
+    constant uint& head_dim           [[buffer(6)]],   // 128
+    constant uint& seq_len            [[buffer(7)]],   // Current sequence length
+    constant float& scale             [[buffer(8)]],   // 1/sqrt(head_dim)
+    uint2 gid                         [[thread_position_in_grid]]
+) {
+    // gid.x = output element within head (0..head_dim-1)
+    // gid.y = query head index (0..n_q_heads-1)
+
+    uint q_head = gid.y;
+    uint out_idx = gid.x;
+
+    if (q_head >= n_q_heads || out_idx >= head_dim) return;
+
+    // Map query head to KV head (GQA mapping)
+    // 40 query heads / 8 kv heads = 5 queries per KV head
+    uint kv_head = q_head / (n_q_heads / n_kv_heads);
+
+    // Compute attention scores for all positions
+    // scores[pos] = sum_d(q[d] * k[pos, d]) * scale
+
+    // First pass: compute attention scores and find max
+    float max_score = -INFINITY;
+    for (uint pos = 0; pos < seq_len; pos++) {
+        float score = 0.0f;
+        for (uint d = 0; d < head_dim; d++) {
+            float q_val = bf16_to_float(q[q_head * head_dim + d]);
+            float k_val = bf16_to_float(cache_k[kv_head * seq_len * head_dim + pos * head_dim + d]);
+            score += q_val * k_val;
+        }
+        score *= scale;
+        max_score = max(max_score, score);
+    }
+
+    // Second pass: compute softmax and weighted sum
+    float sum_exp = 0.0f;
+    float out_val = 0.0f;
+
+    for (uint pos = 0; pos < seq_len; pos++) {
+        // Recompute score
+        float score = 0.0f;
+        for (uint d = 0; d < head_dim; d++) {
+            float q_val = bf16_to_float(q[q_head * head_dim + d]);
+            float k_val = bf16_to_float(cache_k[kv_head * seq_len * head_dim + pos * head_dim + d]);
+            score += q_val * k_val;
+        }
+        score *= scale;
+
+        float exp_score = exp(score - max_score);
+        sum_exp += exp_score;
+
+        // Accumulate weighted V
+        float v_val = bf16_to_float(cache_v[kv_head * seq_len * head_dim + pos * head_dim + out_idx]);
+        out_val += exp_score * v_val;
+    }
+
+    // Normalize
+    output[q_head * head_dim + out_idx] = float_to_bf16(out_val / sum_exp);
+}
+
+// =============================================================================
+// 6. Simple MatMul (for weight matrices)
+// =============================================================================
+
+kernel void matmul_bf16(
+    device const bfloat16_t* A [[buffer(0)]],  // [M, K]
