+    constant uint& M           [[buffer(3)]],
+    constant uint& N           [[buffer(4)]],
+    constant uint& K           [[buffer(5)]],
+    uint2 gid                  [[thread_position_in_grid]]
+) {
+    uint row = gid.y;
+    uint col = gid.x;
+
+    if (row >= M || col >= N) return;
+
+    float sum = 0.0f;
+    for (uint k = 0; k < K; k++) {
+        sum += bf16_to_float(A[row * K + k]) * bf16_to_float(B[k * N + col]);
+    }
+
+    C[row * N + col] = float_to_bf16(sum);
+}
+
+// MatMul with bias addition
+kernel void matmul_bias_bf16(
+    device const bfloat16_t* A    [[buffer(0)]],  // [M, K]
+    device const bfloat16_t* B    [[buffer(1)]],  // [K, N]
+    device const bfloat16_t* bias [[buffer(2)]],  // [N]
+    device bfloat16_t* C          [[buffer(3)]],  // [M, N]
+    constant uint& M              [[buffer(4)]],
+    constant uint& N              [[buffer(5)]],
+    constant uint& K              [[buffer(6)]],
+    uint2 gid                     [[thread_position_in_grid]]
