+    for (uint k = 0; k < K; k++) {
+        sum += bf16_to_float(A[row * K + k]) * bf16_to_float(B[k * N + col]);
+    }
+
+    C[row * N + col] = float_to_bf16(sum);
+}
+
+// =============================================================================
+// 7. Residual Add
+// =============================================================================
+
+kernel void residual_add_bf16(
+    device const bfloat16_t* input    [[buffer(0)]],
+    device const bfloat16_t* residual [[buffer(1)]],
+    device bfloat16_t* output         [[buffer(2)]],
+    uint gid                          [[thread_position_in_grid]]
