+//! Metal Inference Engine for Qwen2.5 Streaming
+//!
+//! Manages Metal device, buffers, and kernel dispatch for streaming inference.
+//! Uses per-kernel synchronous dispatch to prevent GPU lockup.
+
+const std = @import("std");
+const objc = @import("metal/objc.zig");
+const model = @import("qwen_model.zig");
+const streaming = @import("streaming_qwen.zig");
+const QwenConfig = model.QwenConfig;
+const LayerOffsets = model.LayerOffsets;
+const MmapQ8Pointers = streaming.MmapQ8Pointers;
+pub const BF16 = @import("gguf_loader.zig").BF16;
+
+const log = std.log.scoped(.metal_inference);
+
+/// Qwen2.5 Metal kernels source
+const qwen_kernels_source = @embedFile("metal/qwen_kernels.metal");
+
+/// GPU dequantization kernels source
+const dequant_kernels_source = @embedFile("metal/dequant_kernels.metal");
+
+/// Metal buffer for inference
+pub const InferenceBuffer = struct {
+    handle: objc.MTLBuffer,
+    size: u64,
+
+    pub fn contents(self: InferenceBuffer) [*]u8 {
+        return objc.bufferContents(self.handle);
+    }
+
+    pub fn asSlice(self: InferenceBuffer, comptime T: type, count: usize) []T {
+        const ptr: [*]T = @ptrCast(@alignCast(self.contents()));
+        return ptr[0..count];
+    }
+};
+
+/// Metal Inference Engine
+pub const MetalInferenceEngine = struct {
+    allocator: std.mem.Allocator,
+    device: objc.MTLDevice,
+    command_queue: objc.MTLCommandQueue,
+    library: ?objc.MTLLibrary,
+
+    // Pipeline states for each kernel
+    rmsnorm_pipeline: ?objc.MTLComputePipelineState = null,
+    rope_pipeline: ?objc.MTLComputePipelineState = null,
+    swiglu_pipeline: ?objc.MTLComputePipelineState = null,
+    matmul_pipeline: ?objc.MTLComputePipelineState = null,
+    gqa_pipeline: ?objc.MTLComputePipelineState = null,
+    residual_pipeline: ?objc.MTLComputePipelineState = null,
+
+    // Dequantization pipelines
+    dequant_library: ?objc.MTLLibrary = null,
+    dequant_q8_pipeline: ?objc.MTLComputePipelineState = null,
+    dequant_q8_x4_pipeline: ?objc.MTLComputePipelineState = null,
+
+    // Model config
+    config: QwenConfig,
+
+    // Persistent buffers
+    kv_cache_k: ?InferenceBuffer = null,
+    kv_cache_v: ?InferenceBuffer = null,
+    hidden_state: ?InferenceBuffer = null,
+    intermediate: ?InferenceBuffer = null,
+
+    const Self = @This();
+
+    /// Initialize Metal inference engine
+    pub fn init(allocator: std.mem.Allocator, config: QwenConfig) !*Self {
+        log.info("Initializing Metal Inference Engine", .{});
+
+        // Get default Metal device
+        const device = objc.createSystemDefaultDevice() orelse {
+            log.err("Failed to create Metal device", .{});
+            return error.MetalDeviceNotFound;
+        };
+
+        const device_name = objc.deviceGetName(device);
+        log.info("Metal device: {s}", .{device_name});
+
+        // Create command queue
+        const queue = objc.deviceNewCommandQueue(device) orelse {
+            log.err("Failed to create command queue", .{});
+            return error.CommandQueueFailed;
+        };
+
+        var self = try allocator.create(Self);
+        self.* = Self{
+            .allocator = allocator,
+            .device = device,
+            .command_queue = queue,
+            .library = null,
+            .config = config,
+        };
+
+        // Compile shaders
+        try self.compileKernels();
+
+        // Allocate persistent buffers
+        try self.allocateBuffers();
+
+        log.info("Metal Inference Engine initialized", .{});
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Release buffers
+        if (self.kv_cache_k) |buf| objc.release(buf.handle);
+        if (self.kv_cache_v) |buf| objc.release(buf.handle);
+        if (self.hidden_state) |buf| objc.release(buf.handle);
+        if (self.intermediate) |buf| objc.release(buf.handle);
+
+        // Release pipelines
+        if (self.rmsnorm_pipeline) |p| objc.release(p);
+        if (self.rope_pipeline) |p| objc.release(p);
+        if (self.swiglu_pipeline) |p| objc.release(p);
+        if (self.matmul_pipeline) |p| objc.release(p);
+        if (self.gqa_pipeline) |p| objc.release(p);
+        if (self.residual_pipeline) |p| objc.release(p);
+
+        // Release dequant pipelines
+        if (self.dequant_q8_pipeline) |p| objc.release(p);
+        if (self.dequant_q8_x4_pipeline) |p| objc.release(p);
+        if (self.dequant_library) |lib| objc.release(lib);
+
+        if (self.library) |lib| objc.release(lib);
+        objc.release(self.command_queue);
+        objc.release(self.device);
+
+        self.allocator.destroy(self);
+    }
+
+    /// Compile Qwen2.5 kernels
+    fn compileKernels(self: *Self) !void {
+        log.info("Compiling Qwen2.5 Metal kernels...", .{});
+
+        // Use createNSStringLong for large shader source (>4KB)
+        const ns_source = objc.createNSStringLong(qwen_kernels_source) orelse {
+            return error.StringCreationFailed;
+        };
+        defer objc.release(ns_source);
+
+        var err: ?objc.NSError = null;
+        const library = objc.deviceNewLibraryWithSource(self.device, ns_source, null, &err);
+
+        if (library) |lib| {
+            self.library = lib;
+            log.info("Qwen kernels compiled successfully", .{});
+        } else {
+            if (err) |e| {
+                const desc = objc.errorGetDescription(e);
+                log.err("Shader compilation failed: {s}", .{desc});
+            }
+            return error.ShaderCompilationFailed;
+        }
+
+        // Create pipeline states
+        self.rmsnorm_pipeline = try self.createPipeline("rmsnorm_bf16");
+        self.rope_pipeline = try self.createPipeline("rope_bf16");
+        self.swiglu_pipeline = try self.createPipeline("swiglu_bf16");
+        self.gqa_pipeline = try self.createPipeline("gqa_attention_bf16");
+        self.residual_pipeline = try self.createPipeline("residual_add_bf16");
+
+        log.info("Qwen pipelines created", .{});
+
+        // Compile dequantization kernels
+        try self.compileDequantKernels();
+    }
+
+    fn createPipeline(self: *Self, name: []const u8) !objc.MTLComputePipelineState {
+        const ns_name = objc.createNSString(name) orelse {
+            return error.StringCreationFailed;
+        };
+        defer objc.release(ns_name);
+
+        const function = objc.libraryNewFunction(self.library.?, ns_name) orelse {
+            log.err("Kernel '{s}' not found", .{name});
+            return error.KernelNotFound;
+        };
+        defer objc.release(function);
+
+        var err: ?objc.NSError = null;
+        const pipeline = objc.deviceNewComputePipelineState(self.device, function, &err) orelse {
+            if (err) |e| {
+                const desc = objc.errorGetDescription(e);
+                log.err("Pipeline creation failed: {s}", .{desc});
+            }
+            return error.PipelineCreationFailed;
+        };
+
+        return pipeline;
+    }
+
+    fn createPipelineFromLibrary(self: *Self, lib: objc.MTLLibrary, name: []const u8) !objc.MTLComputePipelineState {
+        const ns_name = objc.createNSString(name) orelse {
+            return error.StringCreationFailed;
+        };
+        defer objc.release(ns_name);
+
+        const function = objc.libraryNewFunction(lib, ns_name) orelse {
+            log.err("Kernel '{s}' not found in dequant library", .{name});
+            return error.KernelNotFound;
+        };
+        defer objc.release(function);
+
+        var err: ?objc.NSError = null;
+        const pipeline = objc.deviceNewComputePipelineState(self.device, function, &err) orelse {
+            if (err) |e| {
+                const desc = objc.errorGetDescription(e);
+                log.err("Pipeline creation failed: {s}", .{desc});
+            }
+            return error.PipelineCreationFailed;
+        };
+
+        return pipeline;
+    }
+
+    /// Compile dequantization kernels
+    fn compileDequantKernels(self: *Self) !void {
+        log.info("Compiling GPU dequantization kernels...", .{});
+
+        const ns_source = objc.createNSStringLong(dequant_kernels_source) orelse {
+            return error.StringCreationFailed;
+        };
+        defer objc.release(ns_source);
+
+        var err: ?objc.NSError = null;
+        const library = objc.deviceNewLibraryWithSource(self.device, ns_source, null, &err);
+
+        if (library) |lib| {
+            self.dequant_library = lib;
+            log.info("Dequant kernels compiled successfully", .{});
+        } else {
+            if (err) |e| {
+                const desc = objc.errorGetDescription(e);
+                log.err("Dequant shader compilation failed: {s}", .{desc});
+            }
+            return error.ShaderCompilationFailed;
+        }
+
+        // Create pipeline states for dequantization kernels
+        self.dequant_q8_pipeline = try self.createPipelineFromLibrary(self.dequant_library.?, "dequantize_q8_0_bf16");
+        self.dequant_q8_x4_pipeline = try self.createPipelineFromLibrary(self.dequant_library.?, "dequantize_q8_0_bf16_x4");
+
+        log.info("Dequant pipelines created (basic + x4 coarsened)", .{});
+    }
+
+    /// Allocate persistent GPU buffers
+    fn allocateBuffers(self: *Self) !void {
+        const cfg = self.config;
+
+        // KV cache: [n_layers, n_kv_heads, max_seq, head_dim] * 2 bytes
+        const kv_size = @as(u64, cfg.n_layers) * cfg.num_key_value_heads * cfg.max_seq_len * cfg.head_dim * 2;
+        self.kv_cache_k = try self.createBuffer(kv_size);
+        self.kv_cache_v = try self.createBuffer(kv_size);
+        log.info("KV cache allocated: {} MB per cache", .{kv_size / (1024 * 1024)});
+
+        // Hidden state: [batch, seq, hidden] - start with single token
+        const hidden_size = @as(u64, cfg.hidden_size) * 2;
+        self.hidden_state = try self.createBuffer(hidden_size);
+
+        // Intermediate buffer for FFN: [intermediate_size * 2] for gate and up
+        const intermediate_size = @as(u64, cfg.intermediate_size) * 2 * 2;
+        self.intermediate = try self.createBuffer(intermediate_size);
+
+        log.info("Inference buffers allocated", .{});
+    }
+
+    fn createBuffer(self: *Self, size: u64) !InferenceBuffer {
+        // Use shared storage for CPU/GPU access
+        const options: u64 = 0; // MTLResourceStorageModeShared
+        const handle = objc.deviceNewBuffer(self.device, size, options) orelse {
+            return error.BufferCreationFailed;
+        };
+        return InferenceBuffer{ .handle = handle, .size = size };
+    }
+
+    // =========================================================================
+    // GPU Dequantization
+    // =========================================================================
+
+    /// Dequantize Q8_0 data to BF16 on GPU
+    /// This is the key optimization: eliminates CPU dequant bottleneck (~1.6s → ~0.02s per layer)
+    ///
+    /// Parameters:
+    ///   src_q8: Raw Q8_0 data (34 bytes per block: 2 f16 delta + 32 int8)
+    ///   dst_bf16: Output BF16 buffer
+    ///   num_blocks: Number of Q8_0 blocks to process
+    pub fn dispatchDequantQ8(
+        self: *Self,
+        src_q8: []const u8,
+        dst_bf16: []BF16,
+        num_blocks: u32,
+    ) !void {
+        const pipeline = self.dequant_q8_x4_pipeline orelse self.dequant_q8_pipeline orelse {
+            return error.DequantPipelineNotLoaded;
+        };
+
+        // Create command buffer
+        const cmd_buffer = objc.commandQueueCommandBuffer(self.command_queue) orelse {
+            return error.CommandBufferFailed;
+        };
+
+        const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            objc.release(cmd_buffer);
+            return error.EncoderFailed;
+        };
+
+        objc.encoderSetPipelineState(encoder, pipeline);
+
+        // Create Metal buffers with zero-copy (shared memory on Apple Silicon)
+        // MTLResourceStorageModeShared = 0
+        const storage_mode: u64 = 0;
+
+        // Input Q8 buffer - wrap existing memory (zero-copy)
+        const q8_size = @as(u64, num_blocks) * 34;
+        const src_buf = objc.deviceNewBufferNoCopy(
+            self.device,
+            @constCast(@ptrCast(src_q8.ptr)),
+            q8_size,
+            storage_mode,
+        ) orelse return error.BufferCreationFailed;
+        defer objc.release(src_buf);
+
+        // Output BF16 buffer - wrap destination memory directly (zero-copy)
+        const bf16_size = @as(u64, num_blocks) * 32 * 2; // 32 values per block, 2 bytes per BF16
+        const dst_buf = objc.deviceNewBufferNoCopy(
+            self.device,
+            @ptrCast(dst_bf16.ptr),
+            bf16_size,
+            storage_mode,
+        ) orelse return error.BufferCreationFailed;
+        defer objc.release(dst_buf);
+
+        // Set buffers
+        objc.encoderSetBuffer(encoder, src_buf, 0, 0); // src_bytes
+        objc.encoderSetBuffer(encoder, dst_buf, 0, 1); // dst
+        objc.encoderSetBytes(encoder, &num_blocks, @sizeOf(u32), 2); // num_blocks
+
+        // Calculate dispatch size
+        // For x4 kernel: each thread processes 4 blocks
+        const use_x4 = (self.dequant_q8_x4_pipeline != null);
+        const blocks_per_thread: u32 = if (use_x4) 4 else 1;
+        const num_threads = (num_blocks + blocks_per_thread - 1) / blocks_per_thread;
+
+        const threads_per_group: u64 = 256;
+
+        // Use dispatchThreads for non-uniform dispatch (exact thread count)
+        objc.encoderDispatchThreads(
+            encoder,
+            objc.MTLSize{ .width = num_threads, .height = 1, .depth = 1 },
+            objc.MTLSize{ .width = threads_per_group, .height = 1, .depth = 1 },
+        );
+
+        objc.encoderEndEncoding(encoder);
+        objc.commandBufferCommit(cmd_buffer);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+
+        // With NoCopy buffers, GPU writes directly to dst_bf16 memory
+        // No copy needed - data is already in place!
+    }
+
+    /// Dequantize an entire layer's Q8 weights to BF16 on GPU
+    /// This processes all quantized tensors in the layer buffer
+    pub fn dequantizeLayerQ8(
+        self: *Self,
+        q8_buf: []const u8,
+        bf16_buf: []u8,
+        q8_offsets: model.Q8LayerOffsets,
