+        // Dequantize each quantized tensor
+        // Q projection
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.q_proj..][0..q8_offsets.q_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.q_proj)))[0 .. cfg.hidden_size * cfg.hidden_size],
+            @intCast(q8_offsets.q_proj_blocks),
+        );
+
+        // K projection
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.k_proj..][0..q8_offsets.k_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.k_proj)))[0 .. cfg.hidden_size * cfg.kv_dim],
+            @intCast(q8_offsets.k_proj_blocks),
+        );
+
+        // V projection
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.v_proj..][0..q8_offsets.v_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.v_proj)))[0 .. cfg.hidden_size * cfg.kv_dim],
+            @intCast(q8_offsets.v_proj_blocks),
+        );
+
+        // O projection
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.o_proj..][0..q8_offsets.o_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.o_proj)))[0 .. cfg.hidden_size * cfg.hidden_size],
+            @intCast(q8_offsets.o_proj_blocks),
+        );
+
+        // Gate projection (FFN)
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.gate_proj..][0..q8_offsets.gate_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.gate_proj)))[0 .. cfg.hidden_size * cfg.intermediate_size],
+            @intCast(q8_offsets.gate_proj_blocks),
+        );
+
+        // Up projection (FFN)
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.up_proj..][0..q8_offsets.up_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.up_proj)))[0 .. cfg.hidden_size * cfg.intermediate_size],
+            @intCast(q8_offsets.up_proj_blocks),
+        );
+
+        // Down projection (FFN)
+        try self.dispatchDequantQ8(
+            q8_buf[q8_offsets.down_proj..][0..q8_offsets.down_proj_bytes],
+            @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.down_proj)))[0 .. cfg.intermediate_size * cfg.hidden_size],
+            @intCast(q8_offsets.down_proj_blocks),
+        );
+    }
+
+    /// Dequantize layer using ZERO-COPY mmap pointers
+    /// GPU reads directly from mmap'd GGUF file - no CPU memcpy!
+    /// This is the optimal path for Apple Silicon unified memory.
+    pub fn dequantizeLayerZeroCopy(
+        self: *Self,
+        mmap_ptrs: MmapQ8Pointers,
+        bf16_buf: []u8,
+        q8_offsets: model.Q8LayerOffsets,
+        bf16_offsets: LayerOffsets,
+    ) !void {
+        const cfg = self.config;
+
+        // Q projection - read directly from mmap
+        if (mmap_ptrs.q_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.q_proj)))[0 .. cfg.hidden_size * cfg.hidden_size],
+                @intCast(q8_offsets.q_proj_blocks),
+            );
+        }
+
+        // K projection
+        if (mmap_ptrs.k_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.k_proj)))[0 .. cfg.hidden_size * cfg.kv_dim],
+                @intCast(q8_offsets.k_proj_blocks),
+            );
+        }
+
+        // V projection
+        if (mmap_ptrs.v_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.v_proj)))[0 .. cfg.hidden_size * cfg.kv_dim],
+                @intCast(q8_offsets.v_proj_blocks),
+            );
+        }
+
+        // O projection
+        if (mmap_ptrs.o_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.o_proj)))[0 .. cfg.hidden_size * cfg.hidden_size],
+                @intCast(q8_offsets.o_proj_blocks),
+            );
+        }
+
+        // Gate projection (FFN)
+        if (mmap_ptrs.gate_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.gate_proj)))[0 .. cfg.hidden_size * cfg.intermediate_size],
+                @intCast(q8_offsets.gate_proj_blocks),
+            );
+        }
+
+        // Up projection (FFN)
+        if (mmap_ptrs.up_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.up_proj)))[0 .. cfg.hidden_size * cfg.intermediate_size],
+                @intCast(q8_offsets.up_proj_blocks),
+            );
+        }
+
+        // Down projection (FFN)
+        if (mmap_ptrs.down_proj) |q8_data| {
+            try self.dispatchDequantQ8(
+                q8_data,
+                @as([*]BF16, @ptrCast(@alignCast(bf16_buf.ptr + bf16_offsets.down_proj)))[0 .. cfg.intermediate_size * cfg.hidden_size],
+                @intCast(q8_offsets.down_proj_blocks),
+            );
+        }
+    }
+
+    // =========================================================================
+    // Layer Compute Functions
+    // =========================================================================
+
+    /// Dispatch RMSNorm kernel
+    pub fn dispatchRMSNorm(
+        self: *Self,
+        input: [*]const BF16,
+        weight: [*]const BF16,
+        output: [*]BF16,
+        hidden_size: u32,
+        n_tokens: u32,
+    ) !void {
+        const pipeline = self.rmsnorm_pipeline orelse return error.PipelineNotLoaded;
+
+        // Create command buffer
+        const cmd_buffer = objc.commandQueueCommandBuffer(self.command_queue) orelse {
+            return error.CommandBufferFailed;
+        };
+
+        const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            objc.release(cmd_buffer);
+            return error.EncoderFailed;
+        };
+
+        objc.encoderSetPipelineState(encoder, pipeline);
+
+        // Create temporary buffers for input/output
+        // (In production, these would be pre-allocated Metal buffers)
+        const input_size = @as(u64, hidden_size) * n_tokens * 2;
+        const input_buf = objc.deviceNewBufferWithBytes(
+            self.device,
+            @ptrCast(input),
+            input_size,
+            0,
+        ) orelse return error.BufferCreationFailed;
+        defer objc.release(input_buf);
+
+        const weight_buf = objc.deviceNewBufferWithBytes(
+            self.device,
+            @ptrCast(weight),
+            @as(u64, hidden_size) * 2,
+            0,
+        ) orelse return error.BufferCreationFailed;
+        defer objc.release(weight_buf);
+
+        const output_buf = objc.deviceNewBuffer(self.device, input_size, 0) orelse {
+            return error.BufferCreationFailed;
+        };
+        defer objc.release(output_buf);
+
+        // Set buffers
+        objc.encoderSetBuffer(encoder, input_buf, 0, 0);
+        objc.encoderSetBuffer(encoder, weight_buf, 0, 1);
+        objc.encoderSetBuffer(encoder, output_buf, 0, 2);
+
+        // Set constants
+        const eps: f32 = self.config.rms_norm_eps;
+        objc.encoderSetBytes(encoder, &eps, @sizeOf(f32), 3);
+        objc.encoderSetBytes(encoder, &hidden_size, @sizeOf(u32), 4);
+
+        // Dispatch
+        const threads_per_group: u64 = 256;
+        const num_groups = (hidden_size + threads_per_group - 1) / threads_per_group;
+        objc.encoderDispatchThreadgroups(
+            encoder,
+            objc.MTLSize{ .width = num_groups, .height = n_tokens, .depth = 1 },
+            objc.MTLSize{ .width = threads_per_group, .height = 1, .depth = 1 },
+        );
+
+        objc.encoderEndEncoding(encoder);
+        objc.commandBufferCommit(cmd_buffer);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+
+        // Copy result back
+        const result_ptr = objc.bufferContents(output_buf);
+        @memcpy(@as([*]u8, @ptrCast(output))[0..input_size], result_ptr[0..input_size]);
+    }
+
+    /// Compute a single transformer layer
+    /// This dispatches kernels synchronously to allow GPU yielding
+    pub fn computeLayer(
+        self: *Self,
+        layer_weights: []const u8,
+        offsets: LayerOffsets,
+        hidden_state: []BF16,
+        position: u32,
+        layer_idx: u32,
+    ) !void {
+        _ = layer_idx;
+        _ = position;
+        _ = hidden_state;
+        _ = offsets;
+        _ = layer_weights;
+
+        // TODO: Full implementation would:
+        // 1. RMSNorm on hidden state
+        // 2. QKV MatMul + bias
+        // 3. RoPE on Q, K
