+//! Qwen2.5 Model Configuration and Memory Layout
+//!
+//! Defines the structure of Qwen2.5-32B for streaming inference.
+//! All weights for a single layer are packed into a contiguous buffer
+//! that can be filled by the CPU and consumed by the GPU.
+
+const std = @import("std");
+
+/// Helper: calculate Q8_0 size for a given number of elements
+/// Q8_0 block: 34 bytes for 32 values
+pub fn q8BlockBytes(num_elements: usize) usize {
+    const num_blocks = (num_elements + 31) / 32; // ceil division
+    return num_blocks * 34;
+}
+
+/// Qwen2.5-32B Model Configuration
+/// These values are extracted from the GGUF metadata
+pub const QwenConfig = struct {
+    // Architecture
+    n_layers: u32 = 64,
+    hidden_size: u32 = 5120,
+    intermediate_size: u32 = 27648,
+    num_attention_heads: u32 = 40,
+    num_key_value_heads: u32 = 8,
+    head_dim: u32 = 128, // hidden_size / num_attention_heads
+    vocab_size: u32 = 152064,
+
+    // Normalization
+    rms_norm_eps: f32 = 1e-6,
+
+    // RoPE
+    rope_freq_base: f32 = 1000000.0, // Extended context
+
+    // Context
+    max_seq_len: u32 = 4096, // Can be extended to 131072
+
+    // Derived values
+    kv_dim: u32 = 1024, // num_key_value_heads * head_dim = 8 * 128
+
+    /// Calculate total BF16 size for one layer's weights (bytes)
+    pub fn layerSizeBytes(self: QwenConfig) usize {
+        var size: usize = 0;
+
+        // 1. Input LayerNorm (RMSNorm) - [hidden_size]
+        size += self.hidden_size * 2;
+
+        // 2. Attention weights
+        // Q projection: [hidden_size, hidden_size]
+        size += @as(usize, self.hidden_size) * self.hidden_size * 2;
+        // K projection: [hidden_size, kv_dim]
+        size += @as(usize, self.hidden_size) * self.kv_dim * 2;
+        // V projection: [hidden_size, kv_dim]
+        size += @as(usize, self.hidden_size) * self.kv_dim * 2;
+        // O projection: [hidden_size, hidden_size]
+        size += @as(usize, self.hidden_size) * self.hidden_size * 2;
+
+        // 3. Attention biases (Qwen2.5 has QKV biases)
+        // Q bias: [hidden_size]
+        size += self.hidden_size * 2;
+        // K bias: [kv_dim]
+        size += self.kv_dim * 2;
+        // V bias: [kv_dim]
+        size += self.kv_dim * 2;
+
+        // 4. Post-attention LayerNorm (RMSNorm) - [hidden_size]
+        size += self.hidden_size * 2;
+
+        // 5. FFN weights (SwiGLU has 3 projections)
+        // Gate projection: [hidden_size, intermediate_size]
+        size += @as(usize, self.hidden_size) * self.intermediate_size * 2;
+        // Up projection: [hidden_size, intermediate_size]
+        size += @as(usize, self.hidden_size) * self.intermediate_size * 2;
+        // Down projection: [intermediate_size, hidden_size]
+        size += @as(usize, self.intermediate_size) * self.hidden_size * 2;
+
+        // Align to 4096 bytes for Metal buffer alignment
+        return std.mem.alignForward(usize, size, 4096);
+    }
+
+    /// Calculate Q8_0 size for one layer's weights (bytes)
+    /// Q8_0: 34 bytes per block (2 for f16 delta + 32 for int8 quants) → 32 values
+    /// This is ~53% of BF16 size
+    pub fn layerQ8SizeBytes(self: QwenConfig) usize {
+        var size: usize = 0;
+
+        // 1. Input LayerNorm - typically F32/F16, not quantized
+        // We'll store as BF16 (2 bytes per element)
+        size += self.hidden_size * 2;
+
+        // 2. Attention weights (Q8_0 quantized)
+        size += q8BlockBytes(@as(usize, self.hidden_size) * self.hidden_size); // Q
+        size += q8BlockBytes(@as(usize, self.hidden_size) * self.kv_dim); // K
+        size += q8BlockBytes(@as(usize, self.hidden_size) * self.kv_dim); // V
+        size += q8BlockBytes(@as(usize, self.hidden_size) * self.hidden_size); // O
+
+        // 3. Attention biases - typically F32/F16, not quantized
+        size += self.hidden_size * 2; // Q bias
+        size += self.kv_dim * 2; // K bias
+        size += self.kv_dim * 2; // V bias
+
+        // 4. Post-attention LayerNorm - not quantized
+        size += self.hidden_size * 2;
+
+        // 5. FFN weights (Q8_0 quantized)
+        size += q8BlockBytes(@as(usize, self.hidden_size) * self.intermediate_size); // gate
+        size += q8BlockBytes(@as(usize, self.hidden_size) * self.intermediate_size); // up
+        size += q8BlockBytes(@as(usize, self.intermediate_size) * self.hidden_size); // down
+
+        // Align to 4096 bytes for Metal buffer alignment
+        return std.mem.alignForward(usize, size, 4096);
+    }
+
+    /// Calculate KV cache size for all layers (bytes)
+    pub fn kvCacheSizeBytes(self: QwenConfig) usize {
+        // K cache: [n_layers, n_kv_heads, max_seq_len, head_dim]
+        // V cache: same
+        // Total = 2 * n_layers * n_kv_heads * max_seq_len * head_dim * 2 (BF16)
+        return 2 * @as(usize, self.n_layers) *
+            self.num_key_value_heads *
+            self.max_seq_len *
+            self.head_dim * 2;
+    }
+
+    /// Print config summary
+    pub fn print(self: QwenConfig) void {
+        std.debug.print("\nQwen2.5-32B Configuration:\n", .{});
+        std.debug.print("  Layers: {}\n", .{self.n_layers});
+        std.debug.print("  Hidden: {}\n", .{self.hidden_size});
+        std.debug.print("  FFN: {}\n", .{self.intermediate_size});
+        std.debug.print("  Q Heads: {}, KV Heads: {}\n", .{ self.num_attention_heads, self.num_key_value_heads });
+        std.debug.print("  Head Dim: {}\n", .{self.head_dim});
+        std.debug.print("  Layer Size: {} MB\n", .{self.layerSizeBytes() / (1024 * 1024)});
+        std.debug.print("  KV Cache: {} MB (for {} tokens)\n", .{
+            self.kvCacheSizeBytes() / (1024 * 1024),
+            self.max_seq_len,
+        });
+    }
+};
+
+/// Tensor offsets within a layer buffer
+/// These offsets tell us where each weight tensor starts in the packed buffer
+pub const LayerOffsets = struct {
+    // Offsets in bytes from buffer start
+    input_layernorm: usize,
+
+    q_proj: usize,
+    k_proj: usize,
+    v_proj: usize,
+    o_proj: usize,
+
+    q_bias: usize,
+    k_bias: usize,
+    v_bias: usize,
+
+    post_attn_layernorm: usize,
+
+    gate_proj: usize,
+    up_proj: usize,
+    down_proj: usize,
+
+    // Sizes for convenience
+    q_proj_size: usize,
+    k_proj_size: usize,
+    v_proj_size: usize,
+    o_proj_size: usize,
+    gate_proj_size: usize,
+    up_proj_size: usize,
+    down_proj_size: usize,
+
+    /// Calculate offsets for a given config
+    pub fn init(config: QwenConfig) LayerOffsets {
+        var offset: usize = 0;
+
+        const input_layernorm = offset;
+        offset += config.hidden_size * 2;
+
+        const q_proj = offset;
+        const q_proj_size = @as(usize, config.hidden_size) * config.hidden_size * 2;
+        offset += q_proj_size;
+
+        const k_proj = offset;
+        const k_proj_size = @as(usize, config.hidden_size) * config.kv_dim * 2;
+        offset += k_proj_size;
+
+        const v_proj = offset;
+        const v_proj_size = @as(usize, config.hidden_size) * config.kv_dim * 2;
+        offset += v_proj_size;
+
+        const o_proj = offset;
+        const o_proj_size = @as(usize, config.hidden_size) * config.hidden_size * 2;
+        offset += o_proj_size;
+
+        const q_bias = offset;
+        offset += config.hidden_size * 2;
+
+        const k_bias = offset;
+        offset += config.kv_dim * 2;
+
+        const v_bias = offset;
+        offset += config.kv_dim * 2;
+
+        const post_attn_layernorm = offset;
+        offset += config.hidden_size * 2;
+
+        const gate_proj = offset;
+        const gate_proj_size = @as(usize, config.hidden_size) * config.intermediate_size * 2;
+        offset += gate_proj_size;
+
+        const up_proj = offset;
+        const up_proj_size = @as(usize, config.hidden_size) * config.intermediate_size * 2;
+        offset += up_proj_size;
+
+        const down_proj = offset;
+        const down_proj_size = @as(usize, config.intermediate_size) * config.hidden_size * 2;
+        _ = offset + down_proj_size; // Total size verification
+
+        return LayerOffsets{
+            .input_layernorm = input_layernorm,
+            .q_proj = q_proj,
+            .k_proj = k_proj,
+            .v_proj = v_proj,
+            .o_proj = o_proj,
+            .q_bias = q_bias,
+            .k_bias = k_bias,
+            .v_bias = v_bias,
+            .post_attn_layernorm = post_attn_layernorm,
+            .gate_proj = gate_proj,
+            .up_proj = up_proj,
+            .down_proj = down_proj,
+            .q_proj_size = q_proj_size,
+            .k_proj_size = k_proj_size,
+            .v_proj_size = v_proj_size,
+            .o_proj_size = o_proj_size,
+            .gate_proj_size = gate_proj_size,
+            .up_proj_size = up_proj_size,
+            .down_proj_size = down_proj_size,
+        };
+    }
+};
+
+/// Q8 tensor offsets within a raw Q8 layer buffer
+/// Similar to LayerOffsets but for the compressed Q8 data before GPU dequantization
+pub const Q8LayerOffsets = struct {
+    // Offsets in bytes from Q8 buffer start
+    // Non-quantized tensors (layernorms, biases) stored as BF16 at the start
+    input_layernorm: usize, // BF16
+    q_bias: usize, // BF16
+    k_bias: usize, // BF16
+    v_bias: usize, // BF16
+    post_attn_layernorm: usize, // BF16
+
+    // Quantized tensors (Q8_0 format)
+    q_proj: usize,
+    k_proj: usize,
+    v_proj: usize,
+    o_proj: usize,
+    gate_proj: usize,
+    up_proj: usize,
+    down_proj: usize,
+
+    // Sizes in bytes
+    q_proj_bytes: usize,
+    k_proj_bytes: usize,
+    v_proj_bytes: usize,
+    o_proj_bytes: usize,
+    gate_proj_bytes: usize,
+    up_proj_bytes: usize,
+    down_proj_bytes: usize,
+
+    // Block counts for GPU dispatch
+    q_proj_blocks: usize,
+    k_proj_blocks: usize,
+    v_proj_blocks: usize,
+    o_proj_blocks: usize,
+    gate_proj_blocks: usize,
+    up_proj_blocks: usize,
+    down_proj_blocks: usize,
+
+    /// Calculate Q8 offsets for a given config
+    pub fn init(config: QwenConfig) Q8LayerOffsets {
+        var offset: usize = 0;
+
+        // Non-quantized tensors first (BF16)
+        const input_layernorm = offset;
+        offset += config.hidden_size * 2;
+
+        const q_bias = offset;
+        offset += config.hidden_size * 2;
+
+        const k_bias = offset;
+        offset += config.kv_dim * 2;
+
+        const v_bias = offset;
+        offset += config.kv_dim * 2;
+
+        const post_attn_layernorm = offset;
+        offset += config.hidden_size * 2;
+
+        // Align to 64 bytes for Q8 blocks (helps GPU coalescing)
+        offset = std.mem.alignForward(usize, offset, 64);
+
+        // Q8_0 quantized tensors
+        const q_elements = @as(usize, config.hidden_size) * config.hidden_size;
+        const q_proj = offset;
+        const q_proj_bytes = q8BlockBytes(q_elements);
+        const q_proj_blocks = (q_elements + 31) / 32;
+        offset += q_proj_bytes;
+
+        const k_elements = @as(usize, config.hidden_size) * config.kv_dim;
+        const k_proj = offset;
+        const k_proj_bytes = q8BlockBytes(k_elements);
+        const k_proj_blocks = (k_elements + 31) / 32;
+        offset += k_proj_bytes;
+
+        const v_elements = @as(usize, config.hidden_size) * config.kv_dim;
+        const v_proj = offset;
+        const v_proj_bytes = q8BlockBytes(v_elements);
+        const v_proj_blocks = (v_elements + 31) / 32;
+        offset += v_proj_bytes;
+
+        const o_elements = @as(usize, config.hidden_size) * config.hidden_size;
+        const o_proj = offset;
+        const o_proj_bytes = q8BlockBytes(o_elements);
+        const o_proj_blocks = (o_elements + 31) / 32;
+        offset += o_proj_bytes;
+
+        const gate_elements = @as(usize, config.hidden_size) * config.intermediate_size;
+        const gate_proj = offset;
+        const gate_proj_bytes = q8BlockBytes(gate_elements);
+        const gate_proj_blocks = (gate_elements + 31) / 32;
+        offset += gate_proj_bytes;
+
+        const up_elements = @as(usize, config.hidden_size) * config.intermediate_size;
+        const up_proj = offset;
+        const up_proj_bytes = q8BlockBytes(up_elements);
+        const up_proj_blocks = (up_elements + 31) / 32;
+        offset += up_proj_bytes;
+
+        const down_elements = @as(usize, config.intermediate_size) * config.hidden_size;
+        const down_proj = offset;
+        const down_proj_bytes = q8BlockBytes(down_elements);
+        const down_proj_blocks = (down_elements + 31) / 32;
+        _ = offset + down_proj_bytes;
+
+        return Q8LayerOffsets{
+            .input_layernorm = input_layernorm,
+            .q_bias = q_bias,
+            .k_bias = k_bias,
+            .v_bias = v_bias,
+            .post_attn_layernorm = post_attn_layernorm,
+            .q_proj = q_proj,
+            .k_proj = k_proj,
+            .v_proj = v_proj,
+            .o_proj = o_proj,
+            .gate_proj = gate_proj,
+            .up_proj = up_proj,
+            .down_proj = down_proj,
+            .q_proj_bytes = q_proj_bytes,
+            .k_proj_bytes = k_proj_bytes,
+            .v_proj_bytes = v_proj_bytes,
+            .o_proj_bytes = o_proj_bytes,
+            .gate_proj_bytes = gate_proj_bytes,
+            .up_proj_bytes = up_proj_bytes,
+            .down_proj_bytes = down_proj_bytes,
+            .q_proj_blocks = q_proj_blocks,
