+//! Streaming Qwen2.5 Inference Engine
+//!
+//! Heterogeneous pipelining for running Qwen2.5-32B on limited RAM.
+//! Uses CPU for JIT decompression while GPU computes in parallel.
+//!
+//! Architecture:
+//! ┌─────────────────────────────────────────────────────────────────┐
+//! │  CPU Thread (Loader)          GPU Thread (Compute)              │
+//! │  ┌──────────────────┐        ┌──────────────────┐              │
+//! │  │ Load Layer N+1   │        │ Compute Layer N  │              │
+//! │  │ Q8_0 → BF16      │        │ RMSNorm, Attn,   │              │
+//! │  │ → Buffer B       │        │ FFN from Buf A   │              │
+//! │  └────────┬─────────┘        └────────┬─────────┘              │
+//! │           │                           │                         │
+//! │           ▼                           ▼                         │
+//! │  ┌──────────────────┐        ┌──────────────────┐              │
+//! │  │ Load Layer N+2   │        │ Compute Layer N+1│              │
+//! │  │ → Buffer A       │        │ from Buffer B    │              │
+//! │  └──────────────────┘        └──────────────────┘              │
+//! └─────────────────────────────────────────────────────────────────┘
+
+const std = @import("std");
+const gguf = @import("gguf_loader.zig");
+const model = @import("qwen_model.zig");
+const QwenConfig = model.QwenConfig;
+const LayerOffsets = model.LayerOffsets;
+const Q8LayerOffsets = model.Q8LayerOffsets;
+const GGUFNames = model.GGUFNames;
+const BF16 = gguf.BF16;
+
+const log = std.log.scoped(.streaming_qwen);
+
+// =============================================================================
+// Ping-Pong Buffer
+// =============================================================================
+
+/// One of the two alternating buffers for layer weights
+/// Supports two modes:
+/// 1. CPU Dequant: CPU writes BF16 to `data`, GPU reads directly
+/// 2. GPU Dequant (Zero-Copy): CPU stores mmap pointers in `mmap_q8_ptrs`, GPU reads directly from mmap
+pub const PingPongBuffer = struct {
+    /// BF16 buffer pointer (shared memory - GPU readable)
+    /// This is the final destination for dequantized weights
+    data: []u8,
+
+    /// Raw Q8 staging buffer (shared memory - CPU writable, GPU readable)
+    /// Contains compressed Q8_0 data before GPU dequantization
+    /// Smaller than `data` (~53% of BF16 size)
+    /// NOTE: With zero-copy mode, this is unused - we read directly from mmap
+    raw_q8_data: ?[]u8 = null,
+
+    /// Zero-copy mmap pointers to Q8 tensors in GGUF file
+    /// GPU reads directly from these (unified memory - no copy needed!)
+    mmap_q8_ptrs: MmapQ8Pointers = .{},
+
+    /// Which layer is currently loaded
+    layer_idx: u32 = 0,
+
+    /// Synchronization: CPU signals when data is ready
+    ready_for_gpu: std.Thread.Semaphore = .{},
+
+    /// Synchronization: GPU signals when done computing
+    ready_for_cpu: std.Thread.Semaphore = .{},
+
+    /// Get typed slice at offset from BF16 buffer
+    pub fn getSlice(self: *PingPongBuffer, comptime T: type, offset: usize, count: usize) []T {
+        const ptr: [*]T = @ptrCast(@alignCast(self.data.ptr + offset));
+        return ptr[0..count];
+    }
+
+    /// Get BF16 slice at offset from BF16 buffer
+    pub fn getBF16Slice(self: *PingPongBuffer, offset: usize, count: usize) []BF16 {
+        return self.getSlice(BF16, offset, count);
+    }
+
+    /// Get raw bytes slice from Q8 staging buffer
+    pub fn getRawQ8Slice(self: *PingPongBuffer, offset: usize, size: usize) ?[]u8 {
+        const q8_data = self.raw_q8_data orelse return null;
+        if (offset + size > q8_data.len) return null;
+        return q8_data[offset..][0..size];
+    }
+};
+
+/// Zero-copy pointers to Q8 tensors in mmap'd GGUF file
+/// Each pointer points directly into unified memory (shared CPU/GPU)
+pub const MmapQ8Pointers = struct {
+    q_proj: ?[]const u8 = null,
+    k_proj: ?[]const u8 = null,
+    v_proj: ?[]const u8 = null,
+    o_proj: ?[]const u8 = null,
+    gate_proj: ?[]const u8 = null,
+    up_proj: ?[]const u8 = null,
+    down_proj: ?[]const u8 = null,
+};
+
+// =============================================================================
+// Streaming Engine
+// =============================================================================
+
+pub const StreamingEngine = struct {
+    allocator: std.mem.Allocator,
+
+    // GGUF loader for weight access
+    loader: *gguf.GGUFLoader,
+
+    // Model configuration
+    config: QwenConfig,
+    offsets: LayerOffsets,
+    q8_offsets: Q8LayerOffsets,
+
+    // Ping-pong buffers for layer weights
+    buf_a: PingPongBuffer,
+    buf_b: PingPongBuffer,
+
+    // GPU dequantization mode
+    use_gpu_dequant: bool = false,
+
+    // Loader thread state
+    loader_thread: ?std.Thread = null,
+    running: std.atomic.Value(bool) = std.atomic.Value(bool).init(false),
+
+    // Current generation state
+    current_position: u32 = 0,
+
+    // Tiered Memory Architecture
+    resident_layers: u32 = 0, // Number of layers cached in RAM
+    resident_bytes: usize = 0, // Bytes locked/warmed in RAM
+
+    // Statistics
+    load_time_ns: u64 = 0,
+    compute_time_ns: u64 = 0,
+    layers_loaded: u64 = 0,
+    resident_load_time_ns: u64 = 0, // Time spent loading resident (cached) layers
+    streaming_load_time_ns: u64 = 0, // Time spent loading streaming (cold) layers
+
+    const Self = @This();
+
+    /// Initialize the streaming engine
+    /// Set use_gpu_dequant=true to use GPU for Q8→BF16 conversion (faster)
+    pub fn init(allocator: std.mem.Allocator, loader: *gguf.GGUFLoader) !*Self {
+        return initWithMode(allocator, loader, false);
+    }
+
+    /// Initialize with explicit GPU dequant mode
+    pub fn initWithMode(allocator: std.mem.Allocator, loader: *gguf.GGUFLoader, use_gpu_dequant: bool) !*Self {
+        log.info("Initializing Streaming Qwen2.5 Engine (GPU dequant: {})", .{use_gpu_dequant});
+
+        // Create config from GGUF metadata
+        var config = QwenConfig{};
+        if (loader.metadata.n_layers > 0) config.n_layers = loader.metadata.n_layers;
+        if (loader.metadata.hidden_size > 0) config.hidden_size = loader.metadata.hidden_size;
+        if (loader.metadata.intermediate_size > 0) config.intermediate_size = loader.metadata.intermediate_size;
+        if (loader.metadata.n_heads > 0) config.num_attention_heads = loader.metadata.n_heads;
+        if (loader.metadata.n_kv_heads > 0) config.num_key_value_heads = loader.metadata.n_kv_heads;
+        if (loader.metadata.rope_freq_base > 0) config.rope_freq_base = loader.metadata.rope_freq_base;
+
+        // Calculate derived values
+        config.head_dim = config.hidden_size / config.num_attention_heads;
+        config.kv_dim = config.num_key_value_heads * config.head_dim;
+
+        config.print();
+
+        const offsets = LayerOffsets.init(config);
+        const q8_offsets = Q8LayerOffsets.init(config);
+        const layer_size = config.layerSizeBytes();
+        const q8_layer_size = q8_offsets.totalSize();
+
+        log.info("Layer buffer size: {} MB (BF16)", .{layer_size / (1024 * 1024)});
+        log.info("Q8 staging size: {} MB (Q8_0, {d:.1}% of BF16)", .{
+            q8_layer_size / (1024 * 1024),
+            @as(f64, @floatFromInt(q8_layer_size)) / @as(f64, @floatFromInt(layer_size)) * 100.0,
+        });
+
+        // Allocate ping-pong buffers (page alignment for Metal)
+        const buf_a_data = try allocator.alignedAlloc(u8, comptime std.mem.Alignment.fromByteUnits(4096), layer_size);
+        const buf_b_data = try allocator.alignedAlloc(u8, comptime std.mem.Alignment.fromByteUnits(4096), layer_size);
+
+        // Allocate Q8 staging buffers if GPU dequant is enabled
+        var buf_a_q8: ?[]u8 = null;
+        var buf_b_q8: ?[]u8 = null;
+        if (use_gpu_dequant) {
+            buf_a_q8 = try allocator.alignedAlloc(u8, comptime std.mem.Alignment.fromByteUnits(4096), q8_layer_size);
+            buf_b_q8 = try allocator.alignedAlloc(u8, comptime std.mem.Alignment.fromByteUnits(4096), q8_layer_size);
+            log.info("Allocated Q8 staging buffers: {} MB x 2", .{q8_layer_size / (1024 * 1024)});
+        }
+
+        var self = try allocator.create(Self);
+        self.* = Self{
+            .allocator = allocator,
+            .loader = loader,
+            .config = config,
+            .offsets = offsets,
+            .q8_offsets = q8_offsets,
+            .buf_a = PingPongBuffer{ .data = buf_a_data, .raw_q8_data = buf_a_q8 },
+            .buf_b = PingPongBuffer{ .data = buf_b_data, .raw_q8_data = buf_b_q8 },
+            .use_gpu_dequant = use_gpu_dequant,
+        };
+
+        // Initialize semaphores: buffers start as available for CPU
+        self.buf_a.ready_for_cpu.post();
+        self.buf_b.ready_for_cpu.post();
+
+        log.info("Streaming engine initialized", .{});
+        return self;
+    }
+
+    /// Warm the first N layers into RAM for faster access
+    /// This is the key optimization for tiered memory architecture
+    /// Call this after init() but before start()
+    pub fn warmResidentLayers(self: *Self, n_layers: u32) !void {
+        // Safety check: don't try to cache more layers than exist
+        const layers_to_cache = @min(n_layers, self.config.n_layers);
+
+        log.info("Warming {} resident layers into RAM...", .{layers_to_cache});
+
+        // Calculate bytes needed for N layers
+        const bytes_needed = self.loader.getResidentLayerBytes(layers_to_cache);
+        log.info("Estimated bytes for {} layers: {} MB", .{ layers_to_cache, bytes_needed / (1024 * 1024) });
+
+        // Try to lock memory, fall back to warming if mlock fails
+        const start_time = std.time.nanoTimestamp();
+        self.resident_bytes = try self.loader.lockResidentMemory(bytes_needed);
+        const elapsed: u64 = @intCast(std.time.nanoTimestamp() - start_time);
+
+        self.resident_layers = layers_to_cache;
+
+        log.info("Resident cache ready: {} layers ({} MB) in {} ms", .{
+            self.resident_layers,
+            self.resident_bytes / (1024 * 1024),
+            elapsed / 1_000_000,
+        });
+    }
+
+    /// Check if a layer is in the resident cache (hot) or needs streaming (cold)
+    pub fn isResidentLayer(self: *Self, layer_idx: u32) bool {
+        return layer_idx < self.resident_layers;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.stop();
+        self.allocator.free(self.buf_a.data);
+        self.allocator.free(self.buf_b.data);
+        if (self.buf_a.raw_q8_data) |q8| self.allocator.free(q8);
+        if (self.buf_b.raw_q8_data) |q8| self.allocator.free(q8);
+        self.allocator.destroy(self);
+    }
+
+    /// Start the background loader thread
+    pub fn start(self: *Self) !void {
+        if (self.running.load(.acquire)) return;
+
+        log.info("Starting loader thread", .{});
+        self.running.store(true, .release);
+        self.loader_thread = try std.Thread.spawn(.{}, loaderThreadFn, .{self});
+    }
+
+    /// Stop the background loader thread
+    pub fn stop(self: *Self) void {
+        if (!self.running.load(.acquire)) return;
+
+        log.info("Stopping loader thread", .{});
+        self.running.store(false, .release);
+
+        // Wake up the loader thread if it's waiting
+        self.buf_a.ready_for_cpu.post();
+        self.buf_b.ready_for_cpu.post();
+
+        if (self.loader_thread) |thread| {
+            thread.join();
+        }
+        self.loader_thread = null;
+    }
+
+    // =========================================================================
+    // Loader Thread
+    // =========================================================================
+
+    fn loaderThreadFn(self: *Self) void {
+        log.info("Loader thread started (resident={}, streaming={})", .{
+            self.resident_layers,
+            self.config.n_layers - self.resident_layers,
+        });
+
+        var layer: u32 = 0;
+        var use_buf_a = true;
+
+        while (self.running.load(.acquire)) {
+            const buf = if (use_buf_a) &self.buf_a else &self.buf_b;
+
+            // Wait for buffer to be available
+            buf.ready_for_cpu.wait();
+
+            if (!self.running.load(.acquire)) break;
+
+            // Determine if this is a resident (hot) or streaming (cold) layer
+            const is_resident = self.isResidentLayer(layer);
+
+            // Load layer weights (CPU dequant or raw Q8 memcpy)
+            const load_start = std.time.nanoTimestamp();
+            if (self.use_gpu_dequant) {
+                self.loadLayerWeightsQ8(layer, buf);
+            } else {
+                self.loadLayerWeights(layer, buf);
+            }
+            const elapsed: u64 = @intCast(std.time.nanoTimestamp() - load_start);
+
+            buf.layer_idx = layer;
+            self.load_time_ns += elapsed;
+            self.layers_loaded += 1;
+
+            // Track resident vs streaming load times separately
+            if (is_resident) {
+                self.resident_load_time_ns += elapsed;
+            } else {
+                self.streaming_load_time_ns += elapsed;
+            }
+
+            const layer_type: []const u8 = if (is_resident) "resident" else "streaming";
+            log.debug("Loaded layer {} ({s}) in {} ms", .{ layer, layer_type, elapsed / 1_000_000 });
+
+            // Signal GPU that data is ready
+            buf.ready_for_gpu.post();
+
+            // Move to next layer (wrap around for continuous generation)
+            layer = (layer + 1) % self.config.n_layers;
+            use_buf_a = !use_buf_a;
+        }
+
+        log.info("Loader thread stopped", .{});
+    }
+
+    /// Load all weights for a single layer from GGUF into the buffer
+    fn loadLayerWeights(self: *Self, layer: u32, buf: *PingPongBuffer) void {
+        var name_buf: [64]u8 = undefined;
+        const cfg = self.config;
+        const off = self.offsets;
+
+        // Helper to load a tensor
+        const loadTensor = struct {
+            fn load(
+                loader: *gguf.GGUFLoader,
+                name: []const u8,
+                dest: []BF16,
+            ) void {
+                loader.dequantizeToBF16(name, dest) catch |err| {
+                    log.warn("Failed to load {s}: {}", .{ name, err });
+                };
+            }
+        }.load;
+
+        // 1. Input LayerNorm
+        const ln1_name = GGUFNames.formatName(&name_buf, GGUFNames.input_layernorm, layer);
+        loadTensor(self.loader, ln1_name, buf.getBF16Slice(off.input_layernorm, cfg.hidden_size));
+
+        // 2. Q projection
+        const q_name = GGUFNames.formatName(&name_buf, GGUFNames.q_proj, layer);
+        loadTensor(self.loader, q_name, buf.getBF16Slice(off.q_proj, cfg.hidden_size * cfg.hidden_size));
+
+        // 3. K projection
+        const k_name = GGUFNames.formatName(&name_buf, GGUFNames.k_proj, layer);
+        loadTensor(self.loader, k_name, buf.getBF16Slice(off.k_proj, cfg.hidden_size * cfg.kv_dim));
+
+        // 4. V projection
+        const v_name = GGUFNames.formatName(&name_buf, GGUFNames.v_proj, layer);
+        loadTensor(self.loader, v_name, buf.getBF16Slice(off.v_proj, cfg.hidden_size * cfg.kv_dim));
+
+        // 5. O projection
+        const o_name = GGUFNames.formatName(&name_buf, GGUFNames.o_proj, layer);
+        loadTensor(self.loader, o_name, buf.getBF16Slice(off.o_proj, cfg.hidden_size * cfg.hidden_size));
+
+        // 6. Q bias
+        const qb_name = GGUFNames.formatName(&name_buf, GGUFNames.q_bias, layer);
+        loadTensor(self.loader, qb_name, buf.getBF16Slice(off.q_bias, cfg.hidden_size));
+
+        // 7. K bias
+        const kb_name = GGUFNames.formatName(&name_buf, GGUFNames.k_bias, layer);
+        loadTensor(self.loader, kb_name, buf.getBF16Slice(off.k_bias, cfg.kv_dim));
+
+        // 8. V bias
+        const vb_name = GGUFNames.formatName(&name_buf, GGUFNames.v_bias, layer);
+        loadTensor(self.loader, vb_name, buf.getBF16Slice(off.v_bias, cfg.kv_dim));
+
+        // 9. Post-attention LayerNorm
+        const ln2_name = GGUFNames.formatName(&name_buf, GGUFNames.post_attn_layernorm, layer);
+        loadTensor(self.loader, ln2_name, buf.getBF16Slice(off.post_attn_layernorm, cfg.hidden_size));
+
+        // 10. Gate projection (FFN)
+        const gate_name = GGUFNames.formatName(&name_buf, GGUFNames.gate_proj, layer);
+        loadTensor(self.loader, gate_name, buf.getBF16Slice(off.gate_proj, cfg.hidden_size * cfg.intermediate_size));
+
+        // 11. Up projection (FFN)
+        const up_name = GGUFNames.formatName(&name_buf, GGUFNames.up_proj, layer);
+        loadTensor(self.loader, up_name, buf.getBF16Slice(off.up_proj, cfg.hidden_size * cfg.intermediate_size));
+
+        // 12. Down projection (FFN)
+        const down_name = GGUFNames.formatName(&name_buf, GGUFNames.down_proj, layer);
+        loadTensor(self.loader, down_name, buf.getBF16Slice(off.down_proj, cfg.intermediate_size * cfg.hidden_size));
+    }
+
+    /// Load all weights for a single layer using ZERO-COPY mmap pointers
+    /// No CPU memcpy - GPU reads directly from mmap'd GGUF file!
+    /// Apple Silicon unified memory makes this possible.
+    fn loadLayerWeightsQ8(self: *Self, layer: u32, buf: *PingPongBuffer) void {
+        var name_buf: [64]u8 = undefined;
+        const cfg = self.config;
+        const bf16_off = self.offsets;
+
+        // Helper to load non-quantized tensor (still needs CPU dequant to BF16)
+        // These are small (LayerNorms, biases) so CPU dequant is fine
+        const loadBF16 = struct {
+            fn load(
+                loader: *gguf.GGUFLoader,
+                name: []const u8,
+                dest: []BF16,
+            ) void {
+                loader.dequantizeToBF16(name, dest) catch |err| {
+                    log.warn("Failed to load {s}: {}", .{ name, err });
+                };
+            }
+        }.load;
+
+        // =========================================================================
+        // Non-quantized tensors (CPU dequant → BF16 buffer directly)
+        // LayerNorms and biases are small, CPU dequant is fine
+        // =========================================================================
+
+        // 1. Input LayerNorm
+        const ln1_name = GGUFNames.formatName(&name_buf, GGUFNames.input_layernorm, layer);
+        loadBF16(self.loader, ln1_name, buf.getBF16Slice(bf16_off.input_layernorm, cfg.hidden_size));
+
+        // 2. Q bias
+        const qb_name = GGUFNames.formatName(&name_buf, GGUFNames.q_bias, layer);
+        loadBF16(self.loader, qb_name, buf.getBF16Slice(bf16_off.q_bias, cfg.hidden_size));
+
+        // 3. K bias
+        const kb_name = GGUFNames.formatName(&name_buf, GGUFNames.k_bias, layer);
+        loadBF16(self.loader, kb_name, buf.getBF16Slice(bf16_off.k_bias, cfg.kv_dim));
+
+        // 4. V bias
+        const vb_name = GGUFNames.formatName(&name_buf, GGUFNames.v_bias, layer);
+        loadBF16(self.loader, vb_name, buf.getBF16Slice(bf16_off.v_bias, cfg.kv_dim));
+
+        // 5. Post-attention LayerNorm
+        const ln2_name = GGUFNames.formatName(&name_buf, GGUFNames.post_attn_layernorm, layer);
+        loadBF16(self.loader, ln2_name, buf.getBF16Slice(bf16_off.post_attn_layernorm, cfg.hidden_size));
+
+        // =========================================================================
+        // Quantized tensors - ZERO COPY!
+        // Just store pointers to mmap'd data - GPU reads directly from unified memory
+        // No memcpy needed on Apple Silicon!
+        // =========================================================================
+
+        // 6. Q projection - store mmap pointer
+        const q_name = GGUFNames.formatName(&name_buf, GGUFNames.q_proj, layer);
+        buf.mmap_q8_ptrs.q_proj = self.loader.getRawQ8Slice(q_name);
+
+        // 7. K projection
+        const k_name = GGUFNames.formatName(&name_buf, GGUFNames.k_proj, layer);
+        buf.mmap_q8_ptrs.k_proj = self.loader.getRawQ8Slice(k_name);
+
+        // 8. V projection
+        const v_name = GGUFNames.formatName(&name_buf, GGUFNames.v_proj, layer);
+        buf.mmap_q8_ptrs.v_proj = self.loader.getRawQ8Slice(v_name);
+
+        // 9. O projection
+        const o_name = GGUFNames.formatName(&name_buf, GGUFNames.o_proj, layer);
+        buf.mmap_q8_ptrs.o_proj = self.loader.getRawQ8Slice(o_name);
+
+        // 10. Gate projection
+        const gate_name = GGUFNames.formatName(&name_buf, GGUFNames.gate_proj, layer);
+        buf.mmap_q8_ptrs.gate_proj = self.loader.getRawQ8Slice(gate_name);
+
+        // 11. Up projection
+        const up_name = GGUFNames.formatName(&name_buf, GGUFNames.up_proj, layer);
+        buf.mmap_q8_ptrs.up_proj = self.loader.getRawQ8Slice(up_name);
+
+        // 12. Down projection
+        const down_name = GGUFNames.formatName(&name_buf, GGUFNames.down_proj, layer);
+        buf.mmap_q8_ptrs.down_proj = self.loader.getRawQ8Slice(down_name);
+    }
+
+    // =========================================================================
+    // Inference (Main Thread)
+    // =========================================================================
+
+    /// Run one forward pass through all layers
+    /// Returns when all layers have been processed
+    pub fn forwardPass(self: *Self) !void {
+        log.info("Starting forward pass ({} layers)", .{self.config.n_layers});
+
+        var use_buf_a = true;
+
+        for (0..self.config.n_layers) |layer_idx| {
+            const buf = if (use_buf_a) &self.buf_a else &self.buf_b;
+
+            // Wait for weights to be loaded
+            const wait_start = std.time.nanoTimestamp();
+            buf.ready_for_gpu.wait();
+            const wait_time: u64 = @intCast(std.time.nanoTimestamp() - wait_start);
+
+            if (wait_time > 1_000_000) { // > 1ms
+                log.debug("Layer {}: waited {} ms for weights", .{ layer_idx, wait_time / 1_000_000 });
+            }
+
+            // Compute this layer (placeholder - would dispatch Metal kernels)
+            const compute_start = std.time.nanoTimestamp();
+            try self.computeLayer(buf, @intCast(layer_idx));
+            const compute_time: u64 = @intCast(std.time.nanoTimestamp() - compute_start);
+            self.compute_time_ns += compute_time;
+
+            log.debug("Layer {}: computed in {} ms", .{ layer_idx, compute_time / 1_000_000 });
+
+            // Release buffer for CPU to refill
+            buf.ready_for_cpu.post();
+
+            use_buf_a = !use_buf_a;
+        }
+
+        log.info("Forward pass complete", .{});
+    }
+
+    /// Compute one layer (placeholder for Metal dispatch)
+    fn computeLayer(self: *Self, buf: *PingPongBuffer, layer_idx: u32) !void {
+        _ = layer_idx;
+
+        // In production, this would dispatch Metal kernels:
+        // 1. RMSNorm (input_layernorm)
+        // 2. QKV MatMul + bias
+        // 3. RoPE on Q, K
+        // 4. Cache K, V
+        // 5. GQA Attention
+        // 6. O projection + residual
+        // 7. RMSNorm (post_attn)
+        // 8. SwiGLU FFN (gate, up, down)
+        // 9. Residual add
+
+        // For now, just verify the buffer has valid data
+        const cfg = self.config;
+        const off = self.offsets;
+
+        // Quick sanity check: verify first few values of input_layernorm aren't zero
+        const ln_weights = buf.getBF16Slice(off.input_layernorm, cfg.hidden_size);
+        var non_zero: u32 = 0;
+        for (ln_weights[0..@min(100, ln_weights.len)]) |v| {
+            if (v != 0) non_zero += 1;
+        }
+
+        if (non_zero < 10) {
+            log.warn("Layer {} input_layernorm appears empty ({} non-zero values)", .{ buf.layer_idx, non_zero });
+        }
+    }
+
+    /// Print performance statistics
+    pub fn printStats(self: *Self) void {
+        const total_time = self.load_time_ns + self.compute_time_ns;
+        if (self.layers_loaded == 0) return;
+
+        std.debug.print("\n=== Streaming Engine Stats ===\n", .{});
+        std.debug.print("Layers loaded: {}\n", .{self.layers_loaded});
+        std.debug.print("Avg load time: {} ms/layer\n", .{self.load_time_ns / self.layers_loaded / 1_000_000});
+        std.debug.print("Avg compute time: {} ms/layer\n", .{
+            if (self.layers_loaded > 0) self.compute_time_ns / self.layers_loaded / 1_000_000 else 0,
+        });
+        std.debug.print("Total time: {} ms\n", .{total_time / 1_000_000});
+        std.debug.print("Load/Compute ratio: {d:.2}\n", .{
+            @as(f64, @floatFromInt(self.load_time_ns)) / @as(f64, @floatFromInt(@max(self.compute_time_ns, 1))),
+        });
+
+        // Tiered memory statistics
+        if (self.resident_layers > 0) {
+            std.debug.print("\n=== Tiered Memory Stats ===\n", .{});
+            std.debug.print("Resident layers: {} (cached in RAM)\n", .{self.resident_layers});
+            std.debug.print("Streaming layers: {}\n", .{self.config.n_layers - self.resident_layers});
+            std.debug.print("Resident bytes: {} MB\n", .{self.resident_bytes / (1024 * 1024)});
+
+            // Calculate per-layer averages for each tier
+            const resident_loaded = @min(self.layers_loaded, self.resident_layers);
+            const streaming_loaded = if (self.layers_loaded > self.resident_layers)
+                self.layers_loaded - self.resident_layers
+            else
+                0;
+
+            if (resident_loaded > 0) {
+                std.debug.print("Avg resident load: {} ms/layer (CPU dequant only)\n", .{
+                    self.resident_load_time_ns / resident_loaded / 1_000_000,
+                });
+            }
+            if (streaming_loaded > 0) {
+                std.debug.print("Avg streaming load: {} ms/layer (disk + CPU dequant)\n", .{
+                    self.streaming_load_time_ns / streaming_loaded / 1_000_000,
+                });
+            }
+
+            // Speedup calculation
+            if (resident_loaded > 0 and streaming_loaded > 0) {
+                const resident_avg = @as(f64, @floatFromInt(self.resident_load_time_ns)) / @as(f64, @floatFromInt(resident_loaded));
+                const streaming_avg = @as(f64, @floatFromInt(self.streaming_load_time_ns)) / @as(f64, @floatFromInt(streaming_loaded));
+                const speedup = streaming_avg / resident_avg;
+                std.debug.print("Resident speedup: {d:.2}x faster than streaming\n", .{speedup});
+            }
+        }
+    }
+};
