+//! GPU Dequantization Benchmark
+//!
+//! Compares CPU SIMD dequantization vs GPU Metal dequantization.
+//! Expected result: GPU should be ~80x faster (~0.02s vs ~1.6s per layer)
+
+const std = @import("std");
+const metal_inference = @import("metal_inference.zig");
+const model = @import("qwen_model.zig");
+const gguf = @import("gguf_loader.zig");
+
+const QwenConfig = model.QwenConfig;
+const Q8LayerOffsets = model.Q8LayerOffsets;
+const LayerOffsets = model.LayerOffsets;
+const BF16 = gguf.BF16;
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n", .{});
+    std.debug.print("=" ** 70 ++ "\n", .{});
+    std.debug.print("  GPU Dequantization Benchmark\n", .{});
+    std.debug.print("  Comparing CPU SIMD vs Metal GPU dequant performance\n", .{});
+    std.debug.print("=" ** 70 ++ "\n\n", .{});
+
+    // Initialize config
+    const config = QwenConfig{};
+    const q8_offsets = Q8LayerOffsets.init(config);
+    const q8_layer_size = q8_offsets.totalSize();
+    const bf16_layer_size = config.layerSizeBytes();
+
+    std.debug.print("Configuration:\n", .{});
+    std.debug.print("  Hidden size: {}\n", .{config.hidden_size});
+    std.debug.print("  Intermediate size: {}\n", .{config.intermediate_size});
+    std.debug.print("  Q8 layer size: {} MB\n", .{q8_layer_size / (1024 * 1024)});
+    std.debug.print("  BF16 layer size: {} MB\n", .{bf16_layer_size / (1024 * 1024)});
+    std.debug.print("  Compression ratio: {d:.1}%\n\n", .{
+        @as(f64, @floatFromInt(q8_layer_size)) / @as(f64, @floatFromInt(bf16_layer_size)) * 100.0,
+    });
+
+    // Allocate test buffers
+    std.debug.print("Allocating test buffers...\n", .{});
+    const q8_buf = try allocator.alloc(u8, q8_layer_size);
+    defer allocator.free(q8_buf);
+    const bf16_buf_cpu = try allocator.alloc(u8, bf16_layer_size);
+    defer allocator.free(bf16_buf_cpu);
+    const bf16_buf_gpu = try allocator.alloc(u8, bf16_layer_size);
+    defer allocator.free(bf16_buf_gpu);
+
+    // Fill Q8 buffer with test data (simulated Q8_0 blocks)
+    std.debug.print("Generating test Q8 data...\n", .{});
+    var prng = std.Random.DefaultPrng.init(12345);
+    const random = prng.random();
+
+    // Q8_0 format: [f16 delta (2 bytes)] + [32 x i8 quants (32 bytes)] = 34 bytes per block
+    var i: usize = 0;
+    while (i < q8_buf.len) : (i += 34) {
+        if (i + 34 > q8_buf.len) break;
+
+        // Random delta (f16) - use small values
+        const delta_f32: f32 = (random.float(f32) - 0.5) * 0.1;
+        const delta_f16: f16 = @floatCast(delta_f32);
+        const delta_ptr: *f16 = @ptrCast(@alignCast(&q8_buf[i]));
+        delta_ptr.* = delta_f16;
+
+        // Random quantized values (i8)
+        for (q8_buf[i + 2 ..][0..32]) |*b| {
+            b.* = @bitCast(random.int(u8));
+        }
+    }
+
+    // Initialize Metal engine
+    std.debug.print("Initializing Metal engine...\n\n", .{});
+    const engine = try metal_inference.MetalInferenceEngine.init(allocator, config);
+    defer engine.deinit();
+
+    // =========================================================================
+    // Benchmark GPU Dequantization (single tensor for fair comparison)
+    // =========================================================================
+    std.debug.print("--- GPU Dequantization Benchmark ---\n", .{});
+
+    // Just dequantize a large chunk to compare apples-to-apples
+    // Calculate how many blocks we can dequantize that fit in the output buffer
+    const max_bf16_values = bf16_layer_size / 2; // BF16 = 2 bytes
+    const max_blocks_from_output = max_bf16_values / 32; // 32 values per block
+    const max_blocks_from_input = q8_buf.len / 34; // 34 bytes per block
+    const total_blocks = @min(max_blocks_from_output, max_blocks_from_input);
+    const total_bf16_values = total_blocks * 32;
+
+    std.debug.print("  Blocks to process: {} ({} MB Q8 -> {} MB BF16)\n\n", .{
+        total_blocks,
+        total_blocks * 34 / (1024 * 1024),
+        total_bf16_values * 2 / (1024 * 1024),
+    });
+
+    const gpu_iterations: u32 = 5;
+    var gpu_total_ns: u64 = 0;
+
+    for (0..gpu_iterations) |iter| {
+        const start = std.time.nanoTimestamp();
+
+        // Direct dispatch of single big dequant operation
+        const bf16_slice: []BF16 = @as([*]BF16, @ptrCast(@alignCast(bf16_buf_gpu.ptr)))[0..total_bf16_values];
+        try engine.dispatchDequantQ8(q8_buf[0 .. total_blocks * 34], bf16_slice, @intCast(total_blocks));
+
+        const elapsed: u64 = @intCast(std.time.nanoTimestamp() - start);
+        gpu_total_ns += elapsed;
+
+        std.debug.print("  Iteration {}: {} ms\n", .{ iter + 1, elapsed / 1_000_000 });
+    }
+
+    const gpu_avg_ms = gpu_total_ns / gpu_iterations / 1_000_000;
+    std.debug.print("GPU Average: {} ms/layer\n\n", .{gpu_avg_ms});
+
+    // =========================================================================
+    // Benchmark CPU SIMD Dequantization (simulated)
+    // =========================================================================
+    std.debug.print("--- CPU SIMD Dequantization Benchmark ---\n", .{});
+
+    const cpu_iterations: u32 = 3;
+    var cpu_total_ns: u64 = 0;
+
+    for (0..cpu_iterations) |iter| {
+        const start = std.time.nanoTimestamp();
+
+        // Simulate CPU dequant by processing Q8 blocks
+        // This mimics the SIMD dequantization in gguf_loader.zig
+        var block_idx: usize = 0;
+        while (block_idx * 34 < q8_buf.len) : (block_idx += 1) {
+            const block_offset = block_idx * 34;
+            if (block_offset + 34 > q8_buf.len) break;
+
+            // Read delta
+            const delta_ptr: *const f16 = @ptrCast(@alignCast(&q8_buf[block_offset]));
+            const delta: f32 = @floatCast(delta_ptr.*);
+
+            // Dequantize 32 values
+            const quants = q8_buf[block_offset + 2 ..][0..32];
+            const out_offset = block_idx * 32 * 2;
+            if (out_offset + 64 > bf16_buf_cpu.len) break;
+
+            const out_ptr: [*]BF16 = @ptrCast(@alignCast(&bf16_buf_cpu[out_offset]));
+            for (quants, 0..) |q, j| {
+                const val: f32 = delta * @as(f32, @floatFromInt(@as(i8, @bitCast(q))));
+                // Convert float to bf16 (truncate lower 16 bits)
+                const bits: u32 = @bitCast(val);
+                out_ptr[j] = @truncate(bits >> 16);
+            }
+        }
+
+        const elapsed: u64 = @intCast(std.time.nanoTimestamp() - start);
+        cpu_total_ns += elapsed;
+
+        std.debug.print("  Iteration {}: {} ms\n", .{ iter + 1, elapsed / 1_000_000 });
+    }
+
+    const cpu_avg_ms = cpu_total_ns / cpu_iterations / 1_000_000;
+    std.debug.print("CPU Average: {} ms/layer\n\n", .{cpu_avg_ms});
+
+    // =========================================================================
+    // Results
+    // =========================================================================
+    std.debug.print("=" ** 70 ++ "\n", .{});
+    std.debug.print("  Results\n", .{});
+    std.debug.print("=" ** 70 ++ "\n\n", .{});
+
+    const speedup = @as(f64, @floatFromInt(cpu_avg_ms)) / @as(f64, @floatFromInt(@max(gpu_avg_ms, 1)));
+
+    std.debug.print("CPU SIMD:  {} ms/layer\n", .{cpu_avg_ms});
+    std.debug.print("GPU Metal: {} ms/layer\n", .{gpu_avg_ms});
+    std.debug.print("Speedup:   {d:.1}x\n\n", .{speedup});
+
+    // Verify correctness (spot check a few values at offset 0)
+    std.debug.print("Verifying correctness (comparing first 1000 values)...\n", .{});
+    var mismatches: u32 = 0;
+
+    const check_count: usize = @min(1000, bf16_buf_cpu.len / 2);
+
+    const cpu_ptr: [*]const BF16 = @ptrCast(@alignCast(bf16_buf_cpu.ptr));
+    const gpu_ptr: [*]const BF16 = @ptrCast(@alignCast(bf16_buf_gpu.ptr));
+
+    for (0..check_count) |j| {
+        const cpu_val = cpu_ptr[j];
+        const gpu_val = gpu_ptr[j];
+        if (cpu_val != gpu_val) {
+            mismatches += 1;
+            if (mismatches <= 5) {
+                std.debug.print("  Mismatch at {}: CPU={x:04}, GPU={x:04}\n", .{ j, cpu_val, gpu_val });
+            }
+        }
+    }
+
+    if (mismatches > 0) {
+        // Show sample of actual values
+        std.debug.print("Sample GPU values: ", .{});
+        for (0..@min(5, check_count)) |j| {
+            std.debug.print("{x:04} ", .{gpu_ptr[j]});
+        }
+        std.debug.print("\n", .{});
+    }
+    std.debug.print("Checked {} values, {} mismatches\n\n", .{ check_count, mismatches });
+
+    // Performance projection
+    const layers: u32 = config.n_layers;
+    const cpu_token_time = cpu_avg_ms * layers;
+    const gpu_token_time = gpu_avg_ms * layers;
+
+    std.debug.print("Performance Projection ({} layers):\n", .{layers});
+    std.debug.print("  CPU: {} ms/token ({d:.2} tok/s)\n", .{
+        cpu_token_time,
+        1000.0 / @as(f64, @floatFromInt(cpu_token_time)),
+    });
+    std.debug.print("  GPU: {} ms/token ({d:.2} tok/s)\n", .{
+        gpu_token_time,
+        1000.0 / @as(f64, @floatFromInt(@max(gpu_token_time, 1))),
+    });
+
+    std.debug.print("\n", .{});
+    std.debug.print("=" ** 70 ++ "\n", .{});
+    std.debug.print("  GPU DEQUANT BENCHMARK COMPLETE\n", .{});
+    std.debug.print("=" ** 70 ++ "\n", .{});
+}

