+//! Zero-Copy Data Loader
+//!
+//! Memory-maps the dataset file directly into Metal's unified memory space.
+//! The GPU reads tokens straight from the SSD page cache with zero CPU copies.
+//!
+//! This is the key optimization that makes training fast:
+//! - PyTorch: Read → Deserialize → Copy to Tensor → Copy to GPU
+//! - Zell: mmap → GPU reads directly (1 step, zero copies)
+
+const std = @import("std");
+const metal = @import("../metal/metal_engine.zig");
+const dataset = @import("dataset_writer.zig");
+const log = std.log.scoped(.data_loader);
+
+/// Zero-Copy Data Loader
+pub const DataLoader = struct {
+    // File handle (kept open for mmap)
+    file: std.fs.File,
+
+    // Memory-mapped region (16KB alignment for Apple Silicon)
+    mmap_ptr: []align(16384) u8,
+    mmap_len: usize,
+
+    // Dataset metadata
+    total_tokens: u64,
+    vocab_size: u32,
+
+    // Pointer to raw token data (after header)
+    data_ptr: [*]const u16,
+
+    // Metal buffer wrapping the mmap (zero-copy)
+    metal_buffer: ?metal.MetalBuffer,
+
+    // Training state
+    cursor: u64 = 0,
+    epoch: u32 = 0,
+
+    // Configuration
+    shuffle: bool,
+    seed: u64,
+
+    // Shuffle indices (if shuffling enabled)
+    shuffle_indices: ?[]u64,
+    allocator: std.mem.Allocator,
+
+    const Self = @This();
+
+    /// Initialize data loader with memory-mapped dataset
+    pub fn init(
+        allocator: std.mem.Allocator,
+        path: []const u8,
+        engine: ?*metal.MetalEngine,
+        options: LoaderOptions,
+    ) !Self {
+        const file = try std.fs.cwd().openFile(path, .{});
+        errdefer file.close();
+
+        const stat = try file.stat();
+        if (stat.size < dataset.HEADER_SIZE) {
+            return error.FileTooSmall;
+        }
+
+        // Memory-map the entire file
+        const mmap_ptr = try std.posix.mmap(
+            null,
+            stat.size,
+            std.posix.PROT.READ,
+            .{ .TYPE = .PRIVATE },
+            file.handle,
+            0,
+        );
+        errdefer std.posix.munmap(mmap_ptr);
+
+        // Parse header
+        const header = mmap_ptr[0..dataset.HEADER_SIZE];
+
+        // Verify magic
+        if (!std.mem.eql(u8, header[0..4], dataset.MAGIC)) {
+            log.err("Invalid file format: expected ZELL magic", .{});
+            return error.InvalidFormat;
+        }
+
+        const version = std.mem.readInt(u32, header[4..8], .little);
+        if (version != dataset.VERSION) {
+            log.warn("Version mismatch: file={d}, loader={d}", .{ version, dataset.VERSION });
+        }
+
+        const total_tokens = std.mem.readInt(u64, header[8..16], .little);
+        const vocab_size = std.mem.readInt(u32, header[16..20], .little);
+
+        // Data starts after header
+        const data_ptr: [*]const u16 = @ptrCast(@alignCast(mmap_ptr[dataset.HEADER_SIZE..].ptr));
+
+        // Create Metal buffer wrapping this memory (zero-copy!)
+        var metal_buffer: ?metal.MetalBuffer = null;
+        if (engine) |eng| {
+            // Cast away const for Metal (we only read, but Metal API wants mutable)
+            const mutable_ptr: *anyopaque = @constCast(@ptrCast(mmap_ptr));
+            metal_buffer = try eng.createBufferNoCopy(mutable_ptr, stat.size);
+            log.info("Created zero-copy Metal buffer for dataset", .{});
+        }
+
+        // Setup shuffle indices if needed
+        var shuffle_indices: ?[]u64 = null;
+        if (options.shuffle) {
+            const num_sequences = total_tokens / options.context_length;
+            shuffle_indices = try allocator.alloc(u64, num_sequences);
+
+            for (shuffle_indices.?, 0..) |*idx, i| {
+                idx.* = i;
+            }
+        }
+
+        log.info("Loaded dataset: {d} tokens, vocab_size={d}, file_size={d}MB", .{
+            total_tokens,
+            vocab_size,
+            stat.size / (1024 * 1024),
+        });
+
+        var self = Self{
+            .file = file,
+            .mmap_ptr = mmap_ptr,
+            .mmap_len = stat.size,
+            .total_tokens = total_tokens,
+            .vocab_size = vocab_size,
+            .data_ptr = data_ptr,
+            .metal_buffer = metal_buffer,
+            .cursor = 0,
+            .epoch = 0,
+            .shuffle = options.shuffle,
+            .seed = options.seed,
+            .shuffle_indices = shuffle_indices,
+            .allocator = allocator,
+        };
+
+        if (options.shuffle) {
+            self.shuffleIndices();
+        }
+
+        return self;
+    }
+
+    /// Shuffle the sequence indices for a new epoch
+    fn shuffleIndices(self: *Self) void {
+        if (self.shuffle_indices) |indices| {
+            var prng = std.Random.DefaultPrng.init(self.seed +% self.epoch);
+            const random = prng.random();
+
+            // Fisher-Yates shuffle
+            var i = indices.len - 1;
+            while (i > 0) : (i -= 1) {
+                const j = random.uintLessThan(usize, i + 1);
+                const tmp = indices[i];
+                indices[i] = indices[j];
+                indices[j] = tmp;
+            }
+        }
+    }
+
+    /// Get the byte offset into the mmap for a batch
+    /// This is passed directly to the embedding kernel
+    pub fn nextBatchOffset(self: *Self, batch_size: usize, context_len: usize) BatchInfo {
+        const tokens_per_batch = batch_size * context_len;
+
+        // Check for epoch boundary
+        if (self.cursor + tokens_per_batch > self.total_tokens) {
+            self.cursor = 0;
+            self.epoch += 1;
+            if (self.shuffle) {
+                self.shuffleIndices();
+            }
+            log.info("Epoch {d} complete, starting epoch {d}", .{ self.epoch - 1, self.epoch });
+        }
+
+        const token_offset = self.cursor;
+
+        // Calculate byte offset: header + token_offset * sizeof(u16)
+        const byte_offset = dataset.HEADER_SIZE + (token_offset * 2);
+
+        self.cursor += tokens_per_batch;
+
+        return BatchInfo{
+            .byte_offset = byte_offset,
+            .token_offset = token_offset,
+            .num_tokens = tokens_per_batch,
+            .epoch = self.epoch,
+        };
+    }
+
+    /// Get a slice of tokens for CPU access (debugging/validation)
+    pub fn getTokenSlice(self: *Self, offset: u64, count: usize) []const u16 {
+        const start = offset;
+        const end = @min(start + count, self.total_tokens);
+        return self.data_ptr[start..end];
+    }
+
+    /// Get the Metal buffer for GPU access
+    pub fn getMetalBuffer(self: *Self) ?metal.MetalBuffer {
+        return self.metal_buffer;
+    }
+
+    /// Get total number of tokens
+    pub fn numTokens(self: *Self) u64 {
+        return self.total_tokens;
+    }
+
+    /// Get number of complete sequences of given length
+    pub fn numSequences(self: *Self, context_len: usize) u64 {
+        return self.total_tokens / context_len;
+    }
+
+    /// Get current epoch
+    pub fn currentEpoch(self: *Self) u32 {
+        return self.epoch;
+    }
+
+    /// Get progress within current epoch (0.0 - 1.0)
+    pub fn epochProgress(self: *Self) f32 {
+        return @as(f32, @floatFromInt(self.cursor)) / @as(f32, @floatFromInt(self.total_tokens));
+    }
+
+    /// Reset to beginning
+    pub fn reset(self: *Self) void {
+        self.cursor = 0;
+        self.epoch = 0;
+        if (self.shuffle) {
+            self.shuffleIndices();
+        }
+    }
+
+    pub fn deinit(self: *Self) void {
+        if (self.metal_buffer) |buf| {
+            metal.MetalEngine.releaseBuffer(buf);
+        }
+        if (self.shuffle_indices) |indices| {
+            self.allocator.free(indices);
+        }
+        std.posix.munmap(self.mmap_ptr);
+        self.file.close();
+        log.info("Data loader closed", .{});
+    }
+};
+
+/// Loader configuration options
+pub const LoaderOptions = struct {
+    shuffle: bool = true,
+    seed: u64 = 42,
+    context_length: usize = 1024,
+};
+
+/// Batch information returned by nextBatchOffset
+pub const BatchInfo = struct {
+    byte_offset: usize, // Offset into mmap in bytes
+    token_offset: u64, // Offset in tokens
+    num_tokens: usize, // Total tokens in batch
+    epoch: u32, // Current epoch number
+};
+
+// =============================================================================
+// Multi-Shard Loader
+// =============================================================================
+
+/// Data loader that handles multiple shards
+pub const ShardedLoader = struct {
+    allocator: std.mem.Allocator,
+    shards: std.ArrayList(DataLoader),
+    current_shard: usize = 0,
+    total_tokens: u64 = 0,
+
+    pub fn init(allocator: std.mem.Allocator) ShardedLoader {
+        return .{
+            .allocator = allocator,
+            .shards = std.ArrayList(DataLoader).init(allocator),
+        };
+    }
+
+    /// Add a shard file
+    pub fn addShard(
+        self: *ShardedLoader,
+        path: []const u8,
+        engine: ?*metal.MetalEngine,
+        options: LoaderOptions,
+    ) !void {
+        const loader = try DataLoader.init(self.allocator, path, engine, options);
+        self.total_tokens += loader.total_tokens;
+        try self.shards.append(loader);
+    }
+
+    /// Get next batch, automatically moving between shards
+    pub fn nextBatchOffset(self: *ShardedLoader, batch_size: usize, context_len: usize) struct {
+        shard_idx: usize,
+        info: BatchInfo,
+    } {
+        var shard = &self.shards.items[self.current_shard];
+        const info = shard.nextBatchOffset(batch_size, context_len);
+
+        // If epoch changed, move to next shard
+        if (info.epoch > 0 and info.token_offset == 0) {
+            self.current_shard = (self.current_shard + 1) % self.shards.items.len;
+        }
+
+        return .{
+            .shard_idx = self.current_shard,
+            .info = info,
+        };
+    }
+
+    pub fn deinit(self: *ShardedLoader) void {
+        for (self.shards.items) |*shard| {
+            shard.deinit();
+        }
+        self.shards.deinit();
+    }
+};
+
+// =============================================================================
+// Streaming Loader (for datasets too large to mmap)
+// =============================================================================
+
+/// Streaming data loader with double-buffering
+/// Use this for extremely large datasets that can't fit in address space
+pub const StreamingLoader = struct {
+    file: std.fs.File,
+    total_tokens: u64,
+
+    // Double buffer for async loading
+    buffer_a: []u16,
+    buffer_b: []u16,
+    active_buffer: u8 = 0,
+
+    buffer_size: usize, // tokens per buffer
+    cursor: u64 = 0,
+    buffer_cursor: usize = 0,
+
+    allocator: std.mem.Allocator,
+
+    pub fn init(allocator: std.mem.Allocator, path: []const u8, buffer_tokens: usize) !StreamingLoader {
+        const file = try std.fs.cwd().openFile(path, .{});
+        const stat = try file.stat();
+
+        // Skip header
+        try file.seekTo(dataset.HEADER_SIZE);
+
+        const buffer_a = try allocator.alloc(u16, buffer_tokens);
+        const buffer_b = try allocator.alloc(u16, buffer_tokens);
+
+        var loader = StreamingLoader{
+            .file = file,
+            .total_tokens = (stat.size - dataset.HEADER_SIZE) / 2,
+            .buffer_a = buffer_a,
+            .buffer_b = buffer_b,
+            .buffer_size = buffer_tokens,
+            .allocator = allocator,
+        };
+
+        // Pre-fill first buffer
+        try loader.fillBuffer(loader.buffer_a);
+
+        return loader;
+    }
+
+    fn fillBuffer(self: *StreamingLoader, buffer: []u16) !void {
+        const bytes = std.mem.sliceAsBytes(buffer);
+        _ = try self.file.readAll(bytes);
+    }
+
+    pub fn getActiveBuffer(self: *StreamingLoader) []const u16 {
+        return if (self.active_buffer == 0) self.buffer_a else self.buffer_b;
+    }
+
+    pub fn deinit(self: *StreamingLoader) void {
+        self.allocator.free(self.buffer_a);
+        self.allocator.free(self.buffer_b);
+        self.file.close();
+    }
+};
+
