+//! Dataset Writer
+//!
+//! Writes tokenized data to a simple binary columnar format for zero-copy loading.
+//!
+//! Format (ZELL Binary Dataset v1):
+//! ┌─────────────────────────────────────────┐
+//! │ Magic: "ZELL" (4 bytes)                 │
+//! │ Version: u32 (4 bytes)                  │
+//! │ Total Tokens: u64 (8 bytes)             │
+//! │ Vocab Size: u32 (4 bytes)               │
+//! │ Reserved: 12 bytes (for future use)     │
+//! ├─────────────────────────────────────────┤
+//! │ Token IDs: [u16]...                     │
+//! └─────────────────────────────────────────┘
+//!
+//! Header size: 32 bytes (aligned for mmap efficiency)
+//! Token size: 2 bytes (u16) - GPT-2 vocab fits in u16, saves 50% space vs u32
+
+const std = @import("std");
+const log = std.log.scoped(.dataset_writer);
+
+/// Dataset file magic number
+pub const MAGIC: *const [4]u8 = "ZELL";
+
+/// Current format version
+pub const VERSION: u32 = 1;
+
+/// Header size in bytes (32 bytes, page-aligned friendly)
+pub const HEADER_SIZE: usize = 32;
+
+/// Dataset Writer for creating binary token files
+pub const DatasetWriter = struct {
+    file: std.fs.File,
+    count: u64 = 0,
+    vocab_size: u32,
+
+    const Self = @This();
+
+    /// Create a new dataset file
+    pub fn init(path: []const u8, vocab_size: u32) !Self {
+        const file = try std.fs.cwd().createFile(path, .{});
+        errdefer file.close();
+
+        // Write header
+        var header: [HEADER_SIZE]u8 = undefined;
+        @memset(&header, 0);
+
+        // Magic (4 bytes)
+        @memcpy(header[0..4], MAGIC);
+
+        // Version (4 bytes)
+        std.mem.writeInt(u32, header[4..8], VERSION, .little);
+
+        // Total tokens placeholder (8 bytes) - will update on finish
+        std.mem.writeInt(u64, header[8..16], 0, .little);
+
+        // Vocab size (4 bytes)
+        std.mem.writeInt(u32, header[16..20], vocab_size, .little);
+
+        // Reserved (12 bytes) - already zeroed
+
+        try file.writeAll(&header);
+
+        log.info("Created dataset file: {s}", .{path});
+
+        return Self{
+            .file = file,
+            .count = 0,
+            .vocab_size = vocab_size,
+        };
+    }
+
+    /// Append tokens to the dataset (u32 input, stored as u16)
+    pub fn append(self: *Self, tokens: []const u32) !void {
+        for (tokens) |t| {
+            if (t >= self.vocab_size) {
+                log.warn("Token {d} exceeds vocab size {d}", .{ t, self.vocab_size });
+            }
+            // Store as u16 (GPT-2 vocab is ~50k, fits comfortably)
+            const t_u16: u16 = @intCast(@min(t, 65535));
+            try self.file.writeInt(u16, t_u16, .little);
+        }
+        self.count += tokens.len;
+    }
+
+    /// Append pre-converted u16 tokens directly
+    pub fn appendU16(self: *Self, tokens: []const u16) !void {
+        const bytes = std.mem.sliceAsBytes(tokens);
+        try self.file.writeAll(bytes);
+        self.count += tokens.len;
+    }
+
+    /// Append a single token
+    pub fn appendOne(self: *Self, token: u32) !void {
+        const t_u16: u16 = @intCast(@min(token, 65535));
+        try self.file.writeInt(u16, t_u16, .little);
+        self.count += 1;
+    }
+
+    /// Finish writing and update header with final token count
+    pub fn finish(self: *Self) !void {
+        // Seek back to update token count in header
+        try self.file.seekTo(8);
+        try self.file.writeInt(u64, self.count, .little);
+
+        // Flush and close
+        self.file.close();
+
+        log.info("Dataset finished: {d} tokens written", .{self.count});
+    }
+
+    /// Get current token count
+    pub fn tokenCount(self: *Self) u64 {
+        return self.count;
+    }
+};
+
+/// Dataset Reader (for verification/debugging)
+pub const DatasetReader = struct {
+    file: std.fs.File,
+    total_tokens: u64,
+    vocab_size: u32,
+    version: u32,
+
+    const Self = @This();
+
+    pub fn init(path: []const u8) !Self {
+        const file = try std.fs.cwd().openFile(path, .{});
+        errdefer file.close();
+
+        var header: [HEADER_SIZE]u8 = undefined;
+        const bytes_read = try file.readAll(&header);
+        if (bytes_read != HEADER_SIZE) {
+            return error.InvalidHeader;
+        }
+
+        // Verify magic
+        if (!std.mem.eql(u8, header[0..4], MAGIC)) {
+            log.err("Invalid magic: expected ZELL", .{});
+            return error.InvalidMagic;
+        }
+
+        const version = std.mem.readInt(u32, header[4..8], .little);
+        if (version != VERSION) {
+            log.warn("Version mismatch: file={d}, expected={d}", .{ version, VERSION });
+        }
+
+        const total_tokens = std.mem.readInt(u64, header[8..16], .little);
+        const vocab_size = std.mem.readInt(u32, header[16..20], .little);
+
+        return Self{
+            .file = file,
+            .total_tokens = total_tokens,
+            .vocab_size = vocab_size,
+            .version = version,
+        };
+    }
+
+    /// Read a batch of tokens
+    pub fn readBatch(self: *Self, allocator: std.mem.Allocator, count: usize) ![]u16 {
+        const tokens = try allocator.alloc(u16, count);
+        errdefer allocator.free(tokens);
+
+        const bytes = std.mem.sliceAsBytes(tokens);
+        const bytes_read = try self.file.readAll(bytes);
+        const tokens_read = bytes_read / 2;
+
+        if (tokens_read < count) {
+            // Return partial read
+            return allocator.realloc(tokens, tokens_read);
+        }
+
+        return tokens;
+    }
+
+    /// Seek to a specific token index
+    pub fn seekToToken(self: *Self, index: u64) !void {
+        const offset = HEADER_SIZE + (index * 2);
+        try self.file.seekTo(offset);
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.file.close();
+    }
+};
+
+// =============================================================================
+// Karpathy-compatible Binary Format
+// =============================================================================
+
+/// Reader for Karpathy's pre-tokenized .bin format
+/// Format: Just raw u16 tokens, no header
+pub const KarpathyBinReader = struct {
+    file: std.fs.File,
+    total_tokens: u64,
+
+    pub fn init(path: []const u8) !KarpathyBinReader {
+        const file = try std.fs.cwd().openFile(path, .{});
+        const stat = try file.stat();
+
+        return .{
+            .file = file,
+            .total_tokens = stat.size / 2, // u16 = 2 bytes
+        };
+    }
+
+    /// Convert Karpathy .bin to ZELL format
+    pub fn convertToZell(self: *KarpathyBinReader, output_path: []const u8, vocab_size: u32) !void {
+        var writer = try DatasetWriter.init(output_path, vocab_size);
+        errdefer writer.file.close();
+
+        var buffer: [8192]u16 = undefined;
+        const bytes = std.mem.sliceAsBytes(&buffer);
+
+        while (true) {
+            const read = try self.file.read(bytes);
+            if (read == 0) break;
+
+            const tokens = buffer[0 .. read / 2];
+            try writer.appendU16(tokens);
+        }
+
+        try writer.finish();
+    }
+
+    pub fn deinit(self: *KarpathyBinReader) void {
+        self.file.close();
+    }
+};
+
+// =============================================================================
+// Shard Writer (for large datasets)
+// =============================================================================
+
+/// Sharded dataset writer for datasets larger than memory
+pub const ShardedWriter = struct {
+    allocator: std.mem.Allocator,
+    base_path: []const u8,
+    vocab_size: u32,
+    tokens_per_shard: u64,
+
+    current_shard: u32 = 0,
+    current_writer: ?DatasetWriter = null,
+    shard_token_count: u64 = 0,
+
+    const Self = @This();
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        base_path: []const u8,
+        vocab_size: u32,
+        tokens_per_shard: u64,
+    ) Self {
+        return .{
+            .allocator = allocator,
+            .base_path = base_path,
+            .vocab_size = vocab_size,
+            .tokens_per_shard = tokens_per_shard,
+        };
+    }
+
+    pub fn append(self: *Self, tokens: []const u32) !void {
+        for (tokens) |token| {
+            try self.appendOne(token);
+        }
+    }
+
+    pub fn appendOne(self: *Self, token: u32) !void {
+        // Create new shard if needed
+        if (self.current_writer == null) {
+            try self.createNewShard();
+        }
+
+        try self.current_writer.?.appendOne(token);
+        self.shard_token_count += 1;
+
+        // Check if shard is full
+        if (self.shard_token_count >= self.tokens_per_shard) {
+            try self.current_writer.?.finish();
+            self.current_writer = null;
+            self.shard_token_count = 0;
+            self.current_shard += 1;
+        }
+    }
+
+    fn createNewShard(self: *Self) !void {
+        const shard_path = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}.{d:0>5}.zell",
+            .{ self.base_path, self.current_shard },
+        );
+        defer self.allocator.free(shard_path);
+
+        self.current_writer = try DatasetWriter.init(shard_path, self.vocab_size);
+        log.info("Created shard {d}", .{self.current_shard});
+    }
+
+    pub fn finish(self: *Self) !void {
+        if (self.current_writer) |*writer| {
+            try writer.finish();
+            self.current_writer = null;
+        }
+        log.info("Sharded dataset complete: {d} shards", .{self.current_shard + 1});
+    }
+};
