+    keep_last_n: u32,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, base_path: []const u8, keep_last_n: u32) !Self {
+        // Create checkpoint directory
+        std.fs.cwd().makePath(base_path) catch |err| {
+            if (err != error.PathAlreadyExists) return err;
+        };
+
+        return Self{
+            .allocator = allocator,
+            .base_path = base_path,
+            .keep_last_n = keep_last_n,
+        };
+    }
+
+    pub fn save(self: *Self, trainer: *MetalTrainer) !void {
+        const path = try std.fmt.allocPrint(self.allocator, "{s}/ckpt_{d:0>8}.bin", .{
+            self.base_path,
+            trainer.step,
+        });
+        defer self.allocator.free(path);
+
+        const log_ckpt = std.log.scoped(.checkpoint);
+        log_ckpt.info("Saving checkpoint to {s} (step={}, tokens={})", .{
+            path,
+            trainer.step,
+            trainer.total_tokens,
+        });
+
+        // For the standalone build, just save basic metadata
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        // Build header buffer
+        var header: [32]u8 = undefined;
+        @memcpy(header[0..8], "ZELLCKPT");
+        std.mem.writeInt(u64, header[8..16], 1, .little); // Version
+        std.mem.writeInt(u64, header[16..24], trainer.step, .little);
+        std.mem.writeInt(u64, header[24..32], trainer.total_tokens, .little);
+
+        try file.writeAll(&header);
+
+        log_ckpt.info("Checkpoint saved", .{});
+    }
+
+    pub fn loadLatest(self: *Self, trainer: *MetalTrainer) !bool {
+        // Find latest checkpoint
+        var dir = std.fs.cwd().openDir(self.base_path, .{ .iterate = true }) catch {
+            return false;
+        };
+        defer dir.close();
+
+        var latest_step: u64 = 0;
+        var latest_path: ?[]const u8 = null;
+
+        var iter = dir.iterate();
+        while (try iter.next()) |entry| {
+            if (entry.kind != .file) continue;
+            if (!std.mem.startsWith(u8, entry.name, "ckpt_")) continue;
+            if (!std.mem.endsWith(u8, entry.name, ".bin")) continue;
+
+            const step_str = entry.name[5 .. entry.name.len - 4];
+            const step = std.fmt.parseInt(u64, step_str, 10) catch continue;
+
+            if (step > latest_step) {
+                latest_step = step;
+                if (latest_path) |p| self.allocator.free(p);
+                latest_path = try std.fmt.allocPrint(self.allocator, "{s}/{s}", .{
+                    self.base_path,
+                    entry.name,
+                });
+            }
+        }
+
+        if (latest_path) |path| {
+            defer self.allocator.free(path);
+
+            const file = std.fs.cwd().openFile(path, .{}) catch return false;
+            defer file.close();
+
+            // Read entire header (magic + version + step + tokens + epoch + accum_step = 32 bytes)
+            var header: [32]u8 = undefined;
+            const bytes_read = file.readAll(&header) catch return false;
+            if (bytes_read < 32) return false;
+
+            // Verify magic
+            if (!std.mem.eql(u8, header[0..8], "ZELLCKPT")) return false;
+
+            // Parse fields
+            // _ = std.mem.readInt(u64, header[8..16], .little); // Version (skip)
+            trainer.step = std.mem.readInt(u64, header[16..24], .little);
+            trainer.total_tokens = std.mem.readInt(u64, header[24..32], .little);
+            // epoch and accum_step would be in additional bytes
+
+            const log_ckpt = std.log.scoped(.checkpoint);
+            log_ckpt.info("Loaded checkpoint: step={}, tokens={}", .{
+                trainer.step,
+                trainer.total_tokens,
+            });
+            return true;
+        }
+
+        return false;
+    }
+
+    pub fn deinit(self: *Self) void {
+        _ = self;
+    }
+};

