+//! GPT-2 BPE Tokenizer
+//!
+//! Loads vocab.json and merges.txt to tokenize text into GPT-2 token IDs.
+//! Also supports loading pre-tokenized binary files for faster data loading.
+
+const std = @import("std");
+const Allocator = std.mem.Allocator;
+const log = std.log.scoped(.tokenizer);
+
+/// GPT-2 BPE Tokenizer
+pub const Tokenizer = struct {
+    allocator: Allocator,
+
+    // Token string -> ID mapping
+    encoder: std.StringHashMap(u32),
+
+    // ID -> Token string mapping (for decoding)
+    decoder: std.AutoHashMap(u32, []const u8),
+
+    // Merge rules: "token1 token2" -> merge rank (lower = higher priority)
+    merges: std.StringHashMap(u32),
+
+    // Special tokens
+    eot_token: u32 = 50256, // <|endoftext|>
+
+    // Byte encoder/decoder for handling arbitrary bytes
+    byte_encoder: [256][]const u8,
+    byte_decoder: std.StringHashMap(u8),
+
+    const Self = @This();
+
+    /// Initialize tokenizer from vocab.json and merges.txt
+    pub fn init(allocator: Allocator, vocab_path: []const u8, merges_path: []const u8) !Self {
+        var self = Self{
+            .allocator = allocator,
+            .encoder = std.StringHashMap(u32).init(allocator),
+            .decoder = std.AutoHashMap(u32, []const u8).init(allocator),
+            .merges = std.StringHashMap(u32).init(allocator),
+            .byte_encoder = undefined,
+            .byte_decoder = std.StringHashMap(u8).init(allocator),
+        };
+
+        // Initialize byte encoder (GPT-2 style byte-to-unicode mapping)
+        try self.initByteEncoder();
+
+        // Load vocabulary
+        try self.loadVocab(vocab_path);
+
+        // Load merge rules
+        try self.loadMerges(merges_path);
+
+        log.info("Tokenizer loaded: {} tokens, {} merges", .{
+            self.encoder.count(),
+            self.merges.count(),
+        });
+
+        return self;
+    }
+
+    /// Initialize the byte encoder mapping
+    /// GPT-2 maps bytes to unicode characters to avoid control characters
+    fn initByteEncoder(self: *Self) !void {
+        // GPT-2 byte encoder: maps bytes to printable unicode
+        // Bytes 33-126, 161-172, 174-255 map to themselves
+        // Other bytes map to 256+ range
+
+        var n: u16 = 0;
+        for (0..256) |i| {
+            const b: u8 = @intCast(i);
+            if ((b >= 33 and b <= 126) or (b >= 161 and b <= 172) or (b >= 174 and b <= 255)) {
+                // Map to itself as a string
+                const s = try self.allocator.alloc(u8, 1);
+                s[0] = b;
+                self.byte_encoder[i] = s;
+                try self.byte_decoder.put(s, b);
+            } else {
+                // Map to 256 + n range (unicode private area simulation)
+                // We use a 2-byte UTF-8 encoding for values 256+
+                const unicode_val: u16 = 256 + n;
+                if (unicode_val < 0x80) {
+                    const s = try self.allocator.alloc(u8, 1);
+                    s[0] = @intCast(unicode_val);
+                    self.byte_encoder[i] = s;
+                    try self.byte_decoder.put(s, b);
+                } else if (unicode_val < 0x800) {
+                    const s = try self.allocator.alloc(u8, 2);
+                    s[0] = @intCast(0xC0 | (unicode_val >> 6));
+                    s[1] = @intCast(0x80 | (unicode_val & 0x3F));
+                    self.byte_encoder[i] = s;
+                    try self.byte_decoder.put(s, b);
+                } else {
+                    const s = try self.allocator.alloc(u8, 3);
+                    s[0] = @intCast(0xE0 | (unicode_val >> 12));
+                    s[1] = @intCast(0x80 | ((unicode_val >> 6) & 0x3F));
+                    s[2] = @intCast(0x80 | (unicode_val & 0x3F));
+                    self.byte_encoder[i] = s;
+                    try self.byte_decoder.put(s, b);
+                }
+                n += 1;
+            }
+        }
+    }
+
+    /// Load vocabulary from vocab.json
+    fn loadVocab(self: *Self, path: []const u8) !void {
+        const file = std.fs.cwd().openFile(path, .{}) catch |err| {
+            log.err("Failed to open vocab file: {s}", .{path});
+            return err;
+        };
+        defer file.close();
+
+        const content = try file.readToEndAlloc(self.allocator, 50 * 1024 * 1024); // 50MB limit
+        defer self.allocator.free(content);
+
+        var parsed = try std.json.parseFromSlice(std.json.Value, self.allocator, content, .{});
+        defer parsed.deinit();
+
+        var iter = parsed.value.object.iterator();
+        while (iter.next()) |entry| {
+            const key = try self.allocator.dupe(u8, entry.key_ptr.*);
+            const id: u32 = @intCast(entry.value_ptr.integer);
+
+            try self.encoder.put(key, id);
+            try self.decoder.put(id, key);
+
+            // Track special token
+            if (std.mem.eql(u8, key, "<|endoftext|>")) {
+                self.eot_token = id;
+            }
+        }
+    }
+
+    /// Load merge rules from merges.txt
+    fn loadMerges(self: *Self, path: []const u8) !void {
+        const file = std.fs.cwd().openFile(path, .{}) catch |err| {
+            log.err("Failed to open merges file: {s}", .{path});
+            return err;
+        };
+        defer file.close();
+
+        const content = try file.readToEndAlloc(self.allocator, 50 * 1024 * 1024);
+        defer self.allocator.free(content);
+
+        var lines = std.mem.splitScalar(u8, content, '\n');
+        var rank: u32 = 0;
+
+        // Skip first line (header: #version: ...)
+        _ = lines.next();
+
+        while (lines.next()) |line| {
+            if (line.len == 0) continue;
+
+            // Each line is "token1 token2"
+            const key = try self.allocator.dupe(u8, line);
+            try self.merges.put(key, rank);
+            rank += 1;
+        }
+    }
+
+    /// Encode text to token IDs
+    pub fn encode(self: *Self, text: []const u8) ![]u32 {
+        var tokens = std.ArrayList(u32).init(self.allocator);
+        errdefer tokens.deinit();
+
+        // Split text into words using GPT-2 regex pattern (simplified)
+        // Full pattern: 's|'t|'re|'ve|'m|'ll|'d| ?\p{L}+| ?\p{N}+| ?[^\s\p{L}\p{N}]+|\s+(?!\S)|\s+
+        // For MVP, we use simple word splitting
+
+        var i: usize = 0;
+        while (i < text.len) {
+            // Find word boundary
+            const word_start = i;
+            var word_end = i;
+
+            // Handle leading space
+            if (text[i] == ' ' and i + 1 < text.len and text[i + 1] != ' ') {
+                word_end = i + 1;
+                // Continue to find the rest of the word
+                while (word_end < text.len and text[word_end] != ' ' and text[word_end] != '\n') {
+                    word_end += 1;
+                }
+            } else if (text[i] == '\n') {
+                // Newline as separate token
+                word_end = i + 1;
+            } else {
+                // Regular word
+                while (word_end < text.len and text[word_end] != ' ' and text[word_end] != '\n') {
+                    word_end += 1;
+                }
+            }
+
+            if (word_end > word_start) {
+                const word = text[word_start..word_end];
+                const word_tokens = try self.bpe(word);
+                defer self.allocator.free(word_tokens);
+
+                for (word_tokens) |t| {
+                    try tokens.append(t);
+                }
+            }
+
+            i = word_end;
+            if (i == word_start) i += 1; // Avoid infinite loop
+        }
+
+        return tokens.toOwnedSlice();
+    }
+
+    /// Apply BPE to a single word
+    fn bpe(self: *Self, word: []const u8) ![]u32 {
+        // Convert bytes to GPT-2 unicode tokens
+        var parts = std.ArrayList([]const u8).init(self.allocator);
+        defer parts.deinit();
+
+        for (word) |b| {
+            try parts.append(self.byte_encoder[b]);
+        }
+
+        // Iteratively merge pairs until no more merges possible
+        while (parts.items.len > 1) {
+            // Find the pair with lowest merge rank
+            var best_rank: ?u32 = null;
+            var best_idx: ?usize = null;
+
+            for (0..parts.items.len - 1) |idx| {
+                // Create pair key
+                const pair_key = try std.fmt.allocPrint(self.allocator, "{s} {s}", .{
+                    parts.items[idx],
+                    parts.items[idx + 1],
+                });
+                defer self.allocator.free(pair_key);
+
+                if (self.merges.get(pair_key)) |rank| {
+                    if (best_rank == null or rank < best_rank.?) {
+                        best_rank = rank;
+                        best_idx = idx;
+                    }
+                }
+            }
+
+            if (best_idx == null) break; // No more merges
+
+            // Merge the pair
+            const idx = best_idx.?;
+            const merged = try std.fmt.allocPrint(self.allocator, "{s}{s}", .{
+                parts.items[idx],
+                parts.items[idx + 1],
+            });
+
+            // Replace in parts list
+            self.allocator.free(@constCast(parts.items[idx]));
+            parts.items[idx] = merged;
+            _ = parts.orderedRemove(idx + 1);
+        }
+
+        // Convert final tokens to IDs
+        var result = try self.allocator.alloc(u32, parts.items.len);
+        for (parts.items, 0..) |token, idx| {
+            if (self.encoder.get(token)) |id| {
+                result[idx] = id;
+            } else {
+                // Unknown token - use byte fallback or EOT
+                result[idx] = self.eot_token;
+                log.warn("Unknown token: {s}", .{token});
+            }
+        }
+
+        return result;
+    }
+
+    /// Decode token IDs back to text
+    pub fn decode(self: *Self, tokens: []const u32) ![]u8 {
+        var result = std.ArrayList(u8).init(self.allocator);
+        errdefer result.deinit();
+
+        for (tokens) |id| {
+            if (self.decoder.get(id)) |token_str| {
+                // Convert GPT-2 unicode back to bytes
+                var i: usize = 0;
+                while (i < token_str.len) {
+                    // Try to find in byte_decoder
+                    var found = false;
+                    for (1..@min(4, token_str.len - i + 1)) |len| {
+                        if (self.byte_decoder.get(token_str[i .. i + len])) |b| {
+                            try result.append(b);
+                            i += len;
+                            found = true;
+                            break;
+                        }
+                    }
+                    if (!found) {
+                        // Fallback: append as-is
+                        try result.append(token_str[i]);
+                        i += 1;
+                    }
+                }
+            }
+        }
+
+        return result.toOwnedSlice();
+    }
+
+    /// Get vocabulary size
+    pub fn vocabSize(self: *Self) u32 {
+        return @intCast(self.encoder.count());
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Free encoder keys
+        var enc_iter = self.encoder.keyIterator();
+        while (enc_iter.next()) |key| {
+            self.allocator.free(key.*);
+        }
+        self.encoder.deinit();
+        self.decoder.deinit();
+
+        // Free merge keys
+        var merge_iter = self.merges.keyIterator();
+        while (merge_iter.next()) |key| {
+            self.allocator.free(key.*);
+        }
+        self.merges.deinit();
+
+        // Free byte encoder
+        for (&self.byte_encoder) |s| {
+            if (s.len > 0) self.allocator.free(s);
+        }
+        self.byte_decoder.deinit();
+    }
+};
