+/// Full model gradients (FP32 for numerical stability during accumulation)
+pub const GPT2Gradients = struct {
+    allocator: std.mem.Allocator,
+    config: GPT2Config,
+
+    // Embedding gradients
+    wte: metal.MetalBuffer, // [vocab, embd] FP32
+    wpe: metal.MetalBuffer, // [ctx, embd] FP32
+
+    // Layer gradients
+    layers: []LayerGradients,
+
+    // Final LayerNorm
+    ln_f_weight: metal.MetalBuffer,
+    ln_f_bias: metal.MetalBuffer,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, engine: *metal.MetalEngine, config: GPT2Config) !Self {
+        const log = std.log.scoped(.gpt2_gradients);
+        log.info("Allocating gradient buffers (FP32)...", .{});
+
+        const embd: u64 = config.n_embd;
+        const vocab: u64 = config.n_vocab;
+        const ctx: u64 = config.n_ctx;
+
+        // Embedding gradients (FP32)
+        const wte = try engine.createBuffer(f32, vocab * embd);
+        const wpe = try engine.createBuffer(f32, ctx * embd);
+
+        // Layer gradients
+        var layers = try allocator.alloc(LayerGradients, config.n_layer);
+        for (0..config.n_layer) |i| {
+            layers[i] = try Self.allocateLayerGradients(engine, config);
+        }
+
+        // Final norm gradients
+        const ln_f_weight = try engine.createBuffer(f32, embd);
+        const ln_f_bias = try engine.createBuffer(f32, embd);
+
+        return Self{
+            .allocator = allocator,
+            .config = config,
+            .wte = wte,
+            .wpe = wpe,
+            .layers = layers,
+            .ln_f_weight = ln_f_weight,
+            .ln_f_bias = ln_f_bias,
+        };
+    }
+
+    fn allocateLayerGradients(engine: *metal.MetalEngine, config: GPT2Config) !LayerGradients {
+        const embd: u64 = config.n_embd;
+
+        return LayerGradients{
+            .ln_1_weight = try engine.createBuffer(f32, embd),
+            .ln_1_bias = try engine.createBuffer(f32, embd),
+            .c_attn_weight = try engine.createBuffer(f32, embd * 3 * embd),
+            .c_attn_bias = try engine.createBuffer(f32, 3 * embd),
+            .c_proj_weight = try engine.createBuffer(f32, embd * embd),
+            .c_proj_bias = try engine.createBuffer(f32, embd),
+            .ln_2_weight = try engine.createBuffer(f32, embd),
+            .ln_2_bias = try engine.createBuffer(f32, embd),
+            .c_fc_weight = try engine.createBuffer(f32, embd * 4 * embd),
+            .c_fc_bias = try engine.createBuffer(f32, 4 * embd),
+            .c_proj_mlp_weight = try engine.createBuffer(f32, 4 * embd * embd),
+            .c_proj_mlp_bias = try engine.createBuffer(f32, embd),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        metal.MetalEngine.releaseBuffer(self.wte);
+        metal.MetalEngine.releaseBuffer(self.wpe);
+        metal.MetalEngine.releaseBuffer(self.ln_f_weight);
+        metal.MetalEngine.releaseBuffer(self.ln_f_bias);
+
+        for (self.layers) |*layer| {
+            Self.releaseLayerGradients(layer);
+        }
+        self.allocator.free(self.layers);
+    }
+
+    fn releaseLayerGradients(layer: *LayerGradients) void {
+        metal.MetalEngine.releaseBuffer(layer.ln_1_weight);
+        metal.MetalEngine.releaseBuffer(layer.ln_1_bias);
+        metal.MetalEngine.releaseBuffer(layer.c_attn_weight);
+        metal.MetalEngine.releaseBuffer(layer.c_attn_bias);
+        metal.MetalEngine.releaseBuffer(layer.c_proj_weight);
+        metal.MetalEngine.releaseBuffer(layer.c_proj_bias);
+        metal.MetalEngine.releaseBuffer(layer.ln_2_weight);
+        metal.MetalEngine.releaseBuffer(layer.ln_2_bias);
+        metal.MetalEngine.releaseBuffer(layer.c_fc_weight);
+        metal.MetalEngine.releaseBuffer(layer.c_fc_bias);
+        metal.MetalEngine.releaseBuffer(layer.c_proj_mlp_weight);
+        metal.MetalEngine.releaseBuffer(layer.c_proj_mlp_bias);
+    }
+
+    /// Zero all gradient buffers (call before each backward pass)
+    pub fn zero(self: *Self) void {
+        zeroBufferF32(self.wte);
+        zeroBufferF32(self.wpe);
+        zeroBufferF32(self.ln_f_weight);
+        zeroBufferF32(self.ln_f_bias);
