+            zeroBufferF32(layer.c_fc_weight);
+            zeroBufferF32(layer.c_fc_bias);
+            zeroBufferF32(layer.c_proj_mlp_weight);
+            zeroBufferF32(layer.c_proj_mlp_bias);
+        }
+    }
