+/// Full AdamW optimizer state (FP32)
+pub const AdamWState = struct {
+    allocator: std.mem.Allocator,
+
+    // Embedding optimizer state
+    wte_m: metal.MetalBuffer,
+    wte_v: metal.MetalBuffer,
+    wpe_m: metal.MetalBuffer,
