+        const ln_f_weight_v = try engine.createBuffer(f32, embd);
+        const ln_f_bias_m = try engine.createBuffer(f32, embd);
+        const ln_f_bias_v = try engine.createBuffer(f32, embd);
+
+        zeroBufferF32(ln_f_weight_m);
+        zeroBufferF32(ln_f_weight_v);
+        zeroBufferF32(ln_f_bias_m);
