+    fn allocateLayerState(engine: *metal.MetalEngine, config: GPT2Config) !LayerOptimizerState {
+        const embd: u64 = config.n_embd;
+
+        var state: LayerOptimizerState = undefined;
+
+        // Allocate all m and v buffers
+        state.ln_1_weight_m = try engine.createBuffer(f32, embd);
+        state.ln_1_weight_v = try engine.createBuffer(f32, embd);
+        state.ln_1_bias_m = try engine.createBuffer(f32, embd);
+        state.ln_1_bias_v = try engine.createBuffer(f32, embd);
+
+        state.c_attn_weight_m = try engine.createBuffer(f32, embd * 3 * embd);
+        state.c_attn_weight_v = try engine.createBuffer(f32, embd * 3 * embd);
+        state.c_attn_bias_m = try engine.createBuffer(f32, 3 * embd);
+        state.c_attn_bias_v = try engine.createBuffer(f32, 3 * embd);
+
+        state.c_proj_weight_m = try engine.createBuffer(f32, embd * embd);
+        state.c_proj_weight_v = try engine.createBuffer(f32, embd * embd);
+        state.c_proj_bias_m = try engine.createBuffer(f32, embd);
+        state.c_proj_bias_v = try engine.createBuffer(f32, embd);
+
+        state.ln_2_weight_m = try engine.createBuffer(f32, embd);
+        state.ln_2_weight_v = try engine.createBuffer(f32, embd);
+        state.ln_2_bias_m = try engine.createBuffer(f32, embd);
+        state.ln_2_bias_v = try engine.createBuffer(f32, embd);
+
+        state.c_fc_weight_m = try engine.createBuffer(f32, embd * 4 * embd);
+        state.c_fc_weight_v = try engine.createBuffer(f32, embd * 4 * embd);
+        state.c_fc_bias_m = try engine.createBuffer(f32, 4 * embd);
+        state.c_fc_bias_v = try engine.createBuffer(f32, 4 * embd);
+
+        state.c_proj_mlp_weight_m = try engine.createBuffer(f32, 4 * embd * embd);
+        state.c_proj_mlp_weight_v = try engine.createBuffer(f32, 4 * embd * embd);
+        state.c_proj_mlp_bias_m = try engine.createBuffer(f32, embd);
+        state.c_proj_mlp_bias_v = try engine.createBuffer(f32, embd);
+
+        // Zero initialize all
+        Self.zeroLayerState(&state);
+
+        return state;
+    }
+
+    fn zeroLayerState(state: *LayerOptimizerState) void {
+        zeroBufferF32(state.ln_1_weight_m);
+        zeroBufferF32(state.ln_1_weight_v);
+        zeroBufferF32(state.ln_1_bias_m);
+        zeroBufferF32(state.ln_1_bias_v);
+        zeroBufferF32(state.c_attn_weight_m);
