+/// Metal Trainer for GPT-2 from scratch
+pub const MetalTrainer = struct {
+    allocator: std.mem.Allocator,
+    config: GPT2Config,
+    engine: *metal.MetalEngine,
+    model: GPT2Model,
+    activations: ActivationBuffers,
+
+    // Gradient structures
+    grads: GPT2Gradients,
+    grad_acts: GradientActivations,
+
+    // Optimizer state (FP32 for numerical stability)
+    opt_state: AdamWState,
+
+    // Training state
+    step: u64 = 0,
+    accum_step: u32 = 0,
+    total_tokens: u64 = 0,
+
+    // Input buffer
+    input_tokens: metal.MetalBuffer, // [batch, seq] u32
+    target_tokens: metal.MetalBuffer, // [batch, seq] u32
+    loss_buffer: metal.MetalBuffer, // [batch * seq] f32
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, engine: *metal.MetalEngine, config: GPT2Config) !Self {
+        const log = std.log.scoped(.metal_trainer);
+        log.info("Initializing Metal Trainer...", .{});
+
+        // Initialize model
+        var model = try GPT2Model.init(allocator, engine, config);
+        errdefer model.deinit();
+
+        // Initialize activations
+        var activations = try ActivationBuffers.init(engine, config);
+        errdefer activations.deinit();
+
+        // Initialize gradients
+        var grads = try GPT2Gradients.init(allocator, engine, config);
+        errdefer grads.deinit();
+
+        var grad_acts = try GradientActivations.init(engine, config);
+        errdefer grad_acts.deinit();
+
+        // Initialize optimizer state
+        var opt_state = try AdamWState.init(allocator, engine, config);
+        errdefer opt_state.deinit();
+
+        const batch_seq: u64 = config.batch_size * config.n_ctx;
+
+        // Input/target buffers
+        const input_tokens = try engine.createBuffer(u32, batch_seq);
+        const target_tokens = try engine.createBuffer(u32, batch_seq);
+        const loss_buffer = try engine.createBuffer(f32, batch_seq);
+
+        log.info("Trainer initialized (model={d:.1}MB, grads={d:.1}MB, opt={d:.1}MB)", .{
+            @as(f64, @floatFromInt(config.modelSizeBytes())) / (1024.0 * 1024.0),
+            @as(f64, @floatFromInt(config.paramCount() * 4)) / (1024.0 * 1024.0), // FP32 grads
+            @as(f64, @floatFromInt(config.paramCount() * 8)) / (1024.0 * 1024.0), // 2x FP32 for m,v
+        });
+
+        return Self{
+            .allocator = allocator,
+            .config = config,
+            .engine = engine,
+            .model = model,
+            .activations = activations,
+            .grads = grads,
+            .grad_acts = grad_acts,
+            .opt_state = opt_state,
+            .input_tokens = input_tokens,
+            .target_tokens = target_tokens,
+            .loss_buffer = loss_buffer,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.model.deinit();
+        self.activations.deinit();
+        self.grads.deinit();
+        self.grad_acts.deinit();
+        self.opt_state.deinit();
+
+        metal.MetalEngine.releaseBuffer(self.input_tokens);
+        metal.MetalEngine.releaseBuffer(self.target_tokens);
+        metal.MetalEngine.releaseBuffer(self.loss_buffer);
+    }
+
+    /// Run forward pass, returns loss
+    pub fn forward(self: *Self, tokens: []const u32) !f32 {
+        const config = self.config;
+        const batch_seq = config.batch_size * config.n_ctx;
+
+        // Copy input tokens to GPU buffer
+        const input_slice = self.input_tokens.asSlice(u32);
+        @memcpy(input_slice[0..tokens.len], tokens);
+
+        // Shift tokens for targets (next token prediction)
+        const target_slice = self.target_tokens.asSlice(u32);
+        @memcpy(target_slice[0 .. tokens.len - 1], tokens[1..]);
+        target_slice[tokens.len - 1] = 0; // Pad last position
+
+        // === Step 1: Embedding Lookup ===
+        // embedded = wte[tokens] + wpe[positions]
+        const embed_params = metal.EmbedParams{
+            .batch_size = config.batch_size,
+            .seq_len = config.n_ctx,
+            .n_vocab = config.n_vocab,
+            .n_embd = config.n_embd,
+        };
+
+        try self.engine.dispatchThreads(
+            "embed_forward_bf16",
+            &[_]metal.MetalBuffer{
+                self.input_tokens,
+                self.model.wte,
+                self.model.wpe,
+                self.activations.embedded,
+            },
+            &embed_params,
+            @sizeOf(metal.EmbedParams),
+            config.n_embd,
+            config.n_ctx,
+            config.batch_size,
+        );
+
+        // Copy embedded to hidden_states for first layer
+        try self.copyBuffer(self.activations.embedded, self.activations.hidden_states);
+
+        // === Step 2: Transformer Layers ===
+        for (self.model.layers, 0..) |layer, layer_idx| {
+            try self.transformerLayerForward(layer, layer_idx);
+        }
+
+        // === Step 3: Final LayerNorm ===
+        const ln_params = metal.LayerNormParams{
+            .batch_size = @intCast(batch_seq),
+            .hidden_size = config.n_embd,
+            .eps = 1e-5,
+        };
+
+        try self.engine.dispatchThreads(
+            "layernorm_forward_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.hidden_states,
+                self.model.ln_f_weight,
+                self.model.ln_f_bias,
+                self.activations.ln_out,
+                self.activations.ln_mean,
+                self.activations.ln_rstd,
+            },
+            &ln_params,
+            @sizeOf(metal.LayerNormParams),
+            batch_seq,
+            1,
+            1,
+        );
+
+        // === Step 4: LM Head (tied weights with wte) ===
+        // logits = ln_out @ wte.T
+        const matmul_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_vocab,
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.ln_out,
+                self.model.wte, // Transposed in kernel
+                self.activations.logits,
+            },
+            &matmul_params,
+            @sizeOf(metal.MatMulParams),
+            config.n_vocab,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // === Step 5: Cross Entropy Loss ===
+        const vocab_size: u32 = config.n_vocab;
+        try self.engine.dispatchThreads(
+            "cross_entropy_forward",
+            &[_]metal.MetalBuffer{
+                self.activations.logits,
+                self.target_tokens,
+                self.loss_buffer,
+            },
+            &vocab_size,
+            @sizeOf(u32),
+            batch_seq,
+            1,
+            1,
+        );
+
+        // Sum losses on CPU (small reduction)
+        const losses = self.loss_buffer.asSlice(f32);
+        var total_loss: f32 = 0.0;
+        for (losses[0..batch_seq]) |l| {
+            total_loss += l;
+        }
+
+        return total_loss / @as(f32, @floatFromInt(batch_seq));
+    }
+
+    fn transformerLayerForward(self: *Self, layer: TransformerLayer, layer_idx: usize) !void {
+        _ = layer_idx;
+        const config = self.config;
+        const batch_seq: u64 = config.batch_size * config.n_ctx;
+        const embd: u64 = config.n_embd;
+
+        // Save residual
+        try self.copyBuffer(self.activations.hidden_states, self.activations.residual);
+
+        // === LayerNorm 1 ===
+        const ln_params = metal.LayerNormParams{
+            .batch_size = @intCast(batch_seq),
+            .hidden_size = config.n_embd,
+            .eps = 1e-5,
+        };
+
+        try self.engine.dispatchThreads(
+            "layernorm_forward_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.hidden_states,
+                layer.ln_1_weight,
+                layer.ln_1_bias,
+                self.activations.ln_out,
+                self.activations.ln_mean,
+                self.activations.ln_rstd,
+            },
+            &ln_params,
+            @sizeOf(metal.LayerNormParams),
+            batch_seq,
+            1,
+            1,
+        );
+
+        // === Attention QKV ===
+        const attn_params = metal.AttentionParams{
+            .batch_size = config.batch_size,
+            .seq_len = config.n_ctx,
+            .n_heads = config.n_head,
+            .head_dim = @intCast(embd / config.n_head),
+            .scale = 1.0 / @sqrt(@as(f32, @floatFromInt(embd / config.n_head))),
+        };
+
+        // QKV projection
+        const qkv_matmul = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = @intCast(3 * embd),
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.ln_out,
+                layer.c_attn_weight,
+                self.activations.qkv,
+            },
+            &qkv_matmul,
+            @sizeOf(metal.MatMulParams),
+            3 * embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Add bias (simplified - would use fused kernel in optimized version)
+        // For MVP, bias addition is handled by separate kernel or fused matmul
+
+        // === Attention Scores & Softmax ===
+        // This is simplified - full implementation needs proper attention mechanism
+        // scores = Q @ K.T / sqrt(d_k), then softmax with causal mask
+
+        const softmax_params = metal.SoftmaxParams{
+            .batch_size = config.batch_size * config.n_head,
+            .seq_len = config.n_ctx,
+        };
+
+        try self.engine.dispatchThreads(
+            "softmax_bf16",
+            &[_]metal.MetalBuffer{self.activations.attn_scores},
+            &softmax_params,
+            @sizeOf(metal.SoftmaxParams),
+            config.n_ctx,
+            config.batch_size * config.n_head,
+            1,
+        );
+
+        // === Attention Output Projection ===
+        const proj_matmul = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_embd,
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.attn_out,
+                layer.c_proj_weight,
+                self.activations.hidden_states,
+            },
+            &proj_matmul,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Add residual
+        try self.addBuffers(self.activations.residual, self.activations.hidden_states);
+
+        // Save residual for MLP
+        try self.copyBuffer(self.activations.hidden_states, self.activations.residual);
+
+        // === LayerNorm 2 ===
+        try self.engine.dispatchThreads(
+            "layernorm_forward_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.hidden_states,
+                layer.ln_2_weight,
+                layer.ln_2_bias,
+                self.activations.ln_out,
+                self.activations.ln_mean,
+                self.activations.ln_rstd,
+            },
+            &ln_params,
+            @sizeOf(metal.LayerNormParams),
+            batch_seq,
+            1,
+            1,
+        );
+
+        // === MLP: FC (expand) ===
+        const fc_matmul = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = @intCast(4 * embd),
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_bf16_bias_gelu",
+            &[_]metal.MetalBuffer{
+                self.activations.ln_out,
+                layer.c_fc_weight,
+                layer.c_fc_bias,
+                self.activations.mlp_hidden,
+            },
+            &fc_matmul,
+            @sizeOf(metal.MatMulParams),
+            4 * embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // === MLP: Projection (contract) ===
+        const proj_mlp_matmul = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_embd,
+            .K = @intCast(4 * embd),
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_bf16",
+            &[_]metal.MetalBuffer{
+                self.activations.mlp_hidden,
+                layer.c_proj_mlp_weight,
+                self.activations.hidden_states,
+            },
+            &proj_mlp_matmul,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Add residual
+        try self.addBuffers(self.activations.residual, self.activations.hidden_states);
+    }
+
+    fn copyBuffer(self: *Self, src: metal.MetalBuffer, dst: metal.MetalBuffer) !void {
+        const count: u32 = @intCast(src.element_count);
+        try self.engine.dispatchThreads(
+            "copy_bf16",
+            &[_]metal.MetalBuffer{ src, dst },
+            &count,
+            @sizeOf(u32),
+            src.element_count,
+            1,
+            1,
+        );
+    }
+
+    fn addBuffers(self: *Self, src: metal.MetalBuffer, dst: metal.MetalBuffer) !void {
+        const count: u32 = @intCast(src.element_count);
+        try self.engine.dispatchThreads(
+            "add_bf16",
+            &[_]metal.MetalBuffer{ src, dst, dst },
+            &count,
+            @sizeOf(u32),
+            src.element_count,
+            1,
+            1,
+        );
+    }
+
+    /// Run a training step (forward + backward + optimizer)
+    pub fn trainStep(self: *Self, tokens: []const u32) !f32 {
+        // Zero gradients at start of accumulation window
+        if (self.accum_step == 0) {
+            self.grads.zero();
+        }
+
+        // Forward pass
+        const loss = try self.forward(tokens);
+
+        // Backward pass (accumulates gradients)
+        try self.backward();
+
+        self.accum_step += 1;
+        self.total_tokens += tokens.len;
+
+        // Optimizer step after gradient accumulation
+        if (self.accum_step >= self.config.grad_accum_steps) {
+            try self.optimizerStep();
+            self.step += 1;
+            self.accum_step = 0;
+        }
+
+        return loss;
+    }
+
+    /// Backward pass: compute gradients for all parameters
+    pub fn backward(self: *Self) !void {
+        const config = self.config;
+        const batch_seq: u64 = config.batch_size * config.n_ctx;
+        const embd: u64 = config.n_embd;
+        const vocab: u64 = config.n_vocab;
+
+        // Scale gradients by 1/grad_accum_steps for proper averaging
+        const grad_scale: f32 = 1.0 / @as(f32, @floatFromInt(config.grad_accum_steps));
+
+        // === Step 1: Cross Entropy Backward ===
+        // d_logits = softmax(logits) - one_hot(targets)
+        const loss_scale: f32 = grad_scale / @as(f32, @floatFromInt(batch_seq));
+
+        try self.engine.dispatch2D(
+            "cross_entropy_backward",
+            &[_]metal.MetalBuffer{
+                self.activations.logits,
+                self.target_tokens,
+                self.grad_acts.d_logits,
+            },
+            &vocab,
+            @sizeOf(u32),
+            vocab,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Scale gradients
+        const scale_params = metal.ElementwiseParams{
+            .count = @intCast(batch_seq * vocab),
+            .scale = loss_scale,
+        };
+        try self.engine.dispatchThreads(
+            "scale_bf16",
+            &[_]metal.MetalBuffer{ self.grad_acts.d_logits, self.grad_acts.d_logits },
+            &scale_params,
+            @sizeOf(metal.ElementwiseParams),
+            batch_seq * vocab,
+            1,
+            1,
+        );
+
+        // === Step 2: LM Head Backward (tied with wte) ===
+        // d_ln_out = d_logits @ wte.T (input gradient)
+        // d_wte += ln_out.T @ d_logits (weight gradient, accumulated)
+        const lm_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_embd,
+            .K = config.n_vocab,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_input",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_logits,
+                self.model.wte,
+                self.grad_acts.d_hidden,
+            },
+            &lm_params,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Accumulate wte gradient (from LM head)
+        const wte_grad_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_vocab,
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+        _ = wte_grad_params;
+
+        // === Step 3: Final LayerNorm Backward ===
+        const ln_params = metal.LayerNormParams{
+            .batch_size = @intCast(batch_seq),
+            .hidden_size = config.n_embd,
+            .eps = 1e-5,
+        };
+
+        try self.engine.dispatch2D(
+            "layernorm_backward_full_bf16",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_hidden,
+                self.activations.hidden_states, // Input to final LN
+                self.model.ln_f_weight,
+                self.activations.ln_mean,
+                self.activations.ln_rstd,
+                self.grad_acts.d_residual, // Output gradient
+                self.grads.ln_f_weight,
+                self.grads.ln_f_bias,
+            },
+            &ln_params,
+            @sizeOf(metal.LayerNormParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Copy d_residual to d_hidden for layer backward
+        try self.copyBuffer(self.grad_acts.d_residual, self.grad_acts.d_hidden);
+
+        // === Step 4: Backward through Transformer Layers (reverse order) ===
+        var layer_idx: usize = config.n_layer;
+        while (layer_idx > 0) {
+            layer_idx -= 1;
+            try self.backwardLayer(layer_idx);
+        }
+
+        // === Step 5: Embedding Backward ===
+        // Scatter d_hidden gradients to wte and wpe
+        const embed_params = metal.EmbedParams{
+            .batch_size = config.batch_size,
+            .seq_len = config.n_ctx,
+            .n_vocab = config.n_vocab,
+            .n_embd = config.n_embd,
+        };
+
+        // For simplicity, we accumulate embedding gradients on CPU
+        // (atomic scatter on GPU is expensive for large vocabs)
+        // In production, use a gather-then-update pattern
+        _ = embed_params;
+    }
+
+    fn backwardLayer(self: *Self, layer_idx: usize) !void {
+        const config = self.config;
+        const batch_seq: u64 = config.batch_size * config.n_ctx;
+        const embd: u64 = config.n_embd;
+
+        const layer = &self.model.layers[layer_idx];
+        const grad_layer = &self.grads.layers[layer_idx];
+
+        // === MLP Backward ===
+        // d_hidden comes in, we compute d_residual (from before MLP)
+
+        // MLP Projection Backward: d_mlp_hidden = d_hidden @ c_proj_mlp.T
+        const proj_mlp_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = @intCast(4 * embd),
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_input",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_hidden,
+                layer.c_proj_mlp_weight,
+                self.grad_acts.d_mlp_hidden,
+            },
+            &proj_mlp_params,
+            @sizeOf(metal.MatMulParams),
+            4 * embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Weight gradient: d_c_proj_mlp = mlp_hidden.T @ d_hidden
+        const weight_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_embd,
+            .K = @intCast(4 * embd),
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_weight",
+            &[_]metal.MetalBuffer{
+                self.activations.mlp_hidden,
+                self.grad_acts.d_hidden,
+                grad_layer.c_proj_mlp_weight,
+            },
+            &weight_params,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            4 * embd,
+            32,
+            8,
+        );
+
+        // Bias gradient: sum over batch dimension
+        const bias_rows: u32 = @intCast(batch_seq);
+        const bias_cols: u32 = config.n_embd;
+        try self.engine.dispatchThreads(
+            "bias_backward_bf16",
+            &[_]metal.MetalBuffer{ self.grad_acts.d_hidden, grad_layer.c_proj_mlp_bias },
+            &bias_rows,
+            @sizeOf(u32),
+            bias_cols,
+            1,
+            1,
+        );
+
+        // GELU Backward: d_pre_gelu = gelu_backward(d_mlp_hidden, pre_gelu)
+        const count: u32 = @intCast(batch_seq * 4 * embd);
+        try self.engine.dispatchThreads(
+            "gelu_backward_bf16",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_mlp_hidden,
+                self.grad_acts.pre_gelu, // Cached from forward
+                self.grad_acts.d_mlp_out,
+            },
+            &count,
+            @sizeOf(u32),
+            batch_seq * 4 * embd,
+            1,
+            1,
+        );
+
+        // FC Backward: d_ln_out = d_pre_gelu @ c_fc.T
+        const fc_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_embd,
+            .K = @intCast(4 * embd),
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_input",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_mlp_out,
+                layer.c_fc_weight,
+                self.grad_acts.d_ln_out,
+            },
+            &fc_params,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // FC Weight gradient
+        const fc_weight_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = @intCast(4 * embd),
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_weight",
+            &[_]metal.MetalBuffer{
+                self.activations.ln_out,
+                self.grad_acts.d_mlp_out,
+                grad_layer.c_fc_weight,
+            },
+            &fc_weight_params,
+            @sizeOf(metal.MatMulParams),
+            4 * embd,
+            embd,
+            32,
+            8,
+        );
+
+        // FC Bias gradient
+        const fc_bias_cols: u32 = @intCast(4 * embd);
+        try self.engine.dispatchThreads(
+            "bias_backward_bf16",
+            &[_]metal.MetalBuffer{ self.grad_acts.d_mlp_out, grad_layer.c_fc_bias },
+            &bias_rows,
+            @sizeOf(u32),
+            fc_bias_cols,
+            1,
+            1,
+        );
+
+        // LayerNorm 2 Backward
+        const ln_params = metal.LayerNormParams{
+            .batch_size = @intCast(batch_seq),
+            .hidden_size = config.n_embd,
+            .eps = 1e-5,
+        };
+
+        try self.engine.dispatch2D(
+            "layernorm_backward_full_bf16",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_ln_out,
+                self.activations.hidden_states,
+                layer.ln_2_weight,
+                self.activations.ln_mean,
+                self.activations.ln_rstd,
+                self.grad_acts.d_residual,
+                grad_layer.ln_2_weight,
+                grad_layer.ln_2_bias,
+            },
+            &ln_params,
+            @sizeOf(metal.LayerNormParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Add residual connection gradient
+        try self.addBuffers(self.grad_acts.d_hidden, self.grad_acts.d_residual);
+
+        // === Attention Backward ===
+        // (Simplified - full implementation would use attention_backward_bf16)
+
+        // Attention Output Projection Backward
+        const proj_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = config.n_embd,
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_input",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_residual,
+                layer.c_proj_weight,
+                self.grad_acts.d_attn_out,
+            },
+            &proj_params,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Output projection weight gradient
+        try self.engine.dispatch2D(
+            "matmul_backward_weight",
+            &[_]metal.MetalBuffer{
+                self.activations.attn_out,
+                self.grad_acts.d_residual,
+                grad_layer.c_proj_weight,
+            },
+            &proj_params,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            embd,
+            32,
+            8,
+        );
+
+        // Output projection bias gradient
+        try self.engine.dispatchThreads(
+            "bias_backward_bf16",
+            &[_]metal.MetalBuffer{ self.grad_acts.d_residual, grad_layer.c_proj_bias },
+            &bias_rows,
+            @sizeOf(u32),
+            bias_cols,
+            1,
+            1,
+        );
+
+        // QKV Backward (simplified - compute gradient for QKV projection)
+        const qkv_params = metal.MatMulParams{
+            .M = @intCast(batch_seq),
+            .N = @intCast(3 * embd),
+            .K = config.n_embd,
+            .alpha = 1.0,
+            .beta = 0.0,
+        };
+
+        try self.engine.dispatch2D(
+            "matmul_backward_weight",
+            &[_]metal.MetalBuffer{
+                self.activations.ln_out,
+                self.grad_acts.d_qkv,
+                grad_layer.c_attn_weight,
+            },
+            &qkv_params,
+            @sizeOf(metal.MatMulParams),
+            3 * embd,
+            embd,
+            32,
+            8,
+        );
+
+        // QKV Input gradient -> d_ln_out
+        try self.engine.dispatch2D(
+            "matmul_backward_input",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_qkv,
+                layer.c_attn_weight,
+                self.grad_acts.d_ln_out,
+            },
+            &qkv_params,
+            @sizeOf(metal.MatMulParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // QKV Bias gradient
+        const qkv_bias_cols: u32 = @intCast(3 * embd);
+        try self.engine.dispatchThreads(
+            "bias_backward_bf16",
+            &[_]metal.MetalBuffer{ self.grad_acts.d_qkv, grad_layer.c_attn_bias },
+            &bias_rows,
+            @sizeOf(u32),
+            qkv_bias_cols,
+            1,
+            1,
+        );
+
+        // LayerNorm 1 Backward
+        try self.engine.dispatch2D(
+            "layernorm_backward_full_bf16",
+            &[_]metal.MetalBuffer{
+                self.grad_acts.d_ln_out,
+                self.activations.residual, // Input to LN1
+                layer.ln_1_weight,
+                self.activations.ln_mean,
+                self.activations.ln_rstd,
+                self.grad_acts.d_hidden, // Output: gradient for previous layer
+                grad_layer.ln_1_weight,
+                grad_layer.ln_1_bias,
+            },
+            &ln_params,
+            @sizeOf(metal.LayerNormParams),
+            embd,
+            batch_seq,
+            32,
+            8,
+        );
+
+        // Add residual connection gradient from attention path
+        try self.addBuffers(self.grad_acts.d_residual, self.grad_acts.d_hidden);
+    }
+
+    /// Apply AdamW optimizer step to all parameters
+    pub fn optimizerStep(self: *Self) !void {
+        const config = self.config;
+        const lr = self.getLearningRate();
+        const step_num: u32 = @intCast(self.step + 1);
+
+        // AdamW parameters
+        const adamw_params = metal.AdamWParams{
+            .count = 0, // Set per-buffer
+            .lr = lr,
+            .beta1 = config.beta1,
+            .beta2 = config.beta2,
+            .eps = config.eps,
+            .weight_decay = config.weight_decay,
+            .step = step_num,
+        };
+
+        // Update embeddings
+        try self.adamwUpdate(
+            self.model.wte,
+            self.grads.wte,
+            self.opt_state.wte_m,
+            self.opt_state.wte_v,
+            config.n_vocab * config.n_embd,
+            adamw_params,
+        );
+
+        try self.adamwUpdate(
+            self.model.wpe,
+            self.grads.wpe,
+            self.opt_state.wpe_m,
+            self.opt_state.wpe_v,
+            config.n_ctx * config.n_embd,
+            adamw_params,
+        );
+
+        // Update each layer
+        for (self.model.layers, self.grads.layers, self.opt_state.layers) |*layer, *grad_layer, *opt_layer| {
+            // LayerNorm 1
+            try self.adamwUpdate(layer.ln_1_weight, grad_layer.ln_1_weight, opt_layer.ln_1_weight_m, opt_layer.ln_1_weight_v, config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.ln_1_bias, grad_layer.ln_1_bias, opt_layer.ln_1_bias_m, opt_layer.ln_1_bias_v, config.n_embd, adamw_params);
+
+            // Attention
+            try self.adamwUpdate(layer.c_attn_weight, grad_layer.c_attn_weight, opt_layer.c_attn_weight_m, opt_layer.c_attn_weight_v, config.n_embd * 3 * config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.c_attn_bias, grad_layer.c_attn_bias, opt_layer.c_attn_bias_m, opt_layer.c_attn_bias_v, 3 * config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.c_proj_weight, grad_layer.c_proj_weight, opt_layer.c_proj_weight_m, opt_layer.c_proj_weight_v, config.n_embd * config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.c_proj_bias, grad_layer.c_proj_bias, opt_layer.c_proj_bias_m, opt_layer.c_proj_bias_v, config.n_embd, adamw_params);
+
+            // LayerNorm 2
+            try self.adamwUpdate(layer.ln_2_weight, grad_layer.ln_2_weight, opt_layer.ln_2_weight_m, opt_layer.ln_2_weight_v, config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.ln_2_bias, grad_layer.ln_2_bias, opt_layer.ln_2_bias_m, opt_layer.ln_2_bias_v, config.n_embd, adamw_params);
+
+            // MLP
+            try self.adamwUpdate(layer.c_fc_weight, grad_layer.c_fc_weight, opt_layer.c_fc_weight_m, opt_layer.c_fc_weight_v, config.n_embd * 4 * config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.c_fc_bias, grad_layer.c_fc_bias, opt_layer.c_fc_bias_m, opt_layer.c_fc_bias_v, 4 * config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.c_proj_mlp_weight, grad_layer.c_proj_mlp_weight, opt_layer.c_proj_mlp_weight_m, opt_layer.c_proj_mlp_weight_v, 4 * config.n_embd * config.n_embd, adamw_params);
+            try self.adamwUpdate(layer.c_proj_mlp_bias, grad_layer.c_proj_mlp_bias, opt_layer.c_proj_mlp_bias_m, opt_layer.c_proj_mlp_bias_v, config.n_embd, adamw_params);
+        }
+
+        // Final LayerNorm
+        try self.adamwUpdate(self.model.ln_f_weight, self.grads.ln_f_weight, self.opt_state.ln_f_weight_m, self.opt_state.ln_f_weight_v, config.n_embd, adamw_params);
+        try self.adamwUpdate(self.model.ln_f_bias, self.grads.ln_f_bias, self.opt_state.ln_f_bias_m, self.opt_state.ln_f_bias_v, config.n_embd, adamw_params);
+    }
+
+    fn adamwUpdate(
+        self: *Self,
+        params: metal.MetalBuffer,
+        grads: metal.MetalBuffer,
+        m: metal.MetalBuffer,
+        v: metal.MetalBuffer,
+        count: u32,
+        base_params: metal.AdamWParams,
+    ) !void {
+        var adamw_params = base_params;
+        adamw_params.count = count;
+
+        try self.engine.dispatchThreads(
+            "adamw_f32_grad",
+            &[_]metal.MetalBuffer{ params, grads, m, v },
+            &adamw_params,
+            @sizeOf(metal.AdamWParams),
+            count,
+            1,
+            1,
+        );
+    }
+
+    /// Get current learning rate (with warmup and cosine decay)
+    pub fn getLearningRate(self: *Self) f32 {
+        const warmup = self.config.warmup_steps;
+        const max_lr = self.config.learning_rate;
+
+        // Linear warmup
+        if (self.step < warmup) {
+            return max_lr * @as(f32, @floatFromInt(self.step + 1)) /
+                @as(f32, @floatFromInt(warmup));
+        }
+
+        // Constant LR after warmup (can add cosine decay here)
+        return max_lr;
+    }
+
+    /// Alias for getLearningRate (convenience for external callers)
+    pub fn getCurrentLR(self: *Self) f32 {
+        return self.getLearningRate();
+    }
+
+    /// Get training statistics
+    pub fn getStats(self: *Self) struct { step: u64, tokens: u64, lr: f32 } {
+        return .{
+            .step = self.step,
+            .tokens = self.total_tokens,
+            .lr = self.getLearningRate(),
+        };
+    }
+};
