+// Embedded Metal Shader Source
+// =============================================================================
+
+/// Load GPT-2 Metal kernels from embedded source
+pub fn loadGPT2Shaders(engine: *metal.MetalEngine) !void {
+    const shader_source = @embedFile("metal/gpt2_kernels.metal");
+    try engine.loadShaderSource(shader_source);
+}
