+//! Generate test dataset for GPT-2 training verification
+//!
+//! Usage: zig run tools/gen_test_data.zig
+
+const std = @import("std");
+
+pub fn main() !void {
+    const allocator = std.heap.page_allocator;
+
+    const path = "data/train.zell";
+    const file = try std.fs.cwd().createFile(path, .{});
+    defer file.close();
+
+    // Number of tokens: need at least batch_size * context_length
+    // Using 100K tokens for a decent test run
+    const num_tokens: u64 = 100_000;
+    const vocab_size: u32 = 50304;
+
+    // Write header (32 bytes)
+    var header: [32]u8 = undefined;
+    @memset(&header, 0);
+    @memcpy(header[0..4], "ZELL");
+    std.mem.writeInt(u32, header[4..8], 1, .little); // Version
+    std.mem.writeInt(u64, header[8..16], num_tokens, .little);
+    std.mem.writeInt(u32, header[16..20], vocab_size, .little);
+    try file.writeAll(&header);
+
+    // Write random tokens (u16)
+    var prng = std.Random.DefaultPrng.init(42);
+    const random = prng.random();
+
+    // Allocate a large buffer for efficiency
+    const buffer_size: usize = 8192;
+    var buffer = try allocator.alloc(u16, buffer_size);
+    defer allocator.free(buffer);
+
+    var written: u64 = 0;
+    while (written < num_tokens) {
+        const to_write = @min(buffer_size, num_tokens - written);
+        for (0..to_write) |i| {
+            // Generate random token ID (0 to vocab_size-1)
+            buffer[i] = @intCast(random.uintLessThan(u32, vocab_size));
+        }
+        const bytes = std.mem.sliceAsBytes(buffer[0..to_write]);
+        try file.writeAll(bytes);
+        written += to_write;
+    }
+
+    std.debug.print("Generated test dataset: {s}\n", .{path});
+    std.debug.print("  Tokens: {d}\n", .{num_tokens});
+    std.debug.print("  Vocab size: {d}\n", .{vocab_size});
+    std.debug.print("  File size: {d} bytes\n", .{32 + num_tokens * 2});
+}

