+//! Data Preprocessing Tool
+//!
+//! Converts text files or Karpathy-style .bin files to ZELL binary format
+//! for zero-copy training data loading.
+//!
+//! Usage:
+//!   zig build run-preprocess -- --input data.txt --output train.zell --mode text
+//!   zig build run-preprocess -- --input train.bin --output train.zell --mode karpathy
+//!
+//! Input modes:
+//!   - text: Plain text file, will be tokenized with GPT-2 BPE
+//!   - karpathy: Pre-tokenized .bin file (u16 little-endian tokens)
+//!   - jsonl: JSON Lines format with "text" field
+
+const std = @import("std");
+const tokenizer = @import("../src/train/tokenizer/bpe_tokenizer.zig");
+const dataset = @import("../src/train/data/dataset_writer.zig");
+
+const log = std.log.scoped(.preprocess);
+
+const Mode = enum {
+    text,
+    karpathy,
+    jsonl,
+};
+
+const Args = struct {
+    input: []const u8 = "",
+    output: []const u8 = "train.zell",
+    vocab_path: []const u8 = "vocab.json",
+    merges_path: []const u8 = "merges.txt",
+    mode: Mode = .karpathy,
+    vocab_size: u32 = 50257,
+    chunk_size: usize = 1024 * 1024, // 1MB chunks for text processing
+};
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    // Parse arguments
+    const args = try parseArgs(allocator);
+
+    log.info("Preprocessing data:", .{});
+    log.info("  Input: {s}", .{args.input});
+    log.info("  Output: {s}", .{args.output});
+    log.info("  Mode: {s}", .{@tagName(args.mode)});
+
+    switch (args.mode) {
+        .karpathy => try convertKarpathy(args),
+        .text => try convertText(allocator, args),
+        .jsonl => try convertJsonl(allocator, args),
+    }
+
+    log.info("Done!", .{});
+}
+
+fn parseArgs(allocator: std.mem.Allocator) !Args {
+    var args = Args{};
+    var arg_iter = try std.process.argsWithAllocator(allocator);
+    defer arg_iter.deinit();
+
+    // Skip program name
+    _ = arg_iter.skip();
+
+    while (arg_iter.next()) |arg| {
+        if (std.mem.eql(u8, arg, "--input") or std.mem.eql(u8, arg, "-i")) {
+            args.input = arg_iter.next() orelse return error.MissingInputArg;
+        } else if (std.mem.eql(u8, arg, "--output") or std.mem.eql(u8, arg, "-o")) {
+            args.output = arg_iter.next() orelse return error.MissingOutputArg;
+        } else if (std.mem.eql(u8, arg, "--mode") or std.mem.eql(u8, arg, "-m")) {
+            const mode_str = arg_iter.next() orelse return error.MissingModeArg;
+            args.mode = std.meta.stringToEnum(Mode, mode_str) orelse {
+                log.err("Unknown mode: {s}", .{mode_str});
+                return error.InvalidMode;
+            };
+        } else if (std.mem.eql(u8, arg, "--vocab")) {
+            args.vocab_path = arg_iter.next() orelse return error.MissingVocabArg;
+        } else if (std.mem.eql(u8, arg, "--merges")) {
+            args.merges_path = arg_iter.next() orelse return error.MissingMergesArg;
+        } else if (std.mem.eql(u8, arg, "--vocab-size")) {
+            const size_str = arg_iter.next() orelse return error.MissingVocabSizeArg;
+            args.vocab_size = std.fmt.parseInt(u32, size_str, 10) catch return error.InvalidVocabSize;
+        } else if (std.mem.eql(u8, arg, "--help") or std.mem.eql(u8, arg, "-h")) {
+            printHelp();
+            std.process.exit(0);
+        }
+    }
+
+    if (args.input.len == 0) {
+        log.err("Missing required --input argument", .{});
+        printHelp();
+        return error.MissingInput;
+    }
+
+    return args;
+}
+
+fn printHelp() void {
+    const help =
+        \\ZELL Data Preprocessing Tool
+        \\
+        \\Converts text or pre-tokenized data to ZELL binary format for
+        \\zero-copy GPU training.
+        \\
+        \\USAGE:
+        \\  preprocess_data --input <file> [options]
+        \\
+        \\OPTIONS:
+        \\  -i, --input <file>    Input file path (required)
+        \\  -o, --output <file>   Output .zell file (default: train.zell)
+        \\  -m, --mode <mode>     Input mode: text, karpathy, jsonl (default: karpathy)
+        \\      --vocab <file>    vocab.json path (for text mode)
+        \\      --merges <file>   merges.txt path (for text mode)
+        \\      --vocab-size <n>  Vocabulary size (default: 50257)
+        \\  -h, --help            Show this help
+        \\
+        \\MODES:
+        \\  karpathy  Pre-tokenized .bin file with u16 tokens (default)
+        \\  text      Plain text file, tokenized with GPT-2 BPE
+        \\  jsonl     JSON Lines with "text" field
+        \\
+        \\EXAMPLES:
+        \\  # Convert Karpathy's pre-tokenized data
+        \\  preprocess_data -i train.bin -o train.zell -m karpathy
+        \\
+        \\  # Tokenize raw text (requires vocab.json and merges.txt)
+        \\  preprocess_data -i openwebtext.txt -o train.zell -m text \
+        \\                  --vocab vocab.json --merges merges.txt
+        \\
+    ;
+    std.debug.print("{s}\n", .{help});
+}
+
+/// Convert Karpathy-style .bin file (raw u16 tokens) to ZELL format
+fn convertKarpathy(args: Args) !void {
+    const input_file = try std.fs.cwd().openFile(args.input, .{});
+    defer input_file.close();
+
+    const stat = try input_file.stat();
+    const total_tokens = stat.size / 2;
+
+    log.info("Input file: {} tokens ({} MB)", .{
+        total_tokens,
+        stat.size / (1024 * 1024),
+    });
+
+    // Create output writer
+    var writer = try dataset.DatasetWriter.init(args.output, args.vocab_size);
+    errdefer writer.file.close();
+
+    // Buffer for reading
+    var buffer: [32768]u16 = undefined;
+    const byte_buffer = std.mem.sliceAsBytes(&buffer);
+
+    var tokens_written: u64 = 0;
+    var last_progress: u64 = 0;
+
+    while (true) {
+        const bytes_read = try input_file.read(byte_buffer);
+        if (bytes_read == 0) break;
+
+        const tokens_read = bytes_read / 2;
+        try writer.appendU16(buffer[0..tokens_read]);
+        tokens_written += tokens_read;
+
+        // Progress update every 10%
+        const progress = (tokens_written * 100) / total_tokens;
+        if (progress >= last_progress + 10) {
+            log.info("Progress: {}% ({} / {} tokens)", .{
+                progress,
+                tokens_written,
+                total_tokens,
+            });
+            last_progress = progress;
+        }
+    }
+
+    try writer.finish();
+    log.info("Written {} tokens to {s}", .{ tokens_written, args.output });
+}
+
+/// Convert plain text file using GPT-2 BPE tokenizer
+fn convertText(allocator: std.mem.Allocator, args: Args) !void {
+    // Load tokenizer
+    log.info("Loading tokenizer from {s} and {s}", .{ args.vocab_path, args.merges_path });
+    var tok = try tokenizer.Tokenizer.init(allocator, args.vocab_path, args.merges_path);
+    defer tok.deinit();
+
+    // Open input file
+    const input_file = try std.fs.cwd().openFile(args.input, .{});
+    defer input_file.close();
+
+    const stat = try input_file.stat();
+    log.info("Input file: {} bytes", .{stat.size});
+
+    // Create output writer
+    var writer = try dataset.DatasetWriter.init(args.output, args.vocab_size);
+    errdefer writer.file.close();
+
+    // Read and process in chunks
+    var buffer = try allocator.alloc(u8, args.chunk_size);
+    defer allocator.free(buffer);
+
+    var total_tokens: u64 = 0;
+    var bytes_processed: u64 = 0;
+
+    while (true) {
+        const bytes_read = try input_file.read(buffer);
+        if (bytes_read == 0) break;
+
+        // Tokenize chunk
+        const tokens = try tok.encode(buffer[0..bytes_read]);
+        defer allocator.free(tokens);
+
+        // Write tokens
+        try writer.append(tokens);
+        total_tokens += tokens.len;
+        bytes_processed += bytes_read;
+
+        // Progress
+        const progress = (bytes_processed * 100) / stat.size;
+        log.info("Progress: {}% - {} tokens", .{ progress, total_tokens });
+    }
+
+    // Add end-of-text token
+    try writer.appendOne(tok.eot_token);
+    total_tokens += 1;
+
+    try writer.finish();
+    log.info("Written {} tokens to {s}", .{ total_tokens, args.output });
+}
+
+/// Convert JSON Lines file with "text" field
+fn convertJsonl(allocator: std.mem.Allocator, args: Args) !void {
+    // Load tokenizer
+    log.info("Loading tokenizer from {s} and {s}", .{ args.vocab_path, args.merges_path });
+    var tok = try tokenizer.Tokenizer.init(allocator, args.vocab_path, args.merges_path);
+    defer tok.deinit();
+
+    // Open input file
+    const input_file = try std.fs.cwd().openFile(args.input, .{});
+    defer input_file.close();
+
+    // Create output writer
+    var writer = try dataset.DatasetWriter.init(args.output, args.vocab_size);
+    errdefer writer.file.close();
+
+    // Read line by line
+    var line_buffer = std.ArrayList(u8).init(allocator);
+    defer line_buffer.deinit();
+
+    var total_tokens: u64 = 0;
+    var lines_processed: u64 = 0;
+
+    const reader = input_file.reader();
+
+    while (true) {
+        reader.streamUntilDelimiter(line_buffer.writer(), '\n', null) catch |err| {
+            if (err == error.EndOfStream) break;
+            return err;
+        };
+        defer line_buffer.clearRetainingCapacity();
+
+        if (line_buffer.items.len == 0) continue;
+
+        // Parse JSON line
+        var parsed = std.json.parseFromSlice(
+            std.json.Value,
+            allocator,
+            line_buffer.items,
+            .{},
+        ) catch {
+            log.warn("Failed to parse JSON line {}", .{lines_processed + 1});
+            continue;
+        };
+        defer parsed.deinit();
+
+        // Extract "text" field
+        const text = parsed.value.object.get("text") orelse {
+            log.warn("Missing 'text' field in line {}", .{lines_processed + 1});
+            continue;
+        };
+
+        if (text != .string) continue;
+
+        // Tokenize and write
+        const tokens = try tok.encode(text.string);
+        defer allocator.free(tokens);
+
+        try writer.append(tokens);
+        try writer.appendOne(tok.eot_token); // Document separator
+        total_tokens += tokens.len + 1;
+
+        lines_processed += 1;
+        if (lines_processed % 10000 == 0) {
+            log.info("Processed {} lines, {} tokens", .{ lines_processed, total_tokens });
+        }
+    }
+
+    try writer.finish();
+    log.info("Written {} tokens from {} documents to {s}", .{
+        total_tokens,
+        lines_processed,
+        args.output,
+    });
+}
+
+// =============================================================================
+// Quick conversion utilities
+// =============================================================================
+
+/// Quick conversion for testing - creates a small dataset from text
+pub fn createTestDataset(allocator: std.mem.Allocator, output_path: []const u8, num_tokens: usize) !void {
+    var writer = try dataset.DatasetWriter.init(output_path, 50257);
+    errdefer writer.file.close();
+
+    var prng = std.Random.DefaultPrng.init(42);
+    const random = prng.random();
+
+    var tokens = try allocator.alloc(u32, num_tokens);
+    defer allocator.free(tokens);
+
+    for (tokens) |*t| {
+        // Generate tokens in common range (skip special tokens)
+        t.* = 1000 + random.uintLessThan(u32, 40000);
+    }
+
+    try writer.append(tokens);
+    try writer.finish();
+
+    log.info("Created test dataset with {} random tokens", .{num_tokens});
+}
+
+/// Verify a ZELL dataset file
+pub fn verifyDataset(path: []const u8) !void {
+    var reader = try dataset.DatasetReader.init(path);
+    defer reader.deinit();
+
+    log.info("Dataset verification:", .{});
+    log.info("  Version: {}", .{reader.version});
+    log.info("  Total tokens: {}", .{reader.total_tokens});
+    log.info("  Vocab size: {}", .{reader.vocab_size});
+
+    // Check file size matches
+    const expected_size = dataset.HEADER_SIZE + (reader.total_tokens * 2);
+    const actual_size = (try reader.file.stat()).size;
+
+    if (actual_size != expected_size) {
+        log.err("Size mismatch! Expected {} bytes, got {}", .{ expected_size, actual_size });
+        return error.SizeMismatch;
+    }
+
+    log.info("  File size: {} bytes (OK)", .{actual_size});
+}
